diffs.replacement:
export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';

export interface FamilyMember {
  id: string;
  name: string;
  relation: string;
  mobileNumber: string;
  canAddTransactions?: boolean;
}

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
  familyMembers: FamilyMember[];
  cloudDatabaseName?: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  timestamp: string;
  type: 'transaction' | 'system' | 'sync';
  isRead: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
  ownerId?: string;
  accountType?: 'Savings' | 'Current' | 'Salary' | 'Others';
  customAccountType?: string;
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number;
  last4: string;
  limit?: number;
  annualLimit?: number; 
  anniversaryDate?: string;
  billingDay?: number;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
  ownerId?: string;
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
  ownerId?: string;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
  ownerId?: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  periodicity?: Periodicity;
  ownerId?: string;
}

export interface Asset {
  id: string;
  name: string;
  value: number;
  type?: 'Physical' | 'Receivable';
  ownerId?: string;
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
  type?: 'Debt' | 'Payable';
  ownerId?: string;
}

export type TransactionType = 'Income' | 'Expense' | 'Asset' | 'Liability';

export interface SharedContact {
  name: string;
  mobile: string;
  amount: number;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  nature: string; // Mandatory nature of transaction
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet' | 'liability';
  date: string;
  category?: string;
  isShared?: boolean;
  sharedAmount?: number;
  numberOfPeople?: number;
  includeSelf?: boolean;
  sharedContacts?: SharedContact[];
  ownerId?: string; 
  isin?: string;
  stockName?: string;
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
  notifications: Notification[];
  transactionNatures: string[]; 
  capital: number; // Tracks initial equity and capital contributions
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';
import { GoogleGenAI } from "@google/genai";

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  netTotal: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature, addWallet } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isIsinResolving, setIsIsinResolving] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(15);
  const [pdfPassword, setPdfPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [pendingFile, setPendingFile] = useState<File | null>(null);

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    finalSettlementAmount: number; 
    isSettlementPayable: boolean; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  // Auto-resolve ISIN
  useEffect(() => {
    const timer = setTimeout(() => {
      if (formData.isin && formData.isin.length === 12 && !formData.stockName) {
        handleIsinLookup(formData.isin);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [formData.isin]);

  const handleIsinLookup = async (isin: string) => {
    setIsIsinResolving(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify the security/stock name for the following ISIN identifier: ${isin}. Return ONLY the official short name of the security. No preamble.`
      });
      const resolvedName = response.text?.trim() || 'Unknown Security';
      setFormData(prev => ({ 
        ...prev, 
        stockName: resolvedName,
        description: prev.description || resolvedName
      }));
    } catch (err) {
      console.error("ISIN Resolution failed:", err);
    } finally {
      setIsIsinResolving(false);
    }
  };

  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
    const zerodhaExists = [...state.banks, ...state.wallets].some(a => a.name.toLowerCase() === 'zerodha');
    if (!zerodhaExists) {
      addWallet({
        id: 'zerodha-account-auto',
        name: 'Zerodha',
        balance: 0,
        ownerId: ''
      });
    }
  }, []);

  useEffect(() => {
    let timer: number;
    if (isScanning && scanTimeLeft > 0) {
      timer = window.setInterval(() => {
        setScanTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isScanning, scanTimeLeft]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setPendingFile(file);
    setShowPasswordInput(true);
  };

  const startAIParsing = async () => {
    if (!pendingFile) return;
    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(18);

    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: pendingFile.type } },
              { text: `Extract data from this Zerodha Contract Note PDF. Return ONLY JSON: { "date": "YYYY-MM-DD", "isSettlementPayable": boolean, "finalSettlementAmount": number, "trades": [{"scrip": "string", "type": "BUY" | "SELL", "netTotal": number}], "otherCharges": number }` }
            ]
          },
          config: { responseMimeType: "application/json" }
        });
        const result = JSON.parse(response.text || '{}');
        if (result.date) setScanResult(result);
        else alert("Failed to parse.");
      } catch (err) {
        console.error(err);
        alert("Verification failed.");
      } finally {
        setIsScanning(false);
        setPdfPassword('');
        setPendingFile(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(pendingFile);
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;
    const zerodhaAccount = [...state.banks, ...state.wallets, ...state.cards].find(a => a.name.toLowerCase() === 'zerodha') || { id: 'zerodha-account-auto', type: 'wallet' };
    scanResult.trades.forEach(t => {
      addTransaction({
        id: Math.random().toString(36).substr(2, 9),
        type: t.type === 'BUY' ? 'Asset' : 'Income', 
        amount: t.netTotal,
        nature: 'Investment in stocks',
        description: `${t.type} ${t.scrip}`,
        accountId: zerodhaAccount.id,
        accountType: (zerodhaAccount as any).type || 'wallet',
        date: scanResult.date,
        ownerId: formData.ownerId
      });
    });
    if (scanResult.otherCharges > 0) {
      addTransaction({
        id: Math.random().toString(36).substr(2, 9),
        type: 'Expense',
        amount: scanResult.otherCharges,
        nature: 'Other Charges',
        description: `Zerodha Charges: ${scanResult.date}`,
        accountId: zerodhaAccount.id,
        accountType: (zerodhaAccount as any).type || 'wallet',
        date: scanResult.date,
        ownerId: formData.ownerId
      });
    }
    setScanResult(null);
  };

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, nature: natures[0] || '' });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const totalValue = t.amount + (t.sharedAmount || 0);
    setFormData({
      ...initialFormState,
      type: t.type,
      amount: String(totalValue),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: t.includeSelf ?? true,
      numberOfPeople: t.numberOfPeople || 2,
      ownerId: t.ownerId || '',
      isin: t.isin || '',
      stockName: t.stockName || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: Number(formData.amount),
      nature: formData.nature,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      ownerId: formData.ownerId,
      isin: formData.isin,
      stockName: formData.stockName
    };
    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 md:gap-6">
        <div><h3 className="text-lg md:text-xl font-black text-slate-800 tracking-tight uppercase">Ledger Hub</h3><p className="text-[9px] md:text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">Dual Entry Reconciliation</p></div>
        <div className="grid grid-cols-2 md:flex md:flex-wrap items-center gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*,.pdf" onChange={handleFileUpload} />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="col-span-2 md:col-span-1 px-3 md:px-6 py-2.5 md:py-3 bg-indigo-900 text-white rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-indigo-950 transition-all shadow-lg"
          >
            <span>📄</span> Zerodha Import
          </button>
          <button onClick={() => handleOpenModal('Income')} className="px-3 md:px-6 py-2.5 md:py-3 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-3 md:px-6 py-2.5 md:py-3 bg-rose-50 text-rose-500 border border-rose-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-3 md:px-6 py-2.5 md:py-3 bg-white text-indigo-600 border border-indigo-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-3 md:px-6 py-2.5 md:py-3 bg-indigo-600 text-white rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Debt</button>
        </div>
      </div>

      {showPasswordInput && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <h4 className="text-base font-black text-slate-800 uppercase tracking-tight mb-4">PDF Security</h4>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-6 leading-relaxed">Zerodha PDFs require your PAN as the key.</p>
            <input 
              type="password" 
              placeholder="Enter PAN" 
              className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-sm mb-6"
              value={pdfPassword}
              onChange={e => setPdfPassword(e.target.value)}
            />
            <div className="flex gap-3">
              <button onClick={() => { setShowPasswordInput(false); setPendingFile(null); }} className="flex-1 py-4 bg-slate-100 text-slate-500 font-bold text-[10px] uppercase rounded-xl">Cancel</button>
              <button onClick={startAIParsing} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg">Start Import</button>
            </div>
          </div>
        </div>
      )}

      {isScanning && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/90 backdrop-blur-md">
          <div className="text-center space-y-6">
            <div className="w-24 h-24 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mx-auto relative flex items-center justify-center">
              <span className="text-white font-black text-lg">{scanTimeLeft}s</span>
            </div>
            <h4 className="text-xl font-black text-white uppercase tracking-tighter">AI Ledger Processing</h4>
          </div>
        </div>
      )}

      {scanResult && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/80 backdrop-blur-xl p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 my-8">
            <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter text-center mb-8">Reconciliation Audit</h3>
            <div className="space-y-6 mb-8">
              <div className="p-5 bg-slate-900 text-white rounded-2xl">
                <p className="text-[8px] font-black text-slate-500 uppercase mb-1 tracking-widest">Impact</p>
                <p className="text-3xl font-black tracking-tight">{formatCurrency(scanResult.finalSettlementAmount, currency)}</p>
              </div>
            </div>
            <div className="flex flex-col gap-3">
              <button onClick={commitScannedTrade} className="w-full py-5 bg-indigo-600 text-white font-black text-xs uppercase rounded-2xl shadow-xl">Audit & Commit</button>
              <button onClick={() => setScanResult(null)} className="w-full py-4 text-slate-400 font-black text-[10px] uppercase">Discard</button>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-500 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-200">
              <tr>
                <th className="px-8 py-7">Timeline</th>
                <th className="px-8 py-7">Classification & Nature</th>
                <th className="px-8 py-7">Execution</th>
                <th className="px-8 py-7 text-right">User Share</th>
                <th className="px-8 py-7 text-center">Protocol</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6 text-[11px] font-black text-slate-400 uppercase">{t.date}</td>
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-2">
                      <p className="text-sm font-black text-slate-800 tracking-tight">{t.description}</p>
                      {t.isin && <span className="bg-slate-100 text-slate-400 text-[7px] font-black px-1.5 py-0.5 rounded-sm uppercase tracking-widest">{t.isin}</span>}
                    </div>
                    <span className="text-[8px] text-indigo-600 font-black uppercase tracking-widest mt-1.5 inline-block bg-indigo-50 px-2 py-0.5 rounded">{t.nature}</span>
                  </td>
                  <td className="px-8 py-6"><span className="text-[9px] font-black text-slate-500 bg-slate-100 px-3 py-1.5 rounded-lg uppercase">{getOwnerName(t.ownerId)}</span></td>
                  <td className="px-8 py-6 text-right">
                    <div className={`text-base font-black ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : (t.type === 'Expense' ? 'text-rose-500' : 'text-slate-800')}`}>{t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}</div>
                  </td>
                  <td className="px-8 py-6 text-center">
                    <div className="flex items-center justify-center gap-3 opacity-0 group-hover:opacity-100 transition-all">
                      <button onClick={() => handleEditClick(t)} className="p-2 text-slate-300 hover:text-indigo-600 text-lg">✎</button>
                      <button onClick={() => setConfirmDeleteTx(t)} className="p-2 text-slate-300 hover:text-rose-500 text-lg">✕</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-xl p-3 md:p-4 overflow-y-auto pt-6 md:pt-10 pb-20">
          <div className="bg-white w-full max-w-2xl rounded-[2rem] md:rounded-[3rem] p-6 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 relative mb-10">
            <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
              <div><h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">{formData.type} Record</h3></div>
              <button onClick={() => setShowModal(false)} className="text-slate-200 hover:text-slate-800 font-black p-2 text-xl">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              {formData.type === 'Asset' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-indigo-50/30 p-6 rounded-[2rem] border border-indigo-100">
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">ISIN Identifier (Optional)</label>
                    <input 
                      className="w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs md:text-sm uppercase tracking-widest focus:ring-2 focus:ring-indigo-500/20" 
                      placeholder="e.g. INE002A01018"
                      maxLength={12}
                      value={formData.isin} 
                      onChange={e => setFormData({ ...formData, isin: e.target.value.toUpperCase() })} 
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Stock / Security Name</label>
                    <div className="relative">
                      <input 
                        className={`w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs md:text-sm focus:ring-2 focus:ring-indigo-500/20 ${isIsinResolving ? 'animate-pulse text-indigo-300' : ''}`} 
                        placeholder={isIsinResolving ? "Resolving via Gemini..." : "Security Name"}
                        value={formData.stockName} 
                        onChange={e => setFormData({ ...formData, stockName: e.target.value })} 
                      />
                      {isIsinResolving && <span className="absolute right-4 top-1/2 -translate-y-1/2 animate-spin text-indigo-500">⚙️</span>}
                    </div>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Entity</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value, accountId: '' })}>
                    <option value="">Me (Primary)</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Nature</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.nature} onChange={e => setFormData({ ...formData, nature: e.target.value })}>
                    <option value="" disabled>Select Protocol</option>
                    {natures.map(n => <option key={n} value={n}>{(n || '').toUpperCase()}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Total Value ({currency})</label>
                  <input required type="number" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-2xl" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Timeline</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Description</label>
                  <input required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold text-xs" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Instrument</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">Select Account</option>
                    {allAccounts.filter(a => (a.ownerId || '') === (formData.ownerId || '')).map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}
                  </select>
                </div>
              </div>

              <div className="flex flex-col md:flex-row gap-3 pt-6">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Discard</button>
                <button type="submit" className="flex-[2] py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-xl">Commit Ledger</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {confirmDeleteTx && <DeleteTransactionConfirmationModal transaction={confirmDeleteTx} currency={currency} onCancel={() => setConfirmDeleteTx(null)} onConfirm={() => { deleteTransaction(confirmDeleteTx.id); setConfirmDeleteTx(null); }} />}
    </div>
  );
};

const DeleteTransactionConfirmationModal: React.FC<{ transaction: Transaction, currency: string, onCancel: () => void, onConfirm: () => void }> = ({ transaction, currency, onCancel, onConfirm }) => {
  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/80 backdrop-blur-2xl p-4">
       <div className="w-full max-sm p-8 bg-white border border-slate-200 rounded-[2.5rem] shadow-2xl animate-in zoom-in duration-300">
          <div className="text-center mb-8"><div className="w-20 h-20 rounded-[1.5rem] bg-rose-50 text-rose-500 flex items-center justify-center text-4xl mx-auto mb-6">🗑️</div><h4 className="text-xl font-black text-slate-800 uppercase">Void entry?</h4></div>
          <div className="flex flex-col gap-4"><button onClick={onConfirm} className="w-full py-4 bg-rose-600 text-white font-black text-xs uppercase rounded-2xl shadow-xl">Purge Entry</button><button onClick={onCancel} className="w-full py-3 text-slate-500 font-black text-[9px] uppercase">Abort</button></div>
       </div>
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';
import { GoogleGenAI } from "@google/genai";

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  netTotal: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature, addWallet } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isIsinResolving, setIsIsinResolving] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(15);
  const [pdfPassword, setPdfPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [pendingFile, setPendingFile] = useState<File | null>(null);

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    finalSettlementAmount: number; 
    isSettlementPayable: boolean; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  // Auto-resolve ISIN
  useEffect(() => {
    const timer = setTimeout(() => {
      if (formData.isin && formData.isin.length === 12 && !formData.stockName) {
        handleIsinLookup(formData.isin);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [formData.isin]);

  const handleIsinLookup = async (isin: string) => {
    setIsIsinResolving(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify the security/stock name for the following ISIN identifier: ${isin}. Return ONLY the official short name of the security. No preamble.`
      });
      const resolvedName = response.text?.trim() || 'Unknown Security';
      setFormData(prev => ({ 
        ...prev, 
        stockName: resolvedName,
        description: prev.description || resolvedName
      }));
    } catch (err) {
      console.error("ISIN Resolution failed:", err);
    } finally {
      setIsIsinResolving(false);
    }
  };

  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
    const zerodhaExists = [...state.banks, ...state.wallets].some(a => a.name.toLowerCase() === 'zerodha');
    if (!zerodhaExists) {
      addWallet({
        id: 'zerodha-account-auto',
        name: 'Zerodha',
        balance: 0,
        ownerId: ''
      });
    }
  }, []);

  useEffect(() => {
    let timer: number;
    if (isScanning && scanTimeLeft > 0) {
      timer = window.setInterval(() => {
        setScanTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isScanning, scanTimeLeft]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setPendingFile(file);
    setShowPasswordInput(true);
  };

  const startAIParsing = async () => {
    if (!pendingFile) return;
    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(18);

    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: pendingFile.type } },
              { text: `Extract data from this Zerodha Contract Note PDF. Return ONLY JSON: { "date": "YYYY-MM-DD", "isSettlementPayable": boolean, "finalSettlementAmount": number, "trades": [{"scrip": "string", "type": "BUY" | "SELL", "netTotal": number}], "otherCharges": number }` }
            ]
          },
          config: { responseMimeType: "application/json" }
        });
        const result = JSON.parse(response.text || '{}');
        if (result.date) setScanResult(result);
        else alert("Failed to parse.");
      } catch (err) {
        console.error(err);
        alert("Verification failed.");
      } finally {
        setIsScanning(false);
        setPdfPassword('');
        setPendingFile(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(pendingFile);
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;
    const zerodhaAccount = [...state.banks, ...state.wallets, ...state.cards].find(a => a.name.toLowerCase() === 'zerodha') || { id: 'zerodha-account-auto', type: 'wallet' };
    scanResult.trades.forEach(t => {
      addTransaction({
        id: Math.random().toString(36).substr(2, 9),
        type: t.type === 'BUY' ? 'Asset' : 'Income', 
        amount: t.netTotal,
        nature: 'Investment in stocks',
        description: `${t.type} ${t.scrip}`,
        accountId: zerodhaAccount.id,
        accountType: (zerodhaAccount as any).type || 'wallet',
        date: scanResult.date,
        ownerId: formData.ownerId
      });
    });
    if (scanResult.otherCharges > 0) {
      addTransaction({
        id: Math.random().toString(36).substr(2, 9),
        type: 'Expense',
        amount: scanResult.otherCharges,
        nature: 'Other Charges',
        description: `Zerodha Charges: ${scanResult.date}`,
        accountId: zerodhaAccount.id,
        accountType: (zerodhaAccount as any).type || 'wallet',
        date: scanResult.date,
        ownerId: formData.ownerId
      });
    }
    setScanResult(null);
  };

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, nature: natures[0] || '' });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const totalValue = t.amount + (t.sharedAmount || 0);
    setFormData({
      ...initialFormState,
      type: t.type,
      amount: String(totalValue),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: t.includeSelf ?? true,
      numberOfPeople: t.numberOfPeople || 2,
      ownerId: t.ownerId || '',
      isin: t.isin || '',
      stockName: t.stockName || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: Number(formData.amount),
      nature: formData.nature,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      ownerId: formData.ownerId,
      isin: formData.isin,
      stockName: formData.stockName
    };
    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 md:gap-6">
        <div><h3 className="text-lg md:text-xl font-black text-slate-800 tracking-tight uppercase">Ledger Hub</h3><p className="text-[9px] md:text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">Dual Entry Reconciliation</p></div>
        <div className="grid grid-cols-2 md:flex md:flex-wrap items-center gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*,.pdf" onChange={handleFileUpload} />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="col-span-2 md:col-span-1 px-3 md:px-6 py-2.5 md:py-3 bg-indigo-900 text-white rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-indigo-950 transition-all shadow-lg"
          >
            <span>📄</span> Zerodha Import
          </button>
          <button onClick={() => handleOpenModal('Income')} className="px-3 md:px-6 py-2.5 md:py-3 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-3 md:px-6 py-2.5 md:py-3 bg-rose-50 text-rose-500 border border-rose-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-3 md:px-6 py-2.5 md:py-3 bg-white text-indigo-600 border border-indigo-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-3 md:px-6 py-2.5 md:py-3 bg-indigo-600 text-white rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Debt</button>
        </div>
      </div>

      {showPasswordInput && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <h4 className="text-base font-black text-slate-800 uppercase tracking-tight mb-4">PDF Security</h4>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-6 leading-relaxed">Zerodha PDFs require your PAN as the key.</p>
            <input 
              type="password" 
              placeholder="Enter PAN" 
              className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-sm mb-6"
              value={pdfPassword}
              onChange={e => setPdfPassword(e.target.value)}
            />
            <div className="flex gap-3">
              <button onClick={() => { setShowPasswordInput(false); setPendingFile(null); }} className="flex-1 py-4 bg-slate-100 text-slate-500 font-bold text-[10px] uppercase rounded-xl">Cancel</button>
              <button onClick={startAIParsing} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg">Start Import</button>
            </div>
          </div>
        </div>
      )}

      {isScanning && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/90 backdrop-blur-md">
          <div className="text-center space-y-6">
            <div className="w-24 h-24 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mx-auto relative flex items-center justify-center">
              <span className="text-white font-black text-lg">{scanTimeLeft}s</span>
            </div>
            <h4 className="text-xl font-black text-white uppercase tracking-tighter">AI Ledger Processing</h4>
          </div>
        </div>
      )}

      {scanResult && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/80 backdrop-blur-xl p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 my-8">
            <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter text-center mb-8">Reconciliation Audit</h3>
            <div className="space-y-6 mb-8">
              <div className="p-5 bg-slate-900 text-white rounded-2xl">
                <p className="text-[8px] font-black text-slate-500 uppercase mb-1 tracking-widest">Impact</p>
                <p className="text-3xl font-black tracking-tight">{formatCurrency(scanResult.finalSettlementAmount, currency)}</p>
              </div>
            </div>
            <div className="flex flex-col gap-3">
              <button onClick={commitScannedTrade} className="w-full py-5 bg-indigo-600 text-white font-black text-xs uppercase rounded-2xl shadow-xl">Audit & Commit</button>
              <button onClick={() => setScanResult(null)} className="w-full py-4 text-slate-400 font-black text-[10px] uppercase">Discard</button>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-500 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-200">
              <tr>
                <th className="px-8 py-7">Timeline</th>
                <th className="px-8 py-7">Classification & Nature</th>
                <th className="px-8 py-7">Execution</th>
                <th className="px-8 py-7 text-right">User Share</th>
                <th className="px-8 py-7 text-center">Protocol</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6 text-[11px] font-black text-slate-400 uppercase">{t.date}</td>
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-2">
                      <p className="text-sm font-black text-slate-800 tracking-tight">{t.description || t.stockName || t.nature}</p>
                      {t.isin && <span className="bg-slate-100 text-slate-400 text-[7px] font-black px-1.5 py-0.5 rounded-sm uppercase tracking-widest">{t.isin}</span>}
                    </div>
                    <span className="text-[8px] text-indigo-600 font-black uppercase tracking-widest mt-1.5 inline-block bg-indigo-50 px-2 py-0.5 rounded">{t.nature}</span>
                  </td>
                  <td className="px-8 py-6"><span className="text-[9px] font-black text-slate-500 bg-slate-100 px-3 py-1.5 rounded-lg uppercase">{getOwnerName(t.ownerId)}</span></td>
                  <td className="px-8 py-6 text-right">
                    <div className={`text-base font-black ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : (t.type === 'Expense' ? 'text-rose-500' : 'text-slate-800')}`}>{t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}</div>
                  </td>
                  <td className="px-8 py-6 text-center">
                    <div className="flex items-center justify-center gap-3 opacity-0 group-hover:opacity-100 transition-all">
                      <button onClick={() => handleEditClick(t)} className="p-2 text-slate-300 hover:text-indigo-600 text-lg">✎</button>
                      <button onClick={() => setConfirmDeleteTx(t)} className="p-2 text-slate-300 hover:text-rose-500 text-lg">✕</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-xl p-3 md:p-4 overflow-y-auto pt-6 md:pt-10 pb-20">
          <div className="bg-white w-full max-w-2xl rounded-[2rem] md:rounded-[3rem] p-6 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 relative mb-10">
            <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
              <div><h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">{formData.type} Record</h3></div>
              <button onClick={() => setShowModal(false)} className="text-slate-200 hover:text-slate-800 font-black p-2 text-xl">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              {formData.type === 'Asset' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 bg-indigo-50/30 p-6 rounded-[2rem] border border-indigo-100">
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">ISIN Identifier (Optional)</label>
                    <input 
                      className="w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs md:text-sm uppercase tracking-widest focus:ring-2 focus:ring-indigo-500/20" 
                      placeholder="e.g. INE002A01018"
                      maxLength={12}
                      value={formData.isin} 
                      onChange={e => setFormData({ ...formData, isin: e.target.value.toUpperCase() })} 
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Stock / Security Name</label>
                    <div className="relative">
                      <input 
                        className={`w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs md:text-sm focus:ring-2 focus:ring-indigo-500/20 ${isIsinResolving ? 'animate-pulse text-indigo-300' : ''}`} 
                        placeholder={isIsinResolving ? "Resolving via Gemini..." : "Security Name"}
                        value={formData.stockName} 
                        onChange={e => setFormData({ ...formData, stockName: e.target.value })} 
                      />
                      {isIsinResolving && <span className="absolute right-4 top-1/2 -translate-y-1/2 animate-spin text-indigo-500">⚙️</span>}
                    </div>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Entity</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value, accountId: '' })}>
                    <option value="">Me (Primary)</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Nature</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.nature} onChange={e => setFormData({ ...formData, nature: e.target.value })}>
                    <option value="" disabled>Select Protocol</option>
                    {natures.map(n => <option key={n} value={n}>{(n || '').toUpperCase()}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Total Value ({currency})</label>
                  <input required type="number" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-2xl" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Timeline</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Description (Optional)</label>
                  <input className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold text-xs" placeholder="Add custom note..." value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Instrument</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">Select Account</option>
                    {allAccounts.filter(a => (a.ownerId || '') === (formData.ownerId || '')).map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}
                  </select>
                </div>
              </div>

              <div className="flex flex-col md:flex-row gap-3 pt-6">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-2xl">Discard</button>
                <button type="submit" className="flex-[2] py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-xl">Commit Ledger</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {confirmDeleteTx && <DeleteTransactionConfirmationModal transaction={confirmDeleteTx} currency={currency} onCancel={() => setConfirmDeleteTx(null)} onConfirm={() => { deleteTransaction(confirmDeleteTx.id); setConfirmDeleteTx(null); }} />}
    </div>
  );
};

const DeleteTransactionConfirmationModal: React.FC<{ transaction: Transaction, currency: string, onCancel: () => void, onConfirm: () => void }> = ({ transaction, currency, onCancel, onConfirm }) => {
  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/80 backdrop-blur-2xl p-4">
       <div className="w-full max-sm p-8 bg-white border border-slate-200 rounded-[2.5rem] shadow-2xl animate-in zoom-in duration-300">
          <div className="text-center mb-8"><div className="w-20 h-20 rounded-[1.5rem] bg-rose-50 text-rose-500 flex items-center justify-center text-4xl mx-auto mb-6">🗑️</div><h4 className="text-xl font-black text-slate-800 uppercase">Void entry?</h4></div>
          <div className="flex flex-col gap-4"><button onClick={onConfirm} className="w-full py-4 bg-rose-600 text-white font-black text-xs uppercase rounded-2xl shadow-xl">Purge Entry</button><button onClick={onCancel} className="w-full py-3 text-slate-500 font-black text-[9px] uppercase">Abort</button></div>
