export default Transactions;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateNetWorth } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';

type Period = 'current_month' | 'last_90_days' | 'ytd' | 'all_time';

const Statements: React.FC = () => {
  const { state, filteredState, activeMemberIds } = useFinance();
  const [activePeriod, setActivePeriod] = useState<Period>('all_time');
  const currency = filteredState.profile.currency;

  const filteredTransactions = useMemo(() => {
    const txs = filteredState.transactions || [];
    const now = new Date();
    if (activePeriod === 'current_month') {
      const start = new Date(now.getFullYear(), now.getMonth(), 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'last_90_days') {
      const start = new Date();
      start.setDate(now.getDate() - 90);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'ytd') {
      const start = new Date(now.getFullYear(), 0, 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    return txs;
  }, [filteredState.transactions, activePeriod]);

  const periodIncome = filteredTransactions.filter(t => t.type === 'Income').reduce((acc, t) => acc + t.amount, 0);
  const periodExpense = filteredTransactions.filter(t => t.type === 'Expense').reduce((acc, t) => acc + t.amount, 0);
  const netSurplus = periodIncome - periodExpense;

  const { assets: totalAssets, liabilities: totalLiabilities, netWorth } = calculateNetWorth(filteredState);

  // Capital Account is tracked in state
  const isAllView = activeMemberIds.includes('all');
  const isMeView = activeMemberIds.length === 0;

  // Retained Earnings (Profit/Loss) = Net Worth - Capital
  const capitalDisplay = isAllView ? state.capital : (isMeView ? state.capital : 0);
  const retainedEarnings = netWorth - capitalDisplay;

  const getLabel = () => {
    if (isAllView) return 'Consolidated Family Wealth';
    if (isMeView) return 'Personal Financial Position';
    return `Custom Selection View (${activeMemberIds.length})`;
  };

  return (
    <div className="space-y-6 md:space-y-12 animate-in fade-in duration-700 pb-20 -mx-3 md:mx-0">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-6 px-4 md:px-0">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h2 className="text-xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Audit Logs</h2>
            <span className="px-1.5 py-0.5 bg-indigo-50 text-indigo-600 text-[8px] md:text-[10px] font-black rounded uppercase tracking-widest border border-indigo-100">Live</span>
          </div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{getLabel()}</p>
        </div>
        <div className="flex flex-wrap items-center gap-1 bg-white p-1 border border-slate-200 rounded-full shadow-sm w-full md:w-auto">
          {[
            { id: 'current_month', label: 'Month' },
            { id: 'last_90_days', label: 'Quarter' },
            { id: 'ytd', label: 'YTD' },
            { id: 'all_time', label: 'All' }
          ].map(p => (
            <button
              key={p.id}
              onClick={() => setActivePeriod(p.id as Period)}
              className={`flex-1 md:flex-none px-4 md:px-6 py-1.5 rounded-full text-[9px] md:text-xs font-black uppercase transition-all ${
                activePeriod === p.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'
              }`}
            >
              {p.label}
            </button>
          ))}
        </div>
      </div>

      {/* PROFIT & LOSS SECTION */}
      <section className="bg-white border-y md:border md:rounded-[2rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-900 px-6 md:px-10 py-6 md:py-8 text-white flex justify-between items-center">
          <div>
            <h3 className="text-sm md:text-lg font-black tracking-widest uppercase">P&L Account</h3>
            <p className="text-slate-500 text-[8px] md:text-[10px] mt-1 uppercase tracking-widest font-black">Period: {activePeriod.replace('_', ' ')}</p>
          </div>
          <div className="text-right">
            <p className="text-[8px] md:text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Net Flow</p>
            <p className={`text-xl md:text-3xl font-black tracking-tight ${netSurplus >= 0 ? 'text-indigo-400' : 'text-rose-400'}`}>
              {formatCurrency(netSurplus, currency)}
            </p>
          </div>
        </div>

        <div className="p-6 md:p-10 grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-16">
          <div className="space-y-6">
            <div className="flex justify-between items-center border-b border-slate-100 pb-2">
              <h4 className="text-[9px] md:text-xs font-black text-slate-400 uppercase tracking-widest">Inflow</h4>
              <p className="text-base md:text-lg font-black text-emerald-600">{formatCurrency(periodIncome, currency)}</p>
            </div>
            <div className="space-y-1">
              {filteredTransactions.filter(t => t.type === 'Income').length > 0 ? filteredTransactions.filter(t => t.type === 'Income').map(t => (
                <div key={t.id} className="flex justify-between items-center py-2 group">
                  <div>
                    <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{t.description || t.nature}</p>
                    <p className="text-[8px] font-bold text-slate-300 uppercase tracking-widest mt-0.5">{t.date}</p>
                  </div>
                  <p className="text-xs font-black text-emerald-600">+{formatCurrency(t.amount, currency)}</p>
                </div>
              )) : <p className="py-10 text-center text-slate-300 italic text-[9px] uppercase tracking-widest">No income</p>}
            </div>
          </div>

          <div className="space-y-6">
            <div className="flex justify-between items-center border-b border-slate-100 pb-2">
              <h4 className="text-[9px] md:text-xs font-black text-slate-400 uppercase tracking-widest">Outflow</h4>
              <p className="text-base md:text-lg font-black text-rose-500">{formatCurrency(periodExpense, currency)}</p>
            </div>
            <div className="space-y-1">
              {filteredTransactions.filter(t => t.type === 'Expense').length > 0 ? filteredTransactions.filter(t => t.type === 'Expense').map(t => (
                <div key={t.id} className="flex justify-between items-center py-2 group">
                  <div>
                    <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{t.description || t.nature}</p>
                    <p className="text-[8px] font-bold text-slate-300 uppercase tracking-widest mt-0.5">{(t.nature || 'UNSPECIFIED').toUpperCase()}</p>
                  </div>
                  <p className="text-xs font-black text-slate-600">-{formatCurrency(t.amount, currency)}</p>
                </div>
              )) : <p className="py-10 text-center text-slate-300 italic text-[9px] uppercase tracking-widest">No expense</p>}
            </div>
          </div>
        </div>
      </section>

      {/* BALANCE SHEET SECTION */}
      <section className="bg-white border-y md:border md:rounded-[2rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-50 px-6 md:px-10 py-6 md:py-8 text-slate-800 flex justify-between items-center border-b border-slate-200">
          <div>
            <h3 className="text-sm md:text-lg font-black tracking-widest uppercase">Balance Sheet</h3>
            <p className="text-slate-400 text-[8px] md:text-[10px] mt-1 uppercase tracking-widest font-black">Consolidated Position</p>
          </div>
          <div className="text-right">
            <p className="text-[8px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Total Equity</p>
            <p className="text-xl md:text-3xl font-black tracking-tight text-indigo-600">
              {formatCurrency(netWorth, currency)}
            </p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
          {/* ASSETS SIDE */}
          <div className="p-6 md:p-10 space-y-6">
            <h4 className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest">Asset Mapping</h4>
            <div className="space-y-6">
              <div>
                <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mb-2">Liquid Funds</p>
                {[...filteredState.banks, ...filteredState.wallets].map((a: any) => (
                  <div key={a.id} className="flex justify-between items-center py-1.5">
                    <span className="text-xs font-bold text-slate-700 uppercase tracking-tight">{a.name}</span>
                    <span className="text-xs font-black text-slate-800">{formatCurrency(a.balance, currency)}</span>
                  </div>
                ))}
              </div>

              <div>
                <p className="text-[8px] font-black text-indigo-300 uppercase tracking-widest mb-2">Equity Investments</p>
                {filteredState.assets.filter(a => a.name.toLowerCase().includes('stocks') || a.nature?.toLowerCase().includes('stocks')).map((a: any) => (
                  <div key={a.id} className="flex justify-between items-center py-1.5 px-3 -mx-3 bg-indigo-50/50 rounded-xl mb-1">
                    <span className="text-xs font-bold text-indigo-900 uppercase tracking-tight">{a.name}</span>
                    <span className="text-xs font-black text-indigo-600">{formatCurrency(a.value, currency)}</span>
                  </div>
                ))}
              </div>

              <div>
                <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest mb-2">Other Receivables</p>
                {filteredState.assets.filter(a => a.type === 'Receivable' && !a.name.toLowerCase().includes('stocks')).map((a: any) => (
                  <div key={a.id} className="flex justify-between items-center py-1.5 px-2 -mx-2 bg-slate-50/30 rounded-lg">
                    <span className="text-xs font-bold text-slate-700 uppercase tracking-tight">{a.name}</span>
                    <span className="text-xs font-black text-slate-800">{formatCurrency(a.value, currency)}</span>
                  </div>
                ))}
              </div>
            </div>
            <div className="pt-4 border-t border-slate-100 flex justify-between items-center">
              <span className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Total Valuation</span>
              <span className="text-lg md:text-2xl font-black text-indigo-600 tracking-tight">{formatCurrency(totalAssets, currency)}</span>
            </div>
          </div>

          {/* LIABILITIES & EQUITY SIDE */}
          <div className="p-6 md:p-10 space-y-6 bg-slate-50/20">
            <h4 className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest">Claims & Risk</h4>

            {/* Liabilities */}
            <div className="space-y-4">
              <p className="text-[8px] font-black text-rose-300 uppercase tracking-widest">External Liabilities</p>
              {filteredState.liabilities.filter(l => l.type === 'Payable' || l.type === 'Debt').map((l: any) => (
                <div key={l.id} className="flex justify-between items-center py-1.5 px-2 -mx-2 bg-rose-50/30 rounded-lg">
                  <span className="text-xs font-bold text-rose-700 uppercase tracking-tight">{l.name}</span>
                  <span className="text-xs font-black text-rose-800">{formatCurrency(l.amount, currency)}</span>
                </div>
              ))}
              {filteredState.cards.filter(c => c.balance >= 0).map((l: any) => (
                <div key={l.id} className="flex justify-between items-center py-1.5">
                  <span className="text-xs font-bold text-slate-500 uppercase tracking-tight">{l.lenderName}</span>
                  <span className="text-xs font-black text-slate-600">{formatCurrency(l.balance, currency)}</span>
                </div>
              ))}
            </div>

            {/* Equity / Capital Section */}
            <div className="pt-4 border-t border-slate-200 space-y-4">
              <p className="text-[8px] font-black text-indigo-300 uppercase tracking-widest">Owner's Equity</p>
              {(isAllView || isMeView) && (
                <div className="flex justify-between items-center py-1.5 px-3 -mx-3 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-100">
                  <span className="text-xs font-black uppercase tracking-widest">Capital Account</span>
                  <span className="text-sm font-black">{formatCurrency(capitalDisplay, currency)}</span>
                </div>
              )}
              <div className="flex justify-between items-center py-1.5 px-3 -mx-3 bg-slate-800 text-white rounded-xl">
                <span className="text-xs font-black uppercase tracking-widest">Retained Earnings</span>
                <span className={`text-sm font-black ${retainedEarnings >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                  {formatCurrency(retainedEarnings, currency)}
                </span>
              </div>
            </div>

            <div className="pt-4 border-t border-slate-100 flex justify-between items-center">
              <span className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Total Liab. & Equity</span>
              <span className="text-lg md:text-2xl font-black text-slate-800 tracking-tight">{formatCurrency(totalLiabilities + netWorth, currency)}</span>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Statements;

export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';
export type AccountClassification = 'Current Asset' | 'Non-Current Asset' | 'Current Liability' | 'Non-Current Liability' | 'Equity';

export interface FamilyMember {
  id: string;
  name: string;
  relation: string;
  mobileNumber: string;
  canAddTransactions?: boolean;
}

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
  familyMembers: FamilyMember[];
  cloudDatabaseName?: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  timestamp: string;
  type: 'transaction' | 'system' | 'sync';
  isRead: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
  ownerId?: string;
  accountType?: 'Savings' | 'Current' | 'Salary' | 'Others';
  customAccountType?: string;
  classification?: AccountClassification;
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number;
  last4: string;
  limit?: number;
  annualLimit?: number; 
  anniversaryDate?: string;
  billingDay?: number;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
  ownerId?: string;
  classification?: AccountClassification;
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
  ownerId?: string;
  classification?: AccountClassification;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
  ownerId?: string;
}

export interface Expense {
  id: string;
