const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, state } = useFinance();
  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: Math.abs(account.balance),
    balanceType: (account.balance < 0 && type === 'card') ? 'receivable' : 'outstanding',
    classification: account.classification || (type === 'card' ? 'Current Liability' : 'Current Asset'),
    last4: account.last4 || '',
    limit: account.limit || '',
    annualLimit: account.annualLimit || '',
    anniversaryDate: account.anniversaryDate || '',
    billingDay: account.billingDay || 1,
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    accountType: account.accountType || 'Savings',
    customAccountType: account.customAccountType || ''
  } : {
    ownerId: '',
    name: '',
    balance: '',
    balanceType: 'outstanding',
    classification: type === 'card' ? 'Current Liability' : 'Current Asset',
    accNum: '',
    accountType: 'Savings',
    customAccountType: '',
    annualLimit: '',
    anniversaryDate: '',
    billingDay: 1,
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });
  const familyMembers = state.profile?.familyMembers || [];
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId, classification: formData.classification };
    if (type === 'bank') {
      const bankData = { ...commonProps, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance), accountType: formData.accountType, customAccountType: formData.accountType === 'Others' ? formData.customAccountType : undefined };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const finalBalance = formData.balanceType === 'receivable' ? -Math.abs(Number(formData.balance)) : Math.abs(Number(formData.balance));
      const cardData = { ...commonProps, lenderName: formData.name, balance: finalBalance, last4: formData.last4, limit: formData.limit ? Number(formData.limit) : undefined, annualLimit: formData.annualLimit ? Number(formData.annualLimit) : undefined, anniversaryDate: formData.anniversaryDate, billingDay: Number(formData.billingDay), offers: formData.offers };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    }
    onCancel();
  };
  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      <div className="grid grid-cols-2 gap-3">
        <div className="space-y-1">
            <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block">Owner</label>
            <select className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}><option value="">Me</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}</select>
        </div>
        <div className="space-y-1">
            <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block">Classification</label>
            <select required className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.classification} onChange={e => setFormData({...formData, classification: e.target.value as AccountClassification})}>
                {CLASSIFICATIONS.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
        </div>
      </div>
      <div className="grid grid-cols-2 gap-3">
        <div className="space-y-1"><label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block">{type === 'card' ? 'Lender' : 'Name'}</label><input required className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} /></div>
        <div className="space-y-1"><label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block">Balance</label><input required type="number" step="any" className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-xl outline-none font-black text-sm" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} /></div>
      </div>
      <div className="flex gap-3 pt-4"><button type="button" onClick={onCancel} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 rounded-xl font-bold text-[9px] uppercase">Cancel</button><button type="submit" className="flex-[2] px-4 py-3 bg-indigo-600 text-white rounded-xl font-bold text-[9px] uppercase shadow-lg shadow-indigo-100">Commit Record</button></div>
    </form>
  );
};

const TransactionHistoryModal: React.FC<{ account: any, currency: string, onClose: () => void }> = ({ account, currency, onClose }) => {
  const { filteredState } = useFinance();
  const tenDaysAgo = new Date(); tenDaysAgo.setDate(tenDaysAgo.getDate() - 10);
  const [dateFrom, setDateFrom] = useState(tenDaysAgo.toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);

  const history = useMemo(() => {
    return (filteredState.transactions || [])
      .filter(t => t.accountId === account.id && t.date >= dateFrom && t.date <= dateTo)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredState.transactions, account.id, dateFrom, dateTo]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
      <div className="bg-white w-full max-w-2xl rounded-2xl p-6 md:p-8 shadow-2xl max-h-[85vh] flex flex-col overflow-hidden animate-slide-up">
        <div className="flex justify-between items-start mb-6 border-b border-slate-100 pb-3">
          <div>
            <h3 className="text-sm md:text-base font-black text-slate-800 uppercase tracking-tight">{account.name || account.lenderName}</h3>
            <p className="text-[8px] font-black text-indigo-500 uppercase mt-1 tracking-widest">Audit Trail</p>
          </div>
          <button onClick={onClose} className="p-1 text-slate-300 hover:text-slate-600 text-xl">✕</button>
        </div>

        <div className="flex gap-2 mb-6">
          <input type="date" className="flex-1 p-2 bg-slate-50 border border-slate-200 rounded-lg text-[10px] font-bold" value={dateFrom} onChange={e => setDateFrom(e.target.value)} />
          <input type="date" className="flex-1 p-2 bg-slate-50 border border-slate-200 rounded-lg text-[10px] font-bold" value={dateTo} onChange={e => setDateTo(e.target.value)} />
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar space-y-2">
          {history.map(t => {
            const totalCashFlow = t.amount + (t.sharedAmount || 0);
            return (
              <div key={t.id} className="p-3 bg-slate-50/50 border border-slate-100 rounded-xl flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-xs font-bold ${t.type === 'Income' || t.type === 'Liability' ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-500'}`}>
                    {t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'}
                  </div>
                  <div>
                    <p className="text-[11px] font-black text-slate-800 uppercase tracking-tight line-clamp-1">{t.description || t.nature}</p>
                    <p className="text-[8px] text-slate-400 font-bold uppercase">{t.date} • {t.nature}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className={`text-[11px] font-black ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-slate-800'}`}>
                    {formatCurrency(totalCashFlow, currency)}
                  </p>
                </div>
              </div>
            );
          })}
          {history.length === 0 && (
            <div className="py-20 text-center text-slate-300 italic text-[10px] uppercase tracking-widest">No entries</div>
          )}
        </div>
      </div>
    </div>
  );
};

