                activePeriod === ['current_month', 'last_90_days', 'ytd', 'all_time'][i] ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'
              }`}
            >
              {l}
            </button>
          ))}
        </div>
      </div>

      {/* P&L SECTION */}
      <section className="bg-white border-y md:border md:rounded-[2rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-900 px-6 md:px-10 py-6 md:py-8 text-white flex justify-between items-center">
