import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateNetWorth } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { AccountClassification } from '../types';
import { TransactionHistoryModal } from './Accounts';

type Period = 'current_month' | 'last_90_days' | 'ytd' | 'all_time';

const Statements: React.FC = () => {
  const { state, filteredState, activeMemberIds } = useFinance();
  const [activePeriod, setActivePeriod] = useState<Period>('all_time');
  const [expandedHeads, setExpandedHeads] = useState<string[]>(['Current Asset', 'Equity']);
  const [selectedAccountForHistory, setSelectedAccountForHistory] = useState<any>(null);
  const currency = filteredState.profile.currency;

  const filteredTransactions = useMemo(() => {
    const txs = filteredState.transactions || [];
    const now = new Date();
    if (activePeriod === 'current_month') {
      const start = new Date(now.getFullYear(), now.getMonth(), 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'last_90_days') {
      const start = new Date();
      start.setDate(now.getDate() - 90);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'ytd') {
      const start = new Date(now.getFullYear(), 0, 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    return txs;
  }, [filteredState.transactions, activePeriod]);

  const periodIncome = filteredTransactions.filter(t => t.type === 'Income').reduce((acc, t) => acc + t.amount, 0);
  const periodExpense = filteredTransactions.filter(t => t.type === 'Expense').reduce((acc, t) => acc + t.amount, 0);
  const netSurplus = periodIncome - periodExpense;

  const { assets: totalAssets, liabilities: totalLiabilities, netWorth } = calculateNetWorth(filteredState);

  const isAllView = activeMemberIds.includes('all');
  const isMeView = activeMemberIds.length === 0;
  const capitalDisplay = isAllView ? state.capital : (isMeView ? state.capital : 0);
  const retainedEarnings = netWorth - capitalDisplay;

  // Balance Sheet Data Structuring
  const heads = useMemo(() => {
    const data: Record<AccountClassification, { total: number, items: { id: string, name: string, value: number, source: string, originalAccount?: any }[] }> = {
      'Current Asset': { total: 0, items: [] },
      'Non-Current Asset': { total: 0, items: [] },
      'Current Liability': { total: 0, items: [] },
      'Non-Current Liability': { total: 0, items: [] },
      'Equity': { total: 0, items: [] }
    };

    // Banks
    filteredState.banks.forEach(b => {
      const cls = b.classification || 'Current Asset';
      data[cls].total += b.balance;
      data[cls].items.push({ id: b.id, name: b.name, value: b.balance, source: 'Bank', originalAccount: b });
    });

    // Wallets
    filteredState.wallets.forEach(w => {
      const cls = w.classification || 'Current Asset';
      data[cls].total += w.balance;
      data[cls].items.push({ id: w.id, name: w.name, value: w.balance, source: 'Wallet', originalAccount: w });
    });

    // Cards
    filteredState.cards.forEach(c => {
      const cls = c.classification || (c.balance < 0 ? 'Current Asset' : 'Current Liability');
      const absVal = Math.abs(c.balance);
      data[cls].total += absVal;
      data[cls].items.push({ id: c.id, name: c.lenderName, value: absVal, source: 'Credit', originalAccount: c });
    });

    // Manual Assets
    filteredState.assets.forEach(a => {
      const cls = a.classification || (a.type === 'Receivable' ? 'Current Asset' : 'Non-Current Asset');
      data[cls].total += a.value;
      data[cls].items.push({ id: a.id, name: a.name, value: a.value, source: 'Manual Asset', originalAccount: a });
    });

    // Liabilities
    filteredState.liabilities.forEach(l => {
      const cls = l.classification || (l.type === 'Payable' ? 'Current Liability' : 'Non-Current Liability');
      data[cls].total += l.amount;
      data[cls].items.push({ id: l.id, name: l.name, value: l.amount, source: 'Manual Debt', originalAccount: l });
    });

    // Equity (Capital + Retained)
    data['Equity'].total = capitalDisplay + retainedEarnings;
    data['Equity'].items.push({ id: 'owner_cap', name: 'Owner Capital', value: capitalDisplay, source: 'Equity' });
    data['Equity'].items.push({ id: 'retained_earning', name: 'Retained Earnings', value: retainedEarnings, source: 'Equity' });

    return data;
  }, [filteredState, capitalDisplay, retainedEarnings]);

  const toggleHead = (head: string) => {
    setExpandedHeads(prev => prev.includes(head) ? prev.filter(h => h !== head) : [...prev, head]);
  };

  const getLabel = () => {
    if (isAllView) return 'Consolidated Family Wealth';
    if (isMeView) return 'Personal Financial Position';
    return `Custom Selection View (${activeMemberIds.length})`;
  };

  const currentAssetsTotal = heads['Current Asset'].total;
  const currentLiabilitiesTotal = heads['Current Liability'].total;
  const currentRatio = currentLiabilitiesTotal > 0 ? (currentAssetsTotal / currentLiabilitiesTotal).toFixed(2) : '∞';

  return (
    <div className="space-y-6 md:space-y-12 animate-in fade-in duration-700 pb-20 -mx-3 md:mx-0">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-6 px-4 md:px-0">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h2 className="text-xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Financial Statements</h2>
            <span className="px-1.5 py-0.5 bg-indigo-50 text-indigo-600 text-[8px] md:text-[10px] font-black rounded uppercase tracking-widest border border-indigo-100">Audit Ready</span>
          </div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{getLabel()}</p>
        </div>
        <div className="flex flex-wrap items-center gap-1 bg-white p-1 border border-slate-200 rounded-full shadow-sm w-full md:w-auto">
          {['Month', 'Quarter', 'YTD', 'All'].map((l, i) => (
            <button
              key={l}
              onClick={() => setActivePeriod(['current_month', 'last_90_days', 'ytd', 'all_time'][i] as Period)}
              className={`flex-1 md:flex-none px-4 md:px-6 py-1.5 rounded-full text-[9px] md:text-xs font-black uppercase transition-all ${
                activePeriod === ['current_month', 'last_90_days', 'ytd', 'all_time'][i] ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'
              }`}
            >
              {l}
            </button>
          ))}
        </div>
      </div>

      {/* P&L SECTION */}
      <section className="bg-white border-y md:border md:rounded-[2rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-900 px-6 md:px-10 py-6 md:py-8 text-white flex justify-between items-center">
          <div><h3 className="text-sm md:text-lg font-black tracking-widest uppercase">P&L Account</h3></div>
          <div className="text-right">
            <p className={`text-xl md:text-3xl font-black tracking-tight ${netSurplus >= 0 ? 'text-indigo-400' : 'text-rose-400'}`}>{formatCurrency(netSurplus, currency)}</p>
          </div>
        </div>
        <div className="p-6 md:p-10 grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="flex justify-between items-center border-b border-slate-100 pb-2">
              <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Inflow</span>
              <span className="font-black text-emerald-600">{formatCurrency(periodIncome, currency)}</span>
            </div>
            <div className="flex justify-between items-center border-b border-slate-100 pb-2">
              <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Outflow</span>
              <span className="font-black text-rose-500">{formatCurrency(periodExpense, currency)}</span>
            </div>
        </div>
      </section>

      {/* BALANCE SHEET SECTION WITH DRILL-DOWN */}
      <section className="bg-white border-y md:border md:rounded-[2.5rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-50 px-6 md:px-10 py-6 md:py-8 text-slate-800 flex justify-between items-center border-b border-slate-200">
          <div>
            <h3 className="text-sm md:text-lg font-black tracking-widest uppercase">Standard Balance Sheet</h3>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Audit Mode: Tap account for ledger history</p>
          </div>
          <div className="text-right">
            <div className="flex items-center justify-end gap-2 mb-1">
                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Liquidity Ratio</span>
                <span className={`px-2 py-0.5 rounded text-[10px] font-black ${Number(currentRatio) > 1.5 ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>{currentRatio}</span>
            </div>
            <p className="text-xl md:text-3xl font-black tracking-tight text-indigo-600">{formatCurrency(netWorth, currency)}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
          {/* ASSETS PANEL */}
          <div className="p-6 md:p-10 space-y-4">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Total Assets: {formatCurrency(totalAssets, currency)}</h4>
            {(['Current Asset', 'Non-Current Asset'] as const).map(head => (
              <div key={head} className="border border-slate-100 rounded-2xl overflow-hidden bg-white shadow-sm transition-all duration-300">
                <button 
                  onClick={() => toggleHead(head)}
                  className="w-full flex justify-between items-center p-5 hover:bg-slate-50 transition-colors"
                >
                  <div className="flex items-center gap-3">
                    <div className={`w-2 h-2 rounded-full ${head === 'Current Asset' ? 'bg-indigo-600' : 'bg-slate-400'}`}></div>
                    <span className="text-xs font-black text-slate-800 uppercase tracking-widest">{head}</span>
                  </div>
                  <div className="flex items-center gap-4">
                    <span className="text-sm font-black text-slate-800">{formatCurrency(heads[head].total, currency)}</span>
                    <span className={`text-[10px] transition-transform duration-300 ${expandedHeads.includes(head) ? 'rotate-180' : ''}`}>▼</span>
                  </div>
                </button>
                {expandedHeads.includes(head) && (
                  <div className="px-5 pb-5 pt-2 space-y-1 bg-slate-50/30">
                    {heads[head].items.length > 0 ? heads[head].items.map((item) => (
                      <button 
                        key={item.id} 
                        onClick={() => item.originalAccount && setSelectedAccountForHistory(item.originalAccount)}
                        className={`w-full flex justify-between items-center p-3 rounded-xl transition-all border border-transparent ${item.originalAccount ? 'hover:bg-white hover:border-slate-200 hover:shadow-sm cursor-pointer' : 'cursor-default'}`}
                      >
                        <div className="text-left">
                          <p className="text-[11px] font-bold text-slate-800 uppercase tracking-tight">{item.name}</p>
                          <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest">{item.source}</p>
                        </div>
                        <div className="flex items-center gap-3">
                          <span className="text-[11px] font-black text-slate-600">{formatCurrency(item.value, currency)}</span>
                          {item.originalAccount && <span className="text-[10px] text-indigo-400 opacity-0 group-hover:opacity-100">➜</span>}
                        </div>
                      </button>
                    )) : <p className="text-center py-4 text-[9px] font-black text-slate-300 uppercase italic">Empty Sector</p>}
                  </div>
                )}
              </div>
            ))}
          </div>

          {/* LIABILITIES & EQUITY PANEL */}
          <div className="p-6 md:p-10 space-y-4 bg-slate-50/10">
            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Liabilities & Equity: {formatCurrency(totalLiabilities + netWorth, currency)}</h4>
            {(['Current Liability', 'Non-Current Liability', 'Equity'] as const).map(head => (
              <div key={head} className="border border-slate-100 rounded-2xl overflow-hidden bg-white shadow-sm transition-all duration-300">
                <button 
                  onClick={() => toggleHead(head)}
                  className="w-full flex justify-between items-center p-5 hover:bg-slate-50 transition-colors"
                >
                  <div className="flex items-center gap-3">
                    <div className={`w-2 h-2 rounded-full ${head === 'Equity' ? 'bg-emerald-500' : 'bg-rose-400'}`}></div>
                    <span className="text-xs font-black text-slate-800 uppercase tracking-widest">{head}</span>
                  </div>
                  <div className="flex items-center gap-4">
