                    <span className="text-sm font-black text-slate-800">{formatCurrency(heads[head].total, currency)}</span>
                    <span className={`text-[10px] transition-transform duration-300 ${expandedHeads.includes(head) ? 'rotate-180' : ''}`}>▼</span>
                  </div>
                </button>
                {expandedHeads.includes(head) && (
                  <div className="px-5 pb-5 pt-2 space-y-1 bg-slate-50/30">
                    {heads[head].items.length > 0 ? heads[head].items.map((item) => (
                      <button 
                        key={item.id} 
                        onClick={() => item.originalAccount && setSelectedAccountForHistory(item.originalAccount)}
                        className={`w-full flex justify-between items-center p-3 rounded-xl transition-all border border-transparent ${item.originalAccount ? 'hover:bg-white hover:border-slate-200 hover:shadow-sm cursor-pointer' : 'cursor-default'}`}
