export default Statements;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateNetWorth } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { AccountClassification } from '../types';
import { TransactionHistoryModal } from './Accounts';

type Period = 'current_month' | 'last_90_days' | 'ytd' | 'all_time' | 'custom';

const Statements: React.FC = () => {
  const { state, filteredState, activeMemberIds } = useFinance();
  const [activePeriod, setActivePeriod] = useState<Period>('all_time');

  // Custom Date States
  const [customStart, setCustomStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customEnd, setCustomEnd] = useState(new Date().toISOString().split('T')[0]);

  const [expandedHeads, setExpandedHeads] = useState<string[]>(['Current Asset', 'Equity']);
  const [selectedAccountForHistory, setSelectedAccountForHistory] = useState<any>(null);
  const currency = filteredState.profile.currency;

  const filteredTransactions = useMemo(() => {
    const txs = filteredState.transactions || [];
    const now = new Date();

    if (activePeriod === 'current_month') {
      const start = new Date(now.getFullYear(), now.getMonth(), 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'last_90_days') {
      const start = new Date();
      start.setDate(now.getDate() - 90);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'ytd') {
      const start = new Date(now.getFullYear(), 0, 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'custom') {
      const start = new Date(customStart);
      const end = new Date(customEnd);
      end.setHours(23, 59, 59, 999);
      return txs.filter(t => {
        const d = new Date(t.date);
        return d >= start && d <= end;
      });
    }
    return txs;
  }, [filteredState.transactions, activePeriod, customStart, customEnd]);

  const periodIncome = filteredTransactions.filter(t => t.type === 'Income').reduce((acc, t) => acc + t.amount, 0);
  const periodExpense = filteredTransactions.filter(t => t.type === 'Expense').reduce((acc, t) => acc + t.amount, 0);
  const netSurplus = periodIncome - periodExpense;

  const { assets: totalAssets, liabilities: totalLiabilities, netWorth } = calculateNetWorth(filteredState);

  const isAllView = activeMemberIds.includes('all');
  const isMeView = activeMemberIds.length === 0;
  const capitalDisplay = isAllView ? state.capital : (isMeView ? state.capital : 0);
  const retainedEarnings = netWorth - capitalDisplay;

  // Balance Sheet Data Structuring with Auto-Reclassification of Negative Balances
  const heads = useMemo(() => {
    const data: Record<AccountClassification, { total: number, items: { id: string, name: string, value: number, source: string, originalAccount?: any }[] }> = {
      'Current Asset': { total: 0, items: [] },
      'Non-Current Asset': { total: 0, items: [] },
      'Current Liability': { total: 0, items: [] },
      'Non-Current Liability': { total: 0, items: [] },
      'Equity': { total: 0, items: [] }
    };

    const processAccount = (id: string, name: string, balance: number, classification: AccountClassification, source: string, originalAccount: any) => {
      let cls = classification;
      let val = balance;

      const isAssetType = cls === 'Current Asset' || cls === 'Non-Current Asset';
      const isLiabilityType = cls === 'Current Liability' || cls === 'Non-Current Liability';

      if (val < 0 && isAssetType) {
        cls = 'Current Liability';
        val = Math.abs(val);
      } else if (val < 0 && isLiabilityType) {
        cls = 'Current Asset';
        val = Math.abs(val);
      }

      data[cls].total += val;
      data[cls].items.push({ id, name, value: val, source, originalAccount });
    };

    filteredState.banks.forEach(b => {
      processAccount(b.id, b.name, b.balance, b.classification || 'Current Asset', 'Bank', b);
    });

    filteredState.wallets.forEach(w => {
      processAccount(w.id, w.name, w.balance, w.classification || 'Current Asset', 'Wallet', w);
    });

    filteredState.cards.forEach(c => {
      processAccount(c.id, c.lenderName, c.balance, c.classification || 'Current Liability', 'Credit', c);
    });

    filteredState.assets.forEach(a => {
      processAccount(a.id, a.name, a.value, a.classification || (a.type === 'Receivable' ? 'Current Asset' : 'Non-Current Asset'), 'Manual Asset', a);
    });

    filteredState.liabilities.forEach(l => {
      processAccount(l.id, l.name, l.amount, l.classification || (l.type === 'Payable' ? 'Current Liability' : 'Non-Current Liability'), 'Manual Debt', l);
    });

    data['Equity'].total = capitalDisplay + retainedEarnings;
    data['Equity'].items.push({ id: 'owner_cap', name: 'Owner Capital', value: capitalDisplay, source: 'Equity' });
    data['Equity'].items.push({ id: 'retained_earning', name: 'Retained Earnings', value: retainedEarnings, source: 'Equity' });

    return data;
  }, [filteredState, capitalDisplay, retainedEarnings]);

  const toggleHead = (head: string) => {
    setExpandedHeads(prev => prev.includes(head) ? prev.filter(h => h !== head) : [...prev, head]);
  };

  const currentAssetsTotal = heads['Current Asset'].total;
  const currentLiabilitiesTotal = heads['Current Liability'].total;
  const currentRatio = currentLiabilitiesTotal > 0 ? (currentAssetsTotal / currentLiabilitiesTotal).toFixed(2) : '∞';

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-700 pb-20 -mx-3 md:mx-0">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-6 px-4 md:px-0">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h2 className="text-xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Audit Statements</h2>
            <span className="px-1.5 py-0.5 bg-indigo-50 text-indigo-600 text-[8px] md:text-[10px] font-black rounded uppercase tracking-widest border border-indigo-100">Live Ledger</span>
          </div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
            {/* Fix: changed isMeSelected to isMeView */}
            {isAllView ? 'Consolidated Family Wealth' : isMeView ? 'Personal Position' : 'Selective Portfolio'}
          </p>
        </div>

        <div className="flex flex-col md:flex-row items-stretch md:items-center gap-4 w-full md:w-auto">
          {activePeriod === 'custom' && (
            <div className="flex items-center gap-2 bg-white p-2 border border-slate-200 rounded-2xl shadow-sm animate-in slide-in-from-right-4">
              <input type="date" value={customStart} onChange={e => setCustomStart(e.target.value)} className="bg-transparent border-0 text-[10px] font-black uppercase outline-none" />
              <span className="text-[10px] font-black text-slate-300">TO</span>
              <input type="date" value={customEnd} onChange={e => setCustomEnd(e.target.value)} className="bg-transparent border-0 text-[10px] font-black uppercase outline-none" />
            </div>
          )}
          <div className="flex flex-wrap items-center gap-1 bg-white p-1 border border-slate-200 rounded-full shadow-sm">
            {[
              { id: 'current_month', label: 'Month' },
              { id: 'last_90_days', label: 'Quarter' },
              { id: 'ytd', label: 'YTD' },
              { id: 'all_time', label: 'All' },
              { id: 'custom', label: '📅' }
            ].map(p => (
              <button
                key={p.id}
                onClick={() => setActivePeriod(p.id as Period)}
                className={`px-4 py-1.5 rounded-full text-[9px] md:text-xs font-black uppercase transition-all ${
                  activePeriod === p.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'
                }`}
              >
                {p.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* P&L SECTION */}
      <section className="bg-white border-y md:border md:rounded-[2.5rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-900 px-6 md:px-10 py-8 md:py-10 text-white">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6">
            <div>
              <h3 className="text-sm md:text-lg font-black tracking-widest uppercase mb-1">Profit & Loss Account</h3>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest">Performance Metric Summary</p>
            </div>
            <div className="text-center md:text-right">
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Net Flow Surplus</p>
              <p className={`text-3xl md:text-5xl font-black tracking-tighter ${netSurplus >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                {formatCurrency(netSurplus, currency)}
              </p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4 mt-10 pt-10 border-t border-white/10">
            <div className="text-center md:text-left">
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Total Inflow</p>
              <p className="text-xl md:text-2xl font-black text-emerald-400">{formatCurrency(periodIncome, currency)}</p>
            </div>
            <div className="text-center md:text-right">
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Total Outflow</p>
              <p className="text-xl md:text-2xl font-black text-rose-400">{formatCurrency(periodExpense, currency)}</p>
            </div>
          </div>
        </div>

        <div className="p-6 md:p-10 grid grid-cols-1 md:grid-cols-2 gap-10">
          <div className="space-y-4">
            <div className="flex justify-between items-center border-b border-slate-100 pb-3">
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Revenue Streams</h4>
              <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-1 rounded">Total: {formatCurrency(periodIncome, currency)}</span>
            </div>
            <div className="space-y-2">
              {filteredTransactions.filter(t => t.type === 'Income').length > 0 ? (
                filteredTransactions.filter(t => t.type === 'Income').map(t => (
                  <div key={t.id} className="flex justify-between items-center p-3 rounded-xl hover:bg-slate-50 transition-colors border border-transparent hover:border-slate-100">
                    <div>
                      <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{t.description || t.nature}</p>
                      <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-0.5">{t.date}</p>
                    </div>
                    <p className="text-xs font-black text-emerald-600">+{formatCurrency(t.amount, currency)}</p>
                  </div>
                ))
              ) : (
                <p className="py-10 text-center text-slate-300 italic text-[9px] uppercase font-black tracking-widest">No inflow records</p>
              )}
            </div>
          </div>

          <div className="space-y-4">
