import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, isCloudSyncing, setActiveMemberIds, resetBoarding, simulateSync, markNotificationRead, clearNotifications } = useFinance();
  const [showNotifications, setShowNotifications] = useState(false);
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isShrunk, setIsShrunk] = useState(false);

  const mainRef = useRef<HTMLDivElement>(null);
  const notificationsRef = useRef<HTMLDivElement>(null);
  const selectorRef = useRef<HTMLDivElement>(null);
  const familyMembers = state.profile?.familyMembers || [];
  const unreadCount = state.notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    const handleScroll = () => {
      if (mainRef.current) {
        setIsShrunk(mainRef.current.scrollTop > 40);
      }
    };
    const currentMain = mainRef.current;
    if (currentMain) {
      currentMain.addEventListener('scroll', handleScroll);
    }
    return () => currentMain?.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationsRef.current && !notificationsRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
      if (selectorRef.current && !selectorRef.current.contains(event.target as Node)) {
        setShowMemberSelector(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const isAllSelected = activeMemberIds.includes('all');
  const isMeSelected = activeMemberIds.length === 0;

  const getSelectionLabel = () => {
    if (isAllSelected) return 'Entire Family';
    if (isMeSelected) return 'Mine';
    if (activeMemberIds.length === 1) {
      const member = familyMembers.find(m => m.id === activeMemberIds[0]);
      return member ? member.name : 'Custom View';
    }
    return `Group (${activeMemberIds.length})`;
  };

  const toggleMember = (id: string | 'all') => {
    if (id === 'all') {
      setActiveMemberIds(['all']);
    } else if (id === '') {
      setActiveMemberIds([]);
    } else {
      let nextIds = activeMemberIds.filter(mid => mid !== 'all');
      if (nextIds.includes(id)) {
        nextIds = nextIds.filter(mid => mid !== id);
      } else {
        nextIds.push(id);
      }
      setActiveMemberIds(nextIds);
    }
  };

  const handleSync = async () => {
    setIsSyncing(true);
    await simulateSync();
    setIsSyncing(false);
  };

  const navItems = [
    { id: 'dashboard', label: 'Dash', icon: '📊' },
    { id: 'accounts', label: 'Accounts', icon: '🏦' },
    { id: 'transactions', label: 'Txns', icon: '💸' },
    { id: 'statements', label: 'Reports', icon: '📜' },
    { id: 'profile', label: 'You', icon: '👤' },
  ];

  return (
    <div className="h-screen flex flex-col md:flex-row bg-slate-50 font-sans selection:bg-indigo-100 overflow-hidden">
      {/* Desktop Sidebar */}
      <aside className="hidden md:flex w-64 bg-slate-900 border-r border-slate-800 z-30 flex-col text-white sticky top-0 h-screen">
        <div className="p-8">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold">M</div>
             <h1 className="text-xl font-bold tracking-tight">MyFin</h1>
          </div>
          <p className="text-xs font-medium text-slate-400 mt-1 uppercase tracking-widest">Finance Suite</p>
        </div>

        <nav className="flex-1 px-4 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-4 px-5 py-3 rounded-xl text-sm font-medium transition-all ${
                activeTab === item.id 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
            >
              <span className="text-lg">{item.icon}</span>
              {item.label}
            </button>
          ))}

          <div className="pt-10 space-y-1">
             <p className="px-5 text-[10px] font-bold text-slate-600 uppercase tracking-widest mb-2">Session</p>
             <button
              onClick={resetBoarding}
              className="w-full flex items-center gap-4 px-5 py-3 rounded-xl text-xs font-medium text-slate-500 hover:text-rose-400 transition-colors uppercase"
            >
              <span>🚪</span> Sign Out
            </button>
          </div>
        </nav>
      </aside>

      {/* Main Content Area */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto overflow-x-hidden">
        {/* Morphing Header */}
        <header className={`sticky top-0 bg-white/80 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all duration-300 morph-header ${isShrunk ? 'h-14' : 'h-20'} pt-[var(--sat)]`}>
          <div className="flex items-center gap-4">
            <div className="md:hidden flex items-center gap-2">
               <div className={`bg-indigo-600 rounded-lg flex items-center justify-center font-bold text-white transition-all ${isShrunk ? 'w-7 h-7 text-xs' : 'w-9 h-9 text-sm'}`}>M</div>
               {!isShrunk && <span className="font-black text-slate-800 tracking-tighter text-lg">MyFin</span>}
            </div>

            <div className="flex items-center gap-2">
              <button 
                onClick={handleSync}
                disabled={isSyncing}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${
                  isSyncing 
