import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateNetWorth } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { AccountClassification } from '../types';
import { TransactionHistoryModal } from './Accounts';

type Period = 'current_month' | 'last_90_days' | 'ytd' | 'all_time' | 'custom';

const Statements: React.FC = () => {
  const { state, filteredState, activeMemberIds } = useFinance();
  const [activePeriod, setActivePeriod] = useState<Period>('all_time');

  // Custom Date States
  const [customStart, setCustomStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customEnd, setCustomEnd] = useState(new Date().toISOString().split('T')[0]);

  const [expandedHeads, setExpandedHeads] = useState<string[]>(['Current Asset', 'Equity']);
  const [selectedAccountForHistory, setSelectedAccountForHistory] = useState<any>(null);
  const currency = filteredState.profile.currency;

  const filteredTransactions = useMemo(() => {
    const txs = filteredState.transactions || [];
    const now = new Date();

    if (activePeriod === 'current_month') {
      const start = new Date(now.getFullYear(), now.getMonth(), 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'last_90_days') {
      const start = new Date();
      start.setDate(now.getDate() - 90);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'ytd') {
      const start = new Date(now.getFullYear(), 0, 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'custom') {
      const start = new Date(customStart);
      const end = new Date(customEnd);
      end.setHours(23, 59, 59, 999);
      return txs.filter(t => {
        const d = new Date(t.date);
        return d >= start && d <= end;
      });
    }
    return txs;
  }, [filteredState.transactions, activePeriod, customStart, customEnd]);

  const periodIncome = filteredTransactions.filter(t => t.type === 'Income').reduce((acc, t) => acc + t.amount, 0);
  const periodExpense = filteredTransactions.filter(t => t.type === 'Expense').reduce((acc, t) => acc + t.amount, 0);
  const netSurplus = periodIncome - periodExpense;

  const { assets: totalAssets, liabilities: totalLiabilities, netWorth } = calculateNetWorth(filteredState);

  const isAllView = activeMemberIds.includes('all');
  const isMeView = activeMemberIds.length === 0;
  const isConsolidatedView = isAllView || activeMemberIds.length > 1;

  const capitalDisplay = isAllView ? state.capital : (isMeView ? state.capital : 0);
  const retainedEarnings = netWorth - capitalDisplay;

  // Balance Sheet Data Structuring with Auto-Reclassification of Negative Balances
  const heads = useMemo(() => {
    const data: Record<AccountClassification, { total: number, items: { id: string, name: string, value: number, source: string, originalAccount?: any }[] }> = {
      'Current Asset': { total: 0, items: [] },
      'Non-Current Asset': { total: 0, items: [] },
      'Current Liability': { total: 0, items: [] },
      'Non-Current Liability': { total: 0, items: [] },
      'Equity': { total: 0, items: [] }
    };

    const processAccount = (id: string, name: string, balance: number, classification: AccountClassification, source: string, originalAccount: any) => {
      let cls = classification;
      let val = balance;

      const isAssetType = cls === 'Current Asset' || cls === 'Non-Current Asset';
      const isLiabilityType = cls === 'Current Liability' || cls === 'Non-Current Liability';

      if (val < 0 && isAssetType) {
        cls = 'Current Liability';
        val = Math.abs(val);
      } else if (val < 0 && isLiabilityType) {
        cls = 'Current Asset';
        val = Math.abs(val);
      }

      data[cls].total += val;
      data[cls].items.push({ id, name, value: val, source, originalAccount });
    };

    filteredState.banks.forEach(b => {
      processAccount(b.id, b.name, b.balance, b.classification || 'Current Asset', 'Bank', b);
    });

    filteredState.wallets.forEach(w => {
      processAccount(w.id, w.name, w.balance, w.classification || 'Current Asset', 'Wallet', w);
    });

    filteredState.cards.forEach(c => {
      processAccount(c.id, c.lenderName, c.balance, c.classification || 'Current Liability', 'Credit', c);
    });

    filteredState.assets.forEach(a => {
      processAccount(a.id, a.name, a.value, a.classification || (a.type === 'Receivable' ? 'Current Asset' : 'Non-Current Asset'), 'Manual Asset', a);
    });

    filteredState.liabilities.forEach(l => {
      processAccount(l.id, l.name, l.amount, l.classification || (l.type === 'Payable' ? 'Current Liability' : 'Non-Current Liability'), 'Manual Debt', l);
    });

    data['Equity'].total = capitalDisplay + retainedEarnings;
    data['Equity'].items.push({ id: 'owner_cap', name: 'Owner Capital', value: capitalDisplay, source: 'Equity' });
    data['Equity'].items.push({ id: 'retained_earning', name: 'Retained Earnings', value: retainedEarnings, source: 'Equity' });

    return data;
  }, [filteredState, capitalDisplay, retainedEarnings]);

  const toggleHead = (head: string) => {
    setExpandedHeads(prev => prev.includes(head) ? prev.filter(h => h !== head) : [...prev, head]);
  };

  const currentAssetsTotal = heads['Current Asset'].total + heads['Non-Current Asset'].total;
  const currentLiabilitiesTotal = heads['Current Liability'].total + heads['Non-Current Liability'].total + heads['Equity'].total;
  const liquidityRatioTotal = heads['Current Liability'].total > 0 ? (heads['Current Asset'].total / heads['Current Liability'].total).toFixed(2) : '∞';

  const assetHeaderLabel = isMeView ? "Total Assets" : (isConsolidatedView ? "Consolidated Assets" : "Capital Resources");
  const liabilityHeaderLabel = isMeView ? "Total Equity and Liabilities" : (isConsolidatedView ? "Consolidated Equity and Liabilities" : "Claims & Equity");

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-700 pb-20 -mx-3 md:mx-0">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-6 px-4 md:px-0">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h2 className="text-xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Audit Statements</h2>
            <span className="px-1.5 py-0.5 bg-indigo-50 text-indigo-600 text-[8px] md:text-[10px] font-black rounded uppercase tracking-widest border border-indigo-100">Live Ledger</span>
          </div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
            {isAllView ? 'Consolidated Family Wealth' : isMeView ? 'Personal Position' : 'Selective Portfolio'}
          </p>
        </div>

        <div className="flex flex-col md:flex-row items-stretch md:items-center gap-4 w-full md:w-auto">
          {activePeriod === 'custom' && (
            <div className="flex items-center gap-2 bg-white p-2 border border-slate-200 rounded-2xl shadow-sm animate-in slide-in-from-right-4">
              <input type="date" value={customStart} onChange={e => setCustomStart(e.target.value)} className="bg-transparent border-0 text-[10px] font-black uppercase outline-none" />
              <span className="text-[10px] font-black text-slate-300">TO</span>
              <input type="date" value={customEnd} onChange={e => setCustomEnd(e.target.value)} className="bg-transparent border-0 text-[10px] font-black uppercase outline-none" />
            </div>
          )}
          <div className="flex flex-wrap items-center gap-1 bg-white p-1 border border-slate-200 rounded-full shadow-sm">
            {[
              { id: 'current_month', label: 'Month' },
              { id: 'last_90_days', label: 'Quarter' },
              { id: 'ytd', label: 'YTD' },
              { id: 'all_time', label: 'All' },
              { id: 'custom', label: '📅' }
            ].map(p => (
              <button
                key={p.id}
                onClick={() => setActivePeriod(p.id as Period)}
                className={`px-4 py-1.5 rounded-full text-[9px] md:text-xs font-black uppercase transition-all ${
                  activePeriod === p.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'
                }`}
              >
                {p.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* P&L SECTION */}
      <section className="bg-white border-y md:border md:rounded-[2.5rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-900 px-6 md:px-10 py-8 md:py-10 text-white">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6">
            <div>
              <h3 className="text-sm md:text-lg font-black tracking-widest uppercase mb-1">Profit & Loss Account</h3>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-widest">Performance Metric Summary</p>
            </div>
            <div className="text-center md:text-right">
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Net Flow Surplus</p>
              <p className={`text-3xl md:text-5xl font-black tracking-tighter ${netSurplus >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                {formatCurrency(netSurplus, currency)}
              </p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4 mt-10 pt-10 border-t border-white/10">
            <div className="text-center md:text-left">
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Total Inflow</p>
              <p className="text-xl md:text-2xl font-black text-emerald-400">{formatCurrency(periodIncome, currency)}</p>
            </div>
            <div className="text-center md:text-right">
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">Total Outflow</p>
              <p className="text-xl md:text-2xl font-black text-rose-400">{formatCurrency(periodExpense, currency)}</p>
            </div>
          </div>
        </div>

        <div className="p-6 md:p-10 grid grid-cols-1 md:grid-cols-2 gap-10">
          <div className="space-y-4">
            <div className="flex justify-between items-center border-b border-slate-100 pb-3">
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Revenue Streams</h4>
              <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-1 rounded">Total: {formatCurrency(periodIncome, currency)}</span>
            </div>
            <div className="space-y-2">
              {filteredTransactions.filter(t => t.type === 'Income').length > 0 ? (
                filteredTransactions.filter(t => t.type === 'Income').map(t => (
                  <div key={t.id} className="flex justify-between items-center p-3 rounded-xl hover:bg-slate-50 transition-colors border border-transparent hover:border-slate-100">
                    <div>
                      <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{t.description || t.nature}</p>
                      <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-0.5">{t.date}</p>
                    </div>
                    <p className="text-xs font-black text-emerald-600">+{formatCurrency(t.amount, currency)}</p>
                  </div>
                ))
              ) : (
                <p className="py-10 text-center text-slate-300 italic text-[9px] uppercase font-black tracking-widest">No inflow records</p>
              )}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center border-b border-slate-100 pb-3">
              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Operating Burn</h4>
              <span className="text-[10px] font-black text-rose-600 bg-rose-50 px-2 py-1 rounded">Total: {formatCurrency(periodExpense, currency)}</span>
            </div>
            <div className="space-y-2">
              {filteredTransactions.filter(t => t.type === 'Expense').length > 0 ? (
                filteredTransactions.filter(t => t.type === 'Expense').map(t => (
                  <div key={t.id} className="flex justify-between items-center p-3 rounded-xl hover:bg-slate-50 transition-colors border border-transparent hover:border-slate-100">
                    <div>
                      <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{t.description || t.nature}</p>
                      <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-0.5">{t.nature.toUpperCase()}</p>
                    </div>
                    <p className="text-xs font-black text-slate-700">-{formatCurrency(t.amount, currency)}</p>
                  </div>
                ))
              ) : (
                <p className="py-10 text-center text-slate-300 italic text-[9px] uppercase font-black tracking-widest">No outflow records</p>
              )}
            </div>
          </div>
        </div>
      </section>

      {/* BALANCE SHEET SECTION */}
      <section className="bg-white border-y md:border md:rounded-[2.5rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-50 px-6 md:px-10 py-8 md:py-10 text-slate-800 border-b border-slate-200">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6">
            <div>
              <h3 className="text-sm md:text-lg font-black tracking-widest uppercase mb-1">Standard Balance Sheet</h3>
              <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Current Solvency Audit</p>
            </div>
            <div className="text-center md:text-right">
              <div className="flex items-center justify-center md:justify-end gap-2 mb-2">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Liquidity Ratio</span>
                  <span className={`px-2 py-1 rounded text-[10px] font-black ${Number(liquidityRatioTotal) > 1.5 ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>{liquidityRatioTotal}</span>
              </div>
              <p className="text-3xl md:text-5xl font-black tracking-tighter text-indigo-600">{formatCurrency(netWorth, currency)}</p>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">{isMeView ? 'Personal Net Worth' : 'Total Family Equity'}</p>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
          {/* ASSETS PANEL */}
          <div className="p-6 md:p-10 space-y-6">
            <div className="flex justify-between items-center px-2">
              <h4 className="text-[11px] font-black text-slate-800 uppercase tracking-widest">{isMeView ? "Total Assets" : (isConsolidatedView ? "Consolidated Assets" : "Capital Resources")}</h4>
              <span className="text-xs font-black text-indigo-600">TOTAL: {formatCurrency(currentAssetsTotal, currency)}</span>
            </div>

            <div className="space-y-4">
              {(['Current Asset', 'Non-Current Asset'] as const).map(head => (
                <div key={head} className="border border-slate-100 rounded-3xl overflow-hidden bg-white shadow-sm transition-all duration-300">
                  <button onClick={() => toggleHead(head)} className="w-full flex justify-between items-center p-5 hover:bg-slate-50 transition-colors">
                    <div className="flex items-center gap-3">
                      <div className={`w-2 h-2 rounded-full ${head === 'Current Asset' ? 'bg-indigo-600' : 'bg-slate-400'}`}></div>
                      <span className="text-xs font-black text-slate-800 uppercase tracking-widest">{head}</span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="text-sm font-black text-slate-800">{formatCurrency(heads[head].total, currency)}</span>
                      <span className={`text-[10px] transition-transform duration-300 ${expandedHeads.includes(head) ? 'rotate-180' : ''}`}>▼</span>
                    </div>
                  </button>
                  {expandedHeads.includes(head) && (
                    <div className="px-5 pb-5 pt-2 space-y-1 bg-slate-50/30">
                      {heads[head].items.length > 0 ? (
                        heads[head].items.map((item) => (
                          <button key={item.id} onClick={() => item.originalAccount && setSelectedAccountForHistory(item.originalAccount)} className={`w-full flex justify-between items-center p-3 rounded-xl transition-all border border-transparent ${item.originalAccount ? 'hover:bg-white hover:border-slate-200 hover:shadow-sm cursor-pointer' : 'cursor-default'}`}>
                            <div className="text-left">
                              <p className="text-[11px] font-bold text-slate-800 uppercase tracking-tight">{item.name}</p>
                              <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest">{item.source}</p>
                            </div>
                            <div className="flex items-center gap-3">
                              <span className="text-[11px] font-black text-slate-600">{formatCurrency(item.value, currency)}</span>
                              {item.originalAccount && <span className="text-[10px] text-indigo-400 opacity-0 group-hover:opacity-100">➜</span>}
                            </div>
                          </button>
                        ))
                      ) : (
                        <p className="text-center py-4 text-[9px] font-black text-slate-300 uppercase italic">Empty Sector</p>
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="p-6 bg-slate-50 rounded-3xl border border-dashed border-slate-200 flex justify-between items-center mt-8">
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{assetHeaderLabel}</p>
               <p className="text-2xl font-black text-slate-800 tracking-tighter">{formatCurrency(currentAssetsTotal, currency)}</p>
            </div>
          </div>

          {/* LIABILITIES & EQUITY PANEL */}
          <div className="p-6 md:p-10 space-y-6 bg-slate-50/10">
            <div className="flex justify-between items-center px-2">
              <h4 className="text-[11px] font-black text-slate-800 uppercase tracking-widest">{isMeView ? "Total Equity and Liabilities" : (isConsolidatedView ? "Consolidated Equity and Liabilities" : "Claims & Equity")}</h4>
              <span className="text-xs font-black text-rose-600">TOTAL: {formatCurrency(currentLiabilitiesTotal, currency)}</span>
            </div>

            <div className="space-y-4">
              {(['Current Liability', 'Non-Current Liability', 'Equity'] as const).map(head => (
                <div key={head} className="border border-slate-100 rounded-3xl overflow-hidden bg-white shadow-sm transition-all duration-300">
                  <button onClick={() => toggleHead(head)} className="w-full flex justify-between items-center p-5 hover:bg-slate-50 transition-colors">
                    <div className="flex items-center gap-3">
                      <div className={`w-2 h-2 rounded-full ${head === 'Equity' ? 'bg-emerald-500' : 'bg-rose-400'}`}></div>
                      <span className="text-xs font-black text-slate-800 uppercase tracking-widest">{head}</span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="text-sm font-black text-slate-800">{formatCurrency(heads[head].total, currency)}</span>
                      <span className={`text-[10px] transition-transform duration-300 ${expandedHeads.includes(head) ? 'rotate-180' : ''}`}>▼</span>
                    </div>
                  </button>
                  {expandedHeads.includes(head) && (
                    <div className="px-5 pb-5 pt-2 space-y-1 bg-slate-50/30">
                      {heads[head].items.length > 0 ? (
                        heads[head].items.map((item) => (
                          <button key={item.id} onClick={() => item.originalAccount && setSelectedAccountForHistory(item.originalAccount)} className={`w-full flex justify-between items-center p-3 rounded-xl transition-all border border-transparent ${item.originalAccount ? 'hover:bg-white hover:border-slate-200 hover:shadow-sm cursor-pointer' : 'cursor-default'}`}>
                            <div className="text-left">
                              <p className="text-[11px] font-bold text-slate-800 uppercase tracking-tight">{item.name}</p>
                              <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest">{item.source}</p>
                            </div>
                            <div className="flex items-center gap-3">
                              <span className="text-[11px] font-black text-slate-600">{formatCurrency(item.value, currency)}</span>
                              {item.originalAccount && <span className="text-[10px] text-indigo-400">➜</span>}
                            </div>
                          </button>
                        ))
                      ) : (
                        <p className="text-center py-4 text-[9px] font-black text-slate-300 uppercase italic">Empty Sector</p>
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="p-6 bg-indigo-600 rounded-3xl shadow-xl flex justify-between items-center mt-8">
               <p className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">{liabilityHeaderLabel}</p>
               <p className="text-2xl font-black text-white tracking-tighter">{formatCurrency(currentLiabilitiesTotal, currency)}</p>
            </div>
          </div>
        </div>
      </section>

      {/* Drill-down Modal for Ledger History */}
      {selectedAccountForHistory && (
        <TransactionHistoryModal 
          account={selectedAccountForHistory} 
          currency={currency} 
          onClose={() => setSelectedAccountForHistory(null)} 
        />
      )}
    </div>
  );
};

export default Statements;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateNetWorth } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { AccountClassification } from '../types';
import { TransactionHistoryModal } from './Accounts';

type Period = 'current_month' | 'last_90_days' | 'ytd' | 'all_time' | 'custom';

const Statements: React.FC = () => {
  const { state, filteredState, activeMemberIds } = useFinance();
  const [activePeriod, setActivePeriod] = useState<Period>('all_time');

  // Custom Date States for Calendar Selection
  const [customStart, setCustomStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customEnd, setCustomEnd] = useState(new Date().toISOString().split('T')[0]);

  const [expandedHeads, setExpandedHeads] = useState<string[]>(['Current Asset', 'Equity']);
  const [selectedAccountForHistory, setSelectedAccountForHistory] = useState<any>(null);
  const currency = filteredState.profile.currency;

  const filteredTransactions = useMemo(() => {
    const txs = filteredState.transactions || [];
    const now = new Date();

    if (activePeriod === 'current_month') {
      const start = new Date(now.getFullYear(), now.getMonth(), 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'last_90_days') {
      const start = new Date();
      start.setDate(now.getDate() - 90);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'ytd') {
      const start = new Date(now.getFullYear(), 0, 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'custom') {
      const start = new Date(customStart);
      const end = new Date(customEnd);
      end.setHours(23, 59, 59, 999);
      return txs.filter(t => {
        const d = new Date(t.date);
        return d >= start && d <= end;
      });
    }
    return txs;
  }, [filteredState.transactions, activePeriod, customStart, customEnd]);

  const periodIncome = filteredTransactions.filter(t => t.type === 'Income').reduce((acc, t) => acc + t.amount, 0);
  const periodExpense = filteredTransactions.filter(t => t.type === 'Expense').reduce((acc, t) => acc + t.amount, 0);
  const netSurplus = periodIncome - periodExpense;

  const { netWorth } = calculateNetWorth(filteredState);

  const isAllView = activeMemberIds.includes('all');
  const isMeView = activeMemberIds.length === 0;
  const isConsolidatedView = isAllView || activeMemberIds.length > 1;

  const capitalDisplay = isAllView ? state.capital : (isMeView ? state.capital : 0);
  const retainedEarnings = netWorth - capitalDisplay;

  // Balance Sheet Data Structuring with Auto-Reclassification
  const heads = useMemo(() => {
    const data: Record<AccountClassification, { total: number, items: { id: string, name: string, value: number, source: string, originalAccount?: any }[] }> = {
      'Current Asset': { total: 0, items: [] },
      'Non-Current Asset': { total: 0, items: [] },
      'Current Liability': { total: 0, items: [] },
      'Non-Current Liability': { total: 0, items: [] },
      'Equity': { total: 0, items: [] }
    };

    const processAccount = (id: string, name: string, balance: number, classification: AccountClassification, source: string, originalAccount: any) => {
      let cls = classification;
      let val = balance;
      const isAssetType = cls === 'Current Asset' || cls === 'Non-Current Asset';
      const isLiabilityType = cls === 'Current Liability' || cls === 'Non-Current Liability';

      if (val < 0 && isAssetType) {
        cls = 'Current Liability';
        val = Math.abs(val);
      } else if (val < 0 && isLiabilityType) {
        cls = 'Current Asset';
        val = Math.abs(val);
      }

      data[cls].total += val;
      data[cls].items.push({ id, name, value: val, source, originalAccount });
    };

    filteredState.banks.forEach(b => processAccount(b.id, b.name, b.balance, b.classification || 'Current Asset', 'Bank', b));
    filteredState.wallets.forEach(w => processAccount(w.id, w.name, w.balance, w.classification || 'Current Asset', 'Wallet', w));
    filteredState.cards.forEach(c => processAccount(c.id, c.lenderName, c.balance, c.classification || 'Current Liability', 'Credit', c));
    filteredState.assets.forEach(a => processAccount(a.id, a.name, a.value, a.classification || (a.type === 'Receivable' ? 'Current Asset' : 'Non-Current Asset'), 'Manual Asset', a));
    filteredState.liabilities.forEach(l => processAccount(l.id, l.name, l.amount, l.classification || (l.type === 'Payable' ? 'Current Liability' : 'Non-Current Liability'), 'Manual Debt', l));

    data['Equity'].total = capitalDisplay + retainedEarnings;
    data['Equity'].items.push({ id: 'owner_cap', name: 'Owner Capital', value: capitalDisplay, source: 'Equity' });
    data['Equity'].items.push({ id: 'retained_earning', name: 'Retained Earnings', value: retainedEarnings, source: 'Equity' });

    return data;
  }, [filteredState, capitalDisplay, retainedEarnings]);

  const toggleHead = (head: string) => {
    setExpandedHeads(prev => prev.includes(head) ? prev.filter(h => h !== head) : [...prev, head]);
  };

  const totalAssetsValue = heads['Current Asset'].total + heads['Non-Current Asset'].total;
  const totalLiabilitiesAndEquityValue = heads['Current Liability'].total + heads['Non-Current Liability'].total + heads['Equity'].total;
  const liquidityRatio = heads['Current Liability'].total > 0 ? (heads['Current Asset'].total / heads['Current Liability'].total).toFixed(2) : '∞';

  const assetHeader = isMeView ? "Total Assets" : (isConsolidatedView ? "Consolidated Assets" : "Assigned Assets");
  const liabilityHeader = isMeView ? "Total Equity and Liabilities" : (isConsolidatedView ? "Consolidated Equity and Liabilities" : "Total Claims & Equity");

  return (
