  amount: number;
  nature: string; 
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet' | 'liability';
  date: string;
  category?: string;
  isShared?: boolean;
  sharedAmount?: number;
  numberOfPeople?: number;
  includeSelf?: boolean;
  sharedContacts?: SharedContact[];
  ownerId?: string; 
  isin?: string;
  stockName?: string;
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
  notifications: Notification[];
  transactionNatures: string[]; 
  capital: number; 
}

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Transaction, CreditCard, AccountClassification, CreditCardOtherBenefit } from '../types';

const CLASSIFICATIONS: AccountClassification[] = [
  'Current Asset',
  'Non-Current Asset',
  'Current Liability',
  'Non-Current Liability',
  'Equity'
];

const Accounts: React.FC = () => {
  const { filteredState, state, deleteBank, deleteCard, deleteWallet, addTransactionNature, deleteTransactionNature } = useFinance();
  const [showModal, setShowModal] = useState<'bank' | 'card' | 'wallet' | null>(null);
  const [editingAccount, setEditingAccount] = useState<any>(null);
  const [viewingHistory, setViewingHistory] = useState<any>(null);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string, type: 'bank' | 'card' | 'wallet', name: string } | null>(null);
  const [newNature, setNewNature] = useState('');

  const currency = filteredState.profile.currency;

  const getOwnerName = (ownerId?: string) => {
    if (!ownerId) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === ownerId);
    return member ? member.name : 'Individual';
  };

  const handleEdit = (type: 'bank' | 'card' | 'wallet', account: any) => {
    setEditingAccount(account);
    setShowModal(type);
  };

  const handleDelete = (type: 'bank' | 'card' | 'wallet', id: string, name: string) => {
    setConfirmDelete({ id, type, name });
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'bank') deleteBank(confirmDelete.id);
    else if (confirmDelete.type === 'card') deleteCard(confirmDelete.id);
    else if (confirmDelete.type === 'wallet') deleteWallet(confirmDelete.id);
    setConfirmDelete(null);
  };

  const handleAddNature = (e: React.FormEvent) => {
    e.preventDefault();
    if (newNature.trim()) {
      addTransactionNature(newNature.trim());
      setNewNature('');
    }
  };

  return (
    <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500 pb-20">
