            const isReceivable = card.balance < 0;
            return (
              <div key={card.id} className={`relative overflow-hidden bg-gradient-to-br ${isReceivable ? 'from-emerald-600 to-emerald-800' : 'from-indigo-600 to-indigo-800'} p-6 md:p-8 rounded-3xl text-white shadow-xl group flex flex-col justify-between min-h-[280px] md:min-h-[320px]`}>
                <span className="absolute top-6 right-6 text-[8px] font-bold uppercase text-white/40 tracking-widest">{getOwnerName(card.ownerId)}</span>
                <div className="relative z-10">
                  <div className="flex justify-between items-start mb-6 md:mb-8">
                    <div>
                      <div className="flex flex-col mb-1">
                        <p className={`text-[8px] md:text-[10px] ${isReceivable ? 'text-emerald-200' : 'text-indigo-200'} font-bold uppercase tracking-widest`}>
                          {isReceivable ? 'Receivable' : 'Outstanding'}
                        </p>
                        <span className="text-[7px] font-black uppercase bg-black/20 px-1.5 py-0.5 rounded w-fit mt-1">{card.classification || 'Current Liability'}</span>
                      </div>
                      <p className="text-2xl md:text-3xl font-black tracking-tight">{formatCurrency(Math.abs(card.balance), currency)}</p>
                    </div>
                    <div className="text-right">
                      <p className="text-xs font-bold border-b border-white/20 pb-1 mb-2">{card.lenderName}</p>
                      <div className="flex gap-2 justify-end">
                        <span title="Movie Offers" className={`p-1 rounded text-xs ${(card.offers.movie || card.movieOffers?.onePlusOne) ? 'bg-white/20' : 'opacity-20'}`}>🎬</span>
                        <span title="Lounge Access" className={`p-1 rounded text-xs ${(card.offers.lounge || (card.loungeAccess?.count ?? 0) > 0) ? 'bg-white/20' : 'opacity-20'}`}>🛋️</span>
                        <span title="Dining Benefits" className={`p-1 rounded text-xs ${card.offers.dining ? 'bg-white/20' : 'opacity-20'}`}>🍽️</span>
                      </div>
                    </div>
                  </div>
                </div>
                <div className={`relative z-10 flex justify-between items-end border-t border-white/10 pt-4 md:pt-6`}>
                  <p className={`text-xs font-mono tracking-widest ${isReceivable ? 'text-emerald-100' : 'text-indigo-100'}`}>•••• {card.last4}</p>
                  <div className="flex gap-3">
                    <button onClick={() => handleEdit('card', card)} className={`text-[9px] font-bold uppercase ${isReceivable ? 'text-emerald-200' : 'text-indigo-200'} hover:text-white`}>Edit</button>
                    <button onClick={() => setViewingHistory(card)} className={`text-[9px] font-bold uppercase ${isReceivable ? 'text-emerald-200' : 'text-indigo-200'} hover:text-white`}>History</button>
                    <button onClick={() => handleDelete('card', card.id, card.lenderName)} className="text-[9px] font-bold uppercase text-rose-300 hover:text-rose-500">Del</button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </section>

      {/* Nature of Transaction Management Section */}
      <section className="bg-white p-6 md:p-10 rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <h3 className="text-base md:text-lg font-bold text-slate-800 tracking-tight mb-6 uppercase">Audit Protocol Categories</h3>
        <form onSubmit={handleAddNature} className="flex gap-2 mb-8">
          <input 
            placeholder="New classification..." 
            className="flex-1 p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500/20 font-bold text-xs"
            value={newNature}
            onChange={e => setNewNature(e.target.value)}
          />
          <button type="submit" className="px-4 py-3 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest">Add</button>
        </form>
        <div className="flex flex-wrap gap-2">
          {(state.transactionNatures || []).map(nature => (
            <div key={nature} className="flex items-center gap-2 bg-slate-50 border border-slate-200 px-3 py-1.5 rounded-lg group">
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-tight">{nature}</span>
              <button 
                onClick={() => deleteTransactionNature(nature)}
                className="text-slate-300 hover:text-rose-500 font-bold text-xs"
              >✕</button>
            </div>
          ))}
        </div>
      </section>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-2xl rounded-[2rem] border border-slate-200 shadow-2xl animate-in zoom-in duration-200 max-h-[90vh] flex flex-col overflow-hidden">
            <div className="p-6 md:p-8 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-base md:text-lg font-black text-slate-800 uppercase tracking-tighter">Configure {showModal}</h3>
              <button onClick={onCancel} className="text-slate-300 hover:text-slate-800 text-xl font-black">✕</button>
            </div>
            <div className="flex-1 overflow-y-auto p-6 md:p-8 custom-scrollbar">
              <AccountForm type={showModal} account={editingAccount} onCancel={() => { setShowModal(null); setEditingAccount(null); }} />
            </div>
          </div>
        </div>
      )}
      {viewingHistory && <TransactionHistoryModal account={viewingHistory} currency={currency} onClose={() => setViewingHistory(null)} />}
      {confirmDelete && <DeleteConfirmationModal accountName={confirmDelete.name} onCancel={() => setConfirmDelete(null)} onConfirm={executeDelete} />}
    </div>
  );
};

const DeleteConfirmationModal: React.FC<{ accountName: string, onCancel: () => void, onConfirm: () => void }> = ({ accountName, onCancel, onConfirm }) => {
  const [step, setStep] = useState(1);
  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
       <div className={`w-full max-w-sm p-6 md:p-8 rounded-3xl border transition-all duration-300 ${step === 2 ? 'bg-rose-50 border-rose-200' : 'bg-white border-slate-200'} shadow-2xl animate-in zoom-in duration-200`}>
          <div className="text-center mb-6">
             <div className={`w-12 h-12 rounded-full flex items-center justify-center text-xl mx-auto mb-4 ${step === 2 ? 'bg-rose-200 text-rose-600' : 'bg-slate-100 text-slate-400'}`}>⚠️</div>
             <h4 className={`text-lg font-black tracking-tight ${step === 2 ? 'text-rose-800' : 'text-slate-800'}`}>{step === 1 ? `Delete?` : 'Are you sure?'}</h4>
             <p className="text-xs font-medium text-slate-500 mt-2">{accountName}</p>
          </div>
          <div className="flex flex-col gap-2">
             {step === 1 ? (
               <>
                 <button onClick={() => setStep(2)} className="w-full py-4 bg-rose-500 text-white font-bold text-[10px] uppercase rounded-2xl">Proceed</button>
                 <button onClick={onCancel} className="w-full py-3 bg-slate-100 text-slate-600 font-bold text-[10px] uppercase rounded-2xl">Cancel</button>
               </>
             ) : (
               <>
                 <button onClick={onConfirm} className="w-full py-4 bg-rose-600 text-white font-bold text-[10px] uppercase rounded-2xl">Delete Forever</button>
                 <button onClick={onCancel} className="text-slate-500 font-bold text-[10px] uppercase">Abort</button>
               </>
             )}
          </div>
       </div>
    </div>
  );
};

const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, addTransactionNature, state } = useFinance();
  const [showNewNatureInput, setShowNewNatureInput] = useState(false);
  const [tempNature, setTempNature] = useState('');

  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: Math.abs(account.balance),
    balanceType: (account.balance < 0 && type === 'card') ? 'receivable' : 'outstanding',
    classification: account.classification || (type === 'card' ? 'Current Liability' : 'Current Asset'),
    last4: account.last4 || '',
    limit: account.limit || '',
    annualLimit: account.annualLimit || '',
    anniversaryDate: account.anniversaryDate || '',
    billingDay: account.billingDay || 1,
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    // NEW CARD FIELDS
    cashbackPct: account.cashbackPct || '',
    movieOffers: account.movieOffers || { onePlusOne: false, amountBased: '' },
    loungeAccess: account.loungeAccess || { count: '', spendLimit: '', period: 'Monthly' },
    fuelSurchargeWaiver: account.fuelSurchargeWaiver || false,
    forexMarkup: account.forexMarkup || '',
    pointsConversion: account.pointsConversion || '',
    otherBenefits: account.otherBenefits || [] as CreditCardOtherBenefit[],
    // OTHER
    accountType: account.accountType || 'Savings',
    customAccountType: account.customAccountType || ''
  } : {
    ownerId: '',
    name: '',
    balance: '',
    balanceType: 'outstanding',
    classification: type === 'card' ? 'Current Liability' : 'Current Asset',
    accNum: '',
    accountType: 'Savings',
    customAccountType: '',
    annualLimit: '',
    anniversaryDate: '',
    billingDay: 1,
    offers: { movie: false, dining: false, concierge: false, lounge: false },
    cashbackPct: '',
    movieOffers: { onePlusOne: false, amountBased: '' },
    loungeAccess: { count: '', spendLimit: '', period: 'Monthly' },
    fuelSurchargeWaiver: false,
    forexMarkup: '',
    pointsConversion: '',
    otherBenefits: []
  });

  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];

  const addOtherBenefit = () => {
    setFormData({
      ...formData,
      otherBenefits: [...formData.otherBenefits, { condition: '', benefitName: '', linkedNatures: [] }]
    });
  };

  const removeOtherBenefit = (index: number) => {
    setFormData({
      ...formData,
      otherBenefits: formData.otherBenefits.filter((_: any, i: number) => i !== index)
    });
  };

  const updateOtherBenefit = (index: number, field: string, value: any) => {
    const next = [...formData.otherBenefits];
    next[index] = { ...next[index], [field]: value };
    setFormData({ ...formData, otherBenefits: next });
  };

  const handleInlineNatureAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (tempNature.trim()) {
      addTransactionNature(tempNature.trim());
      setTempNature('');
      setShowNewNatureInput(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId, classification: formData.classification };
    if (type === 'bank') {
      const bankData = { ...commonProps, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance), accountType: formData.accountType, customAccountType: formData.accountType === 'Others' ? formData.customAccountType : undefined };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const finalBalance = formData.balanceType === 'receivable' ? -Math.abs(Number(formData.balance)) : Math.abs(Number(formData.balance));
      const cardData = { 
        ...commonProps, 
        lenderName: formData.name, 
        balance: finalBalance, 
        last4: formData.last4, 
        limit: formData.limit ? Number(formData.limit) : undefined, 
        annualLimit: formData.annualLimit ? Number(formData.annualLimit) : undefined, 
        anniversaryDate: formData.anniversaryDate, 
        billingDay: Number(formData.billingDay), 
        offers: formData.offers,
        cashbackPct: formData.cashbackPct ? Number(formData.cashbackPct) : undefined,
        movieOffers: {
          onePlusOne: formData.movieOffers.onePlusOne,
          amountBased: formData.movieOffers.amountBased ? Number(formData.movieOffers.amountBased) : 0
        },
        loungeAccess: {
          count: formData.loungeAccess.count ? Number(formData.loungeAccess.count) : 0,
          spendLimit: formData.loungeAccess.spendLimit ? Number(formData.loungeAccess.spendLimit) : 0,
          period: formData.loungeAccess.period
        },
        fuelSurchargeWaiver: formData.fuelSurchargeWaiver,
        forexMarkup: formData.forexMarkup ? Number(formData.forexMarkup) : undefined,
        pointsConversion: formData.pointsConversion,
        otherBenefits: formData.otherBenefits
      };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      {/* Basic Info Section */}
      <div className="space-y-4">
        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest border-b border-slate-100 pb-2">Identification Protocols</h4>
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Entity Owner</label>
              <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}><option value="">Me</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}</select>
          </div>
          <div className="space-y-1">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Classification</label>
              <select required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.classification} onChange={e => setFormData({...formData, classification: e.target.value as AccountClassification})}>
                  {CLASSIFICATIONS.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1"><label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">{type === 'card' ? 'Lender / Card Name' : 'Account Identifier'}</label><input required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} /></div>
          <div className="space-y-1"><label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Opening Flow Balance</label><input required type="number" step="any" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-black text-sm" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} /></div>
        </div>
        {type === 'card' && (
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1"><label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Last 4 Digits</label><input maxLength={4} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.last4} onChange={e => setFormData({...formData, last4: e.target.value})} /></div>
            <div className="space-y-1">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Balance Logic</label>
              <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.balanceType} onChange={e => setFormData({...formData, balanceType: e.target.value})}>
                <option value="outstanding">Outstanding (Debt)</option>
                <option value="receivable">Receivable (Credit)</option>
              </select>
            </div>
          </div>
        )}
      </div>

      {/* Linked Benefits Section (Only for Cards) */}
      {type === 'card' && (
        <div className="space-y-6">
          <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest border-b border-slate-100 pb-2">Integrated Perks</h4>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Cashback & Forex */}
            <div className="space-y-4 p-4 bg-slate-50/50 rounded-2xl border border-slate-100">
               <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">Standard Cashback %</label>
                  <input type="number" step="0.01" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.cashbackPct} onChange={e => setFormData({...formData, cashbackPct: e.target.value})} />
               </div>
               <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">Forex Markup %</label>
                  <input type="number" step="0.01" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.forexMarkup} onChange={e => setFormData({...formData, forexMarkup: e.target.value})} />
               </div>
            </div>

            {/* Movie Offers */}
            <div className="space-y-4 p-4 bg-slate-50/50 rounded-2xl border border-slate-100">
               <div className="flex items-center justify-between mb-2">
                  <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Movie Perks</label>
                  <div className="flex items-center gap-2">
                    <span className="text-[8px] font-bold text-slate-400 uppercase">1+1 Offer</span>
                    <input type="checkbox" className="w-4 h-4 accent-indigo-600" checked={formData.movieOffers.onePlusOne} onChange={e => setFormData({...formData, movieOffers: {...formData.movieOffers, onePlusOne: e.target.checked}})} />
                  </div>
               </div>
               <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">Amount Cap (INR)</label>
                  <input type="number" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.movieOffers.amountBased} onChange={e => setFormData({...formData, movieOffers: {...formData.movieOffers, amountBased: e.target.value}})} />
               </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Lounge Access */}
            <div className="space-y-4 p-4 bg-slate-50/50 rounded-2xl border border-slate-100">
               <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block mb-1">Lounge Access Protocol</label>
               <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-1">
                    <span className="text-[8px] font-bold text-slate-400 uppercase">Visits Count</span>
                    <input type="number" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.loungeAccess.count} onChange={e => setFormData({...formData, loungeAccess: {...formData.loungeAccess, count: e.target.value}})} />
                  </div>
                  <div className="space-y-1">
                    <span className="text-[8px] font-bold text-slate-400 uppercase">Period</span>
                    <select className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-[10px] font-bold" value={formData.loungeAccess.period} onChange={e => setFormData({...formData, loungeAccess: {...formData.loungeAccess, period: e.target.value}})}>
                      <option>Monthly</option><option>Quarterly</option><option>Yearly</option>
                    </select>
                  </div>
               </div>
               <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">Required Spend (Threshold)</label>
                  <input type="number" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.loungeAccess.spendLimit} onChange={e => setFormData({...formData, loungeAccess: {...formData.loungeAccess, spendLimit: e.target.value}})} />
               </div>
            </div>

            {/* Miscellaneous */}
            <div className="space-y-4 p-4 bg-slate-50/50 rounded-2xl border border-slate-100">
               <div className="flex items-center justify-between mb-4">
                  <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Fuel Surcharge Waiver</label>
                  <input type="checkbox" className="w-4 h-4 accent-indigo-600" checked={formData.fuelSurchargeWaiver} onChange={e => setFormData({...formData, fuelSurchargeWaiver: e.target.checked})} />
               </div>
               <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">Points Conversion Ratio</label>
                  <input placeholder="e.g. 1 Point = 0.25 INR" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.pointsConversion} onChange={e => setFormData({...formData, pointsConversion: e.target.value})} />
               </div>
            </div>
          </div>

          {/* OTHER BENEFITS BUILDER */}
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h5 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Additional Conditions</h5>
              <button type="button" onClick={addOtherBenefit} className="text-[8px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-lg uppercase tracking-widest hover:bg-indigo-100 transition-colors">+ New Rule</button>
            </div>

            <div className="space-y-3">
              {formData.otherBenefits.map((benefit: CreditCardOtherBenefit, index: number) => (
                <div key={index} className="p-4 bg-white border border-slate-100 rounded-2xl shadow-sm space-y-4 animate-in slide-in-from-top-2">
                   <div className="flex justify-between items-start">
                      <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-3">
                        <div className="space-y-1">
                          <label className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Threshold / Condition</label>
                          <input placeholder="e.g. Spend > 50k" className="w-full p-2.5 bg-slate-50 border border-slate-100 rounded-lg text-xs font-bold outline-none" value={benefit.condition} onChange={e => updateOtherBenefit(index, 'condition', e.target.value)} />
                        </div>
                        <div className="space-y-1">
                          <label className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Benefit Outcome</label>
                          <input placeholder="e.g. 2,000 Voucher" className="w-full p-2.5 bg-slate-50 border border-slate-100 rounded-lg text-xs font-bold outline-none" value={benefit.benefitName} onChange={e => updateOtherBenefit(index, 'benefitName', e.target.value)} />
                        </div>
                      </div>
                      <button onClick={() => removeOtherBenefit(index)} className="ml-4 p-2 text-rose-300 hover:text-rose-500 text-lg">✕</button>
                   </div>

                   <div className="space-y-2">
                      <div className="flex justify-between items-center">
                        <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Linked Protocol Natures</label>
                        <button type="button" onClick={() => setShowNewNatureInput(true)} className="text-[7px] font-black text-indigo-400 uppercase hover:text-indigo-600">Add New Category</button>
                      </div>

                      {showNewNatureInput && (
                        <div className="flex gap-2 animate-in fade-in slide-in-from-left-2">
                          <input autoFocus placeholder="New nature name..." className="flex-1 p-2 bg-indigo-50/50 border border-indigo-100 rounded-lg text-[10px] font-bold outline-none" value={tempNature} onChange={e => setTempNature(e.target.value)} />
                          <button type="button" onClick={handleInlineNatureAdd} className="px-3 bg-indigo-600 text-white rounded-lg text-[9px] font-bold uppercase">Save</button>
                          <button type="button" onClick={() => setShowNewNatureInput(false)} className="px-2 text-slate-400 text-lg">✕</button>
                        </div>
                      )}

                      <div className="flex flex-wrap gap-2">
                        {natures.map(n => {
                          const isSelected = benefit.linkedNatures.includes(n);
                          return (
                            <button
                              key={n}
                              type="button"
                              onClick={() => {
                                const next = isSelected 
                                  ? benefit.linkedNatures.filter(x => x !== n) 
                                  : [...benefit.linkedNatures, n];
                                updateOtherBenefit(index, 'linkedNatures', next);
                              }}
                              className={`px-3 py-1.5 rounded-full text-[8px] font-black uppercase tracking-tight transition-all border ${
                                isSelected 
                                  ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                                  : 'bg-slate-50 border-slate-200 text-slate-500 hover:bg-slate-100'
                              }`}
                            >
                              {n}
                            </button>
                          );
                        })}
                      </div>
                   </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <div className="flex gap-3 pt-6 sticky bottom-0 bg-white pb-2">
        <button type="button" onClick={onCancel} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 rounded-2xl font-bold text-[10px] uppercase tracking-widest active:scale-95 transition-all">Cancel</button>
        <button type="submit" className="flex-[2] px-4 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-[0.1em] shadow-xl shadow-indigo-100 active:scale-95 transition-all">Commit Configuration</button>
      </div>
    </form>
  );
};

const TransactionHistoryModal: React.FC<{ account: any, currency: string, onClose: () => void }> = ({ account, currency, onClose }) => {
  const { filteredState } = useFinance();
  const tenDaysAgo = new Date(); tenDaysAgo.setDate(tenDaysAgo.getDate() - 30); // Default to 30 days
  const [dateFrom, setDateFrom] = useState(tenDaysAgo.toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);

  const history = useMemo(() => {
    return (filteredState.transactions || [])
      .filter(t => t.accountId === account.id && t.date >= dateFrom && t.date <= dateTo)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredState.transactions, account.id, dateFrom, dateTo]);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
      <div className="bg-white w-full max-w-2xl rounded-[2rem] p-6 md:p-10 shadow-2xl max-h-[85vh] flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">
        <div className="flex justify-between items-start mb-6 border-b border-slate-100 pb-4">
          <div>
            <h3 className="text-base md:text-lg font-black text-slate-800 uppercase tracking-tight">{account.name || account.lenderName}</h3>
            <p className="text-[9px] font-black text-indigo-500 uppercase mt-1 tracking-widest">Transaction Audit Trail</p>
          </div>
          <button onClick={onClose} className="p-2 text-slate-300 hover:text-slate-600 text-xl font-black">✕</button>
        </div>

        <div className="flex gap-3 mb-6 bg-slate-50 p-3 rounded-2xl border border-slate-100">
          <div className="flex-1">
            <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest block mb-1 ml-1">From</label>
            <input type="date" className="w-full p-2.5 bg-white border border-slate-200 rounded-xl text-[10px] font-bold outline-none" value={dateFrom} onChange={e => setDateFrom(e.target.value)} />
          </div>
          <div className="flex-1">
            <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest block mb-1 ml-1">To</label>
            <input type="date" className="w-full p-2.5 bg-white border border-slate-200 rounded-xl text-[10px] font-bold outline-none" value={dateTo} onChange={e => setDateTo(e.target.value)} />
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3 px-1">
          {history.map(t => {
            const totalCashFlow = t.amount + (t.sharedAmount || 0);
            return (
              <div key={t.id} className="p-4 bg-white border border-slate-100 rounded-2xl flex items-center justify-between hover:border-indigo-100 transition-colors shadow-sm">
                <div className="flex items-center gap-4">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xs font-bold ${t.type === 'Income' || t.type === 'Liability' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-500'}`}>
                    {t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'}
                  </div>
                  <div>
                    <p className="text-xs font-black text-slate-800 uppercase tracking-tight line-clamp-1">{t.description || t.nature}</p>
                    <p className="text-[9px] text-slate-400 font-bold uppercase mt-0.5">{t.date} • {t.nature}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className={`text-xs font-black ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-slate-800'}`}>
                    {formatCurrency(totalCashFlow, currency)}
                  </p>
                </div>
              </div>
            );
          })}
          {history.length === 0 && (
            <div className="py-24 text-center">
              <div className="text-4xl mb-4 grayscale opacity-20">📂</div>
              <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] italic">No transaction records found</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

