                    <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">ISIN Protocol Key</label>
                    <input 
                      className="w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs uppercase tracking-widest focus:ring-4 focus:ring-indigo-500/10 transition-all" 
                      placeholder="e.g. INE002A01018"
                      maxLength={12}
                      value={formData.isin} 
                      onChange={e => setFormData({ ...formData, isin: e.target.value.toUpperCase() })} 
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Official Security Name</label>
                    <div className="relative">
                      <input 
                        className={`w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs focus:ring-4 focus:ring-indigo-500/10 transition-all ${isIsinResolving ? 'animate-pulse text-indigo-300' : ''}`} 
                        placeholder={isIsinResolving ? "Querying AI Vault..." : "Identifying..."}
                        value={formData.stockName} 
                        onChange={e => setFormData({ ...formData, stockName: e.target.value })} 
                      />
                      {isIsinResolving && <span className="absolute right-4 top-1/2 -translate-y-1/2 animate-spin text-indigo-500 text-lg">⚙️</span>}
                    </div>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Reporting Entity</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value, accountId: '' })}>
                    <option value="">Me (Primary Vault)</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Nature Protocol</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.nature} onChange={e => setFormData({ ...formData, nature: e.target.value })}>
                    <option value="" disabled>Select Protocol</option>
                    {natures.map(n => <option key={n} value={n}>{n.toUpperCase()}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Settlement Amount ({currency})</label>
                  <input required type="number" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-2xl focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Audit Timeline</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase tracking-widest cursor-pointer" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Brief Description</label>
                  <input className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold text-xs" placeholder="Audit notes..." value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Account Instrument</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">Select Target Account</option>
                    {allAccounts.filter(a => (a.ownerId || '') === (formData.ownerId || '')).map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}
                  </select>
                </div>
              </div>

              {/* Annual Billing Period selection for Credit Cards */}
              {selectedAccount?.type === 'card' && (
                <div className="space-y-2 p-6 bg-slate-50 rounded-[2rem] border border-slate-100 animate-in slide-in-from-bottom-2">
                  <label className="text-[9px] font-black text-indigo-500 uppercase tracking-widest block ml-2">Annual Milestone / Billing Period (Optional)</label>
                  <div className="flex gap-4 items-center">
                    <input 
                      placeholder="e.g. Year 1, 2024-25, etc." 
                      className="flex-1 p-4 bg-white border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase tracking-widest"
                      value={formData.billingPeriod}
                      onChange={e => setFormData({ ...formData, billingPeriod: e.target.value })}
                    />
                    <div className="text-[8px] font-black text-slate-400 w-1/3 leading-tight uppercase">Use this to track spend against annual limits and benefits.</div>
                  </div>
                </div>
              )}

              <div className="flex flex-col md:flex-row gap-4 pt-8 sticky bottom-0 bg-white pb-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase tracking-widest rounded-2xl active:scale-95 transition-all">Discard Changes</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-100 active:scale-95 transition-all">Commit to Ledger</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Transaction, CreditCard, AccountClassification, CreditCardOtherBenefit } from '../types';

const CLASSIFICATIONS: AccountClassification[] = [
  'Current Asset',
  'Non-Current Asset',
  'Current Liability',
  'Non-Current Liability',
  'Equity'
];

const Accounts: React.FC = () => {
  const { filteredState, state, deleteBank, deleteCard, deleteWallet, deleteAsset, deleteLiability, addTransactionNature, deleteTransactionNature } = useFinance();
  const [showModal, setShowModal] = useState<'bank' | 'card' | 'wallet' | 'asset' | 'liability' | null>(null);
  const [editingAccount, setEditingAccount] = useState<any>(null);
  const [viewingHistory, setViewingHistory] = useState<any>(null);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string, type: 'bank' | 'card' | 'wallet' | 'asset' | 'liability', name: string } | null>(null);
  const [newNature, setNewNature] = useState('');

  const currency = filteredState.profile.currency;

  const getOwnerName = (ownerId?: string) => {
    if (!ownerId) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === ownerId);
    return member ? member.name : 'Individual';
  };

  const handleEdit = (type: 'bank' | 'card' | 'wallet' | 'asset' | 'liability', account: any) => {
    setEditingAccount(account);
    setShowModal(type);
  };

  const handleDelete = (type: 'bank' | 'card' | 'wallet' | 'asset' | 'liability', id: string, name: string) => {
    setConfirmDelete({ id, type, name });
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'bank') deleteBank(confirmDelete.id);
    else if (confirmDelete.type === 'card') deleteCard(confirmDelete.id);
    else if (confirmDelete.type === 'wallet') deleteWallet(confirmDelete.id);
    else if (confirmDelete.type === 'asset') deleteAsset(confirmDelete.id);
    else if (confirmDelete.type === 'liability') deleteLiability(confirmDelete.id);
    setConfirmDelete(null);
  };

  const handleAddNature = (e: React.FormEvent) => {
    e.preventDefault();
    if (newNature.trim()) {
      addTransactionNature(newNature.trim());
      setNewNature('');
    }
  };

  const calculateAnnualSpend = (card: CreditCard) => {
    if (!card.anniversaryDate) return 0;

    // Calculate current anniversary year range
    const now = new Date();
    const anniv = new Date(card.anniversaryDate);
    let startOfPeriod = new Date(now.getFullYear(), anniv.getMonth(), anniv.getDate());
    if (startOfPeriod > now) {
      startOfPeriod.setFullYear(startOfPeriod.getFullYear() - 1);
    }

    return state.transactions
      .filter(t => t.accountId === card.id && t.type === 'Expense' && new Date(t.date) >= startOfPeriod)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  return (
    <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500 pb-20">
      {/* Depository Section */}
      <section>
        <div className="flex justify-between items-end mb-6 md:mb-8">
          <div className="flex flex-col">
            <h3 className="text-base md:text-lg font-bold text-slate-800 tracking-tight">Depository Accounts</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Savings & Checking</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('bank'); }}
            className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-bold uppercase hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100"
          >
            + Add Bank
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
          {(filteredState.banks || []).map(bank => (
            <div key={bank.id} className="bg-white p-5 md:p-6 rounded-2xl border border-slate-200 relative group transition-all shadow-sm">
              <span className="absolute top-4 right-4 text-[8px] font-bold uppercase text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full">{getOwnerName(bank.ownerId)}</span>
              <div className="flex justify-between items-start mb-6">
                <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center text-xl">🏦</div>
                <div className="text-right">
                  <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mb-1">Balance</p>
                  <p className="text-lg font-black text-slate-800 tracking-tight">{formatCurrency(bank.balance, currency)}</p>
                </div>
              </div>
              <div className="mb-4">
                 <h4 className="text-sm font-bold text-slate-800">{bank.name}</h4>
                 <div className="flex items-center gap-2 mt-1">
                    <p className="text-[10px] font-medium text-indigo-500 uppercase tracking-widest">
                        {bank.accountType === 'Others' ? bank.customAccountType : bank.accountType}
                    </p>
                    <span className="text-[8px] bg-slate-100 text-slate-400 px-1.5 py-0.5 rounded font-black uppercase">{bank.classification || 'Current Asset'}</span>
                 </div>
              </div>
              <p className="text-[10px] font-mono text-slate-400">{bank.accountNumber || '**** **** ****'}</p>
              <div className="flex gap-4 pt-4 border-t border-slate-50 mt-4">
                <button onClick={() => handleEdit('bank', bank)} className="text-[9px] font-bold uppercase text-indigo-600 hover:underline">Edit</button>
                <button onClick={() => setViewingHistory(bank)} className="text-[9px] font-bold uppercase text-slate-400 hover:text-slate-600 transition-colors">History</button>
                <button onClick={() => handleDelete('bank', bank.id, bank.name)} className="text-[9px] font-bold uppercase text-rose-400 hover:text-rose-600 ml-auto">Delete</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Wallets Section */}
      <section>
        <div className="flex justify-between items-end mb-6 md:mb-8">
          <div className="flex flex-col">
            <h3 className="text-base md:text-lg font-bold text-slate-800 tracking-tight">Wallets</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Cash & Digital</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('wallet'); }}
            className="px-4 py-2 bg-emerald-600 text-white rounded-xl text-[10px] font-bold uppercase hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100"
          >
            + Add Wallet
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
          {(filteredState.wallets || []).map(wallet => (
            <div key={wallet.id} className="bg-white p-5 md:p-6 rounded-2xl border border-slate-200 relative group transition-all shadow-sm">
              <span className="absolute top-4 right-4 text-[8px] font-bold uppercase text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full">{getOwnerName(wallet.ownerId)}</span>
              <div className="flex justify-between items-start mb-6">
                <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center text-xl">👛</div>
                <div className="text-right">
                  <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mb-1">Balance</p>
                  <p className="text-lg font-black text-slate-800 tracking-tight">{formatCurrency(wallet.balance, currency)}</p>
