                <div className="text-right">
                  <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mb-1">Amount</p>
                  <p className="text-lg font-black text-rose-600 tracking-tight">{formatCurrency(liab.amount, currency)}</p>
                </div>
              </div>
              <div className="mb-4">
                 <h4 className="text-sm font-bold text-slate-800">{liab.name}</h4>
                 <div className="flex items-center gap-2 mt-1">
                    <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">{liab.type || 'Debt'}</p>
                    <span className="text-[8px] bg-slate-100 text-slate-400 px-1.5 py-0.5 rounded font-black uppercase">{liab.classification || 'Current Liability'}</span>
                 </div>
              </div>
              <div className="flex gap-4 pt-4 border-t border-slate-50 mt-4">
                <button onClick={() => handleEdit('liability', liab)} className="text-[9px] font-bold uppercase text-slate-600 hover:underline">Edit</button>
                <button onClick={() => setViewingHistory({ ...liab, name: liab.name, id: liab.id })} className="text-[9px] font-bold uppercase text-slate-400 hover:text-slate-600 transition-colors">History</button>
                <button onClick={() => handleDelete('liability', liab.id, liab.name)} className="text-[9px] font-bold uppercase text-rose-400 hover:text-rose-600 ml-auto">Delete</button>
              </div>
            </div>
          ))}
