      {/* Tangible Assets Section */}
      <section>
        <div className="flex justify-between items-end mb-6 md:mb-8">
          <div className="flex flex-col">
            <h3 className="text-base md:text-lg font-bold text-slate-800 tracking-tight">Physical Assets</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Tangible Wealth & Receivables</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('asset'); }}
            className="px-4 py-2 bg-amber-600 text-white rounded-xl text-[10px] font-bold uppercase hover:bg-amber-700 transition-all shadow-md shadow-amber-100"
          >
            + Add Asset
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
          {(filteredState.assets || []).map(asset => (
            <div key={asset.id} className="bg-white p-5 md:p-6 rounded-2xl border border-slate-200 relative group transition-all shadow-sm">
              <span className="absolute top-4 right-4 text-[8px] font-bold uppercase text-amber-600 bg-amber-50 px-2 py-0.5 rounded-full">{getOwnerName(asset.ownerId)}</span>
              <div className="flex justify-between items-start mb-6">
