                         </p>
                      </div>
                      <div className="w-full h-1.5 bg-white/10 rounded-full overflow-hidden">
                        <div className="h-full bg-emerald-400 shadow-[0_0_10px_rgba(52,211,153,0.5)] transition-all duration-1000" style={{ width: `${card.annualLimit ? spendProgress : 100}%` }}></div>
                      </div>
                      {!card.annualLimit && (
                         <p className="text-[7px] font-black text-white/40 uppercase mt-2">No milestone limit set</p>
