                 <h4 className="text-sm font-bold text-slate-800">{asset.name}</h4>
                 <div className="flex items-center gap-2 mt-1">
                    <p className="text-[9px] font-bold text-amber-500 uppercase tracking-widest">{asset.type || 'Physical'}</p>
                    <span className="text-[8px] bg-slate-100 text-slate-400 px-1.5 py-0.5 rounded font-black uppercase">{asset.classification || 'Non-Current Asset'}</span>
