              <div className="flex gap-4 pt-4 border-t border-slate-50 mt-4">
                <button onClick={() => handleEdit('asset', asset)} className="text-[9px] font-bold uppercase text-amber-600 hover:underline">Edit</button>
                <button onClick={() => setViewingHistory({ ...asset, name: asset.name, id: asset.id })} className="text-[9px] font-bold uppercase text-slate-400 hover:text-slate-600 transition-colors">History</button>
                <button onClick={() => handleDelete('asset', asset.id, asset.name)} className="text-[9px] font-bold uppercase text-rose-400 hover:text-rose-600 ml-auto">Delete</button>
              </div>
            </div>
          ))}
