                <input type="number" placeholder="Milestone Target" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.annualLimit} onChange={e => setFormData({...formData, annualLimit: e.target.value})} />
