                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${
                  isSyncing 
                    ? 'bg-slate-100 text-slate-400' 
                    : 'bg-indigo-600 text-white shadow-md active:scale-95'
