import React, { useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { getAnnualPeriodStart, getAnnualPeriodEnd } from '../utils/calculations';
import { CreditCard } from '../types';

const Rewards: React.FC = () => {
  const { filteredState, state } = useFinance();
  const currency = filteredState.profile.currency;
  const cards = filteredState.cards || [];

  const getMonthSpend = (cardId: string) => {
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    return state.transactions
      .filter(t => t.accountId === cardId && t.type === 'Expense' && new Date(t.date) >= startOfMonth)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const getQuarterSpend = (cardId: string) => {
    const now = new Date();
    const quarterStartMonth = Math.floor(now.getMonth() / 3) * 3;
    const startOfQuarter = new Date(now.getFullYear(), quarterStartMonth, 1);
    return state.transactions
      .filter(t => t.accountId === cardId && t.type === 'Expense' && new Date(t.date) >= startOfQuarter)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const calculateAnnualProgress = (card: CreditCard) => {
    if (!card.anniversaryDate) return { spend: 0, startDate: null, endDate: null };
    const start = getAnnualPeriodStart(card.anniversaryDate);
    const end = getAnnualPeriodEnd(start);
    const spend = state.transactions
      .filter(t => t.accountId === card.id && t.type === 'Expense' && new Date(t.date) >= start && new Date(t.date) <= end)
      .reduce((acc, t) => acc + t.amount, 0);
    return { spend, start, end };
  };

  return (
    <div className="space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-2xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Privilege Vault</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mt-2">Active Credit Benefit Applicability</p>
        </div>
        <div className="bg-indigo-600 px-4 py-2 rounded-2xl text-white">
          <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Report Month</p>
          <p className="text-xs font-black uppercase">{new Date().toLocaleString('default', { month: 'long', year: 'numeric' })}</p>
        </div>
      </div>

      {cards.length === 0 ? (
        <div className="py-24 text-center bg-white border border-dashed border-slate-200 rounded-[2.5rem]">
          <div className="text-4xl mb-4">💳</div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">No active credit cards identified in vault</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-8">
          {cards.map(card => {
            const monthSpend = getMonthSpend(card.id);
            const quarterSpend = getQuarterSpend(card.id);
            const annual = calculateAnnualProgress(card);

            // Check Lounge eligibility
            const isLoungeApplicable = card.loungeAccess && card.loungeAccess.count > 0;
            const loungeSpendGoal = card.loungeAccess?.spendLimit || 0;
            const currentLoungeSpend = card.loungeAccess?.period === 'Quarterly' ? quarterSpend : (card.loungeAccess?.period === 'Yearly' ? annual.spend : monthSpend);
            const loungeProgress = loungeSpendGoal > 0 ? Math.min(100, (currentLoungeSpend / loungeSpendGoal) * 100) : 100;
            const isLoungeUnlocked = currentLoungeSpend >= loungeSpendGoal;

            return (
              <div key={card.id} className="bg-white border border-slate-200 rounded-[2.5rem] shadow-sm overflow-hidden flex flex-col lg:flex-row">
                {/* Left Section: Card Branding & Summary */}
                <div className="p-8 lg:w-1/3 bg-slate-900 text-white flex flex-col justify-between">
                  <div>
                    <span className="text-[8px] font-black text-indigo-400 uppercase tracking-widest block mb-2">{card.classification || 'Privilege Credit'}</span>
                    <h3 className="text-xl font-black tracking-tight uppercase leading-none">{card.lenderName}</h3>
                    <p className="text-[10px] font-mono text-white/40 mt-1 tracking-[0.2em]">•••• {card.last4}</p>
                  </div>

                  <div className="mt-12 space-y-6">
                    <div>
                      <p className="text-[8px] font-black text-white/30 uppercase tracking-widest mb-1">Standard Perks</p>
                      <div className="flex flex-wrap gap-2">
                        {card.offers.movie && <span className="bg-white/10 px-2 py-1 rounded text-[9px] font-black uppercase">🎬 Movie 1+1</span>}
                        {card.offers.dining && <span className="bg-white/10 px-2 py-1 rounded text-[9px] font-black uppercase">🍽️ Dining</span>}
                        {card.fuelSurchargeWaiver && <span className="bg-white/10 px-2 py-1 rounded text-[9px] font-black uppercase">⛽ Fuel Waiver</span>}
                        {card.cashbackPct && <span className="bg-indigo-500 px-2 py-1 rounded text-[9px] font-black uppercase">{card.cashbackPct}% Cashback</span>}
                      </div>
                    </div>
                  </div>
                </div>

                {/* Right Section: Applicability Status */}
                <div className="p-8 lg:flex-1 grid grid-cols-1 md:grid-cols-2 gap-8">
                  {/* Lounge Status */}
                  <div className="space-y-4">
                    <div className="flex justify-between items-start">
                      <div>
                        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">🛋️ Lounge Accessibility</h4>
                        <p className="text-[9px] font-bold text-slate-400 mt-0.5">{card.loungeAccess?.count || 0} visits per {card.loungeAccess?.period || 'Cycle'}</p>
                      </div>
                      {isLoungeUnlocked ? (
                        <span className="bg-emerald-100 text-emerald-600 text-[8px] font-black px-2 py-1 rounded-full uppercase">Unlocked</span>
                      ) : (
                        <span className="bg-rose-100 text-rose-500 text-[8px] font-black px-2 py-1 rounded-full uppercase">Goal In Progress</span>
                      )}
                    </div>

                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                      <div className="flex justify-between items-end mb-2">
                        <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{card.loungeAccess?.period || 'Monthly'} Spend Threshold</p>
                        <p className="text-[10px] font-black text-slate-700">{formatCurrency(currentLoungeSpend, currency)} / {formatCurrency(loungeSpendGoal, currency)}</p>
                      </div>
                      <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-1000 ${isLoungeUnlocked ? 'bg-emerald-500' : 'bg-indigo-500'}`}
                          style={{ width: `${loungeProgress}%` }}
                        ></div>
                      </div>
                    </div>
                  </div>

                  {/* Milestone Tracking */}
                  <div className="space-y-4">
                    <div className="flex justify-between items-start">
                      <div>
                        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">🏆 Annual Milestone</h4>
                        <p className="text-[9px] font-bold text-slate-400 mt-0.5">Basis Anniversary Date</p>
                      </div>
                    </div>

                    <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                      <div className="flex justify-between items-end mb-2">
                        <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Cycle Spend</p>
                        <p className="text-[10px] font-black text-slate-700">
                          {formatCurrency(annual.spend, currency)}
                          {card.annualLimit ? ` / ${formatCurrency(card.annualLimit, currency)}` : ''}
                        </p>
                      </div>
                      <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-emerald-500 transition-all duration-1000 shadow-[0_0_10px_rgba(16,185,129,0.3)]"
                          style={{ width: `${card.annualLimit ? Math.min(100, (annual.spend / card.annualLimit) * 100) : 100}%` }}
                        ></div>
                      </div>
                      {card.annualLimit && annual.spend < card.annualLimit && (
                        <p className="text-[8px] font-black text-indigo-500 uppercase mt-2">Spend {formatCurrency(card.annualLimit - annual.spend, currency)} more to hit milestone</p>
                      )}
                    </div>
                  </div>

                  {/* Other Dynamic Benefits */}
                  {(card.otherBenefits || []).length > 0 && (
                    <div className="md:col-span-2 space-y-4 pt-4 border-t border-slate-100">
                      <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">🎯 Custom Targeted Rewards</h4>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                        {card.otherBenefits?.map((benefit, idx) => (
                          <div key={idx} className="flex items-center justify-between p-3.5 bg-indigo-50/30 border border-indigo-100 rounded-2xl group hover:bg-white transition-all">
                             <div>
                                <p className="text-[11px] font-black text-slate-800 uppercase tracking-tight">{benefit.benefitName}</p>
                                <p className="text-[8px] font-bold text-indigo-400 uppercase mt-0.5">Threshold: {benefit.condition}</p>
                             </div>
                             <div className="text-[14px]">💎</div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

