        <div className="bg-indigo-600 px-4 py-2 rounded-2xl text-white">
          <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Benefit Month</p>
          <p className="text-xs font-black uppercase">{new Date().toLocaleString('default', { month: 'long', year: 'numeric' })}</p>
        </div>
      </div>

      {cards.length === 0 ? (
        <div className="py-24 text-center bg-white border border-dashed border-slate-200 rounded-[2.5rem]">
          <div className="text-4xl mb-4">💳</div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">No active credit cards identified in vault</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 gap-8">
          {cards.map(card => {
            const currentMonthSpend = getMonthSpend(card.id);
            const prevMonthSpend = getPreviousMonthSpend(card.id);
            const annual = calculateAnnualProgress(card);

            // Per user request: Benefit for spend-limit met in month M is available in month M+1
            const loungeSpendThreshold = card.loungeAccess?.spendLimit || 0;
            const isLoungeUnlockedForThisMonth = prevMonthSpend >= loungeSpendThreshold;

            // Progress toward NEXT month's benefit
            const nextMonthProgress = loungeSpendThreshold > 0 ? Math.min(100, (currentMonthSpend / loungeSpendThreshold) * 100) : 100;

            return (
