                        {card.fuelSurchargeWaiver && <span className="bg-white/10 px-2 py-1 rounded text-[9px] font-black uppercase">⛽ Fuel Waiver</span>}
                        {card.cashbackPct && <span className="bg-indigo-500 px-2 py-1 rounded text-[9px] font-black uppercase">{card.cashbackPct}% Cashback</span>}
