              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Direct Liabilities Section */}
      <section>
        <div className="flex justify-between items-end mb-6 md:mb-8">
          <div className="flex flex-col">
            <h3 className="text-base md:text-lg font-bold text-slate-800 tracking-tight">Financial Liabilities</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Private Loans & Obligations</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('liability'); }}
            className="px-4 py-2 bg-slate-700 text-white rounded-xl text-[10px] font-bold uppercase hover:bg-slate-800 transition-all shadow-md"
          >
            + Add Debt
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
          {(filteredState.liabilities || []).map(liab => (
            <div key={liab.id} className="bg-white p-5 md:p-6 rounded-2xl border border-slate-200 relative group transition-all shadow-sm">
              <span className="absolute top-4 right-4 text-[8px] font-bold uppercase text-slate-500 bg-slate-100 px-2 py-0.5 rounded-full">{getOwnerName(liab.ownerId)}</span>
              <div className="flex justify-between items-start mb-6">
                <div className="w-10 h-10 bg-slate-50 text-slate-600 rounded-xl flex items-center justify-center text-xl">📉</div>
                <div className="text-right">
                  <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mb-1">Amount</p>
                  <p className="text-lg font-black text-rose-600 tracking-tight">{formatCurrency(liab.amount, currency)}</p>
                </div>
              </div>
              <div className="mb-4">
                 <h4 className="text-sm font-bold text-slate-800">{liab.name}</h4>
                 <div className="flex items-center gap-2 mt-1">
                    <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">{liab.type || 'Debt'}</p>
                    <span className="text-[8px] bg-slate-100 text-slate-400 px-1.5 py-0.5 rounded font-black uppercase">{liab.classification || 'Current Liability'}</span>
                 </div>
              </div>
              <div className="flex gap-4 pt-4 border-t border-slate-50 mt-4">
                <button onClick={() => handleEdit('liability', liab)} className="text-[9px] font-bold uppercase text-slate-600 hover:underline">Edit</button>
                <button onClick={() => setViewingHistory({ ...liab, name: liab.name, id: liab.id })} className="text-[9px] font-bold uppercase text-slate-400 hover:text-slate-600 transition-colors">History</button>
                <button onClick={() => handleDelete('liability', liab.id, liab.name)} className="text-[9px] font-bold uppercase text-rose-400 hover:text-rose-600 ml-auto">Delete</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Nature of Transaction Management Section */}
      <section className="bg-white p-6 md:p-10 rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <h3 className="text-base md:text-lg font-bold text-slate-800 tracking-tight mb-6 uppercase">Audit Protocol Categories</h3>
        <form onSubmit={handleAddNature} className="flex gap-2 mb-8">
          <input 
            placeholder="New classification..." 
            className="flex-1 p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500/20 font-bold text-xs"
            value={newNature}
            onChange={e => setNewNature(e.target.value)}
          />
          <button type="submit" className="px-4 py-3 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest">Add</button>
        </form>
        <div className="flex flex-wrap gap-2">
          {(state.transactionNatures || []).map(nature => (
            <div key={nature} className="flex items-center gap-2 bg-slate-50 border border-slate-200 px-3 py-1.5 rounded-lg group">
              <span className="text-[10px] font-black text-slate-700 uppercase tracking-tight">{nature}</span>
              <button 
                onClick={() => deleteTransactionNature(nature)}
                className="text-slate-300 hover:text-rose-500 font-bold text-xs"
              >✕</button>
            </div>
          ))}
        </div>
      </section>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-2xl rounded-[2rem] border border-slate-200 shadow-2xl animate-in zoom-in duration-200 max-h-[90vh] flex flex-col overflow-hidden">
            <div className="p-6 md:p-8 border-b border-slate-100 flex justify-between items-center">
              <h3 className="text-base md:text-lg font-black text-slate-800 uppercase tracking-tighter">Configure {showModal}</h3>
              <button onClick={() => { setShowModal(null); setEditingAccount(null); }} className="text-slate-300 hover:text-slate-800 text-xl font-black">✕</button>
            </div>
            <div className="flex-1 overflow-y-auto p-6 md:p-8 custom-scrollbar">
              <AccountForm type={showModal} account={editingAccount} onCancel={() => { setShowModal(null); setEditingAccount(null); }} />
            </div>
          </div>
        </div>
      )}
      {viewingHistory && <TransactionHistoryModal account={viewingHistory} currency={currency} onClose={() => setViewingHistory(null)} />}
      {confirmDelete && <DeleteConfirmationModal accountName={confirmDelete.name} onCancel={() => setConfirmDelete(null)} onConfirm={executeDelete} />}
    </div>
  );
};

export const TransactionHistoryModal: React.FC<{ account: any, currency: string, onClose: () => void }> = ({ account, currency, onClose }) => {
  const { filteredState } = useFinance();
  const transactions = (filteredState.transactions || []).filter(t => t.accountId === account.id);

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
      <div className="bg-white w-full max-w-4xl rounded-[2.5rem] border border-slate-200 shadow-2xl animate-in zoom-in duration-200 flex flex-col max-h-[90vh] overflow-hidden">
        <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <div>
            <h3 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Transaction Audit: {account.name || account.lenderName}</h3>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Verified Ledger History</p>
          </div>
          <button onClick={onClose} className="text-slate-300 hover:text-slate-800 text-2xl font-black">✕</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
          {transactions.length > 0 ? (
            <div className="space-y-3">
              {transactions.map(t => (
                <div key={t.id} className="p-5 bg-white border border-slate-100 rounded-2xl flex justify-between items-center hover:shadow-md transition-all">
                  <div>
                    <p className="text-sm font-black text-slate-800 tracking-tight">{t.description || t.nature}</p>
                    <div className="flex items-center gap-2 mt-1">
                      <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.date}</span>
                      <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                      <span className="text-[9px] font-black text-indigo-500 uppercase tracking-widest">{t.nature}</span>
                    </div>
                  </div>
                  <div className={`text-base font-black tracking-tight ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : 'text-rose-500'}`}>
                    {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'} {formatCurrency(t.amount, currency)}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="py-20 text-center text-slate-300 italic text-xs uppercase tracking-widest">No transaction history for this account</div>
          )}
        </div>
      </div>
    </div>
  );
};

const DeleteConfirmationModal: React.FC<{ accountName: string, onCancel: () => void, onConfirm: () => void }> = ({ accountName, onCancel, onConfirm }) => {
  const [step, setStep] = useState(1);
  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
       <div className={`w-full max-w-sm p-6 md:p-8 rounded-3xl border transition-all duration-300 ${step === 2 ? 'bg-rose-50 border-rose-200' : 'bg-white border-slate-200'} shadow-2xl animate-in zoom-in duration-200`}>
          <div className="text-center mb-6">
             <div className={`w-12 h-12 rounded-full flex items-center justify-center text-xl mx-auto mb-4 ${step === 2 ? 'bg-rose-200 text-rose-600' : 'bg-slate-100 text-slate-400'}`}>⚠️</div>
             <h4 className={`text-lg font-black tracking-tight ${step === 2 ? 'text-rose-800' : 'text-slate-800'}`}>{step === 1 ? `Delete?` : 'Are you sure?'}</h4>
             <p className="text-xs font-medium text-slate-500 mt-2">{accountName}</p>
          </div>
          <div className="flex flex-col gap-2">
             {step === 1 ? (
               <>
                 <button onClick={() => setStep(2)} className="w-full py-4 bg-rose-500 text-white font-bold text-[10px] uppercase rounded-2xl">Proceed</button>
                 <button onClick={onCancel} className="w-full py-3 bg-slate-100 text-slate-600 font-bold text-[10px] uppercase rounded-2xl">Cancel</button>
               </>
             ) : (
               <>
                 <button onClick={onConfirm} className="w-full py-4 bg-rose-600 text-white font-bold text-[10px] uppercase rounded-2xl">Delete Forever</button>
                 <button onClick={onCancel} className="text-slate-500 font-bold text-[10px] uppercase">Abort</button>
               </>
             )}
          </div>
       </div>
    </div>
  );
};

const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet' | 'asset' | 'liability', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, addAsset, updateAsset, addLiability, updateLiability, addTransactionNature, state } = useFinance();
  const [showNewNatureInput, setShowNewNatureInput] = useState(false);
  const [tempNature, setTempNature] = useState('');

  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: Math.abs(account.balance || account.value || account.amount || 0),
    balanceType: (account.balance < 0 && type === 'card') ? 'receivable' : 'outstanding',
    classification: account.classification || (type === 'card' || type === 'liability' ? 'Current Liability' : (type === 'asset' ? 'Non-Current Asset' : 'Current Asset')),
    last4: account.last4 || '',
    limit: account.limit || '',
    annualLimit: account.annualLimit || '',
    anniversaryDate: account.anniversaryDate || '',
    billingDay: account.billingDay || 1,
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    cashbackPct: account.cashbackPct || '',
    movieOffers: account.movieOffers || { onePlusOne: false, amountBased: 0 },
    loungeAccess: account.loungeAccess || { count: 0, spendLimit: 0, period: 'Monthly' },
    fuelSurchargeWaiver: account.fuelSurchargeWaiver || false,
    forexMarkup: account.forexMarkup || '',
    pointsConversion: account.pointsConversion || '',
    otherBenefits: account.otherBenefits || [],
    accountType: account.accountType || (type === 'asset' ? 'Physical' : (type === 'liability' ? 'Debt' : 'Savings')),
    customAccountType: account.customAccountType || ''
  } : {
    ownerId: '',
    name: '',
    balance: '',
    balanceType: 'outstanding',
    classification: type === 'card' || type === 'liability' ? 'Current Liability' : (type === 'asset' ? 'Non-Current Asset' : 'Current Asset'),
    accNum: '',
    accountType: type === 'asset' ? 'Physical' : (type === 'liability' ? 'Debt' : 'Savings'),
    customAccountType: '',
    annualLimit: '',
    anniversaryDate: '',
    billingDay: 1,
    offers: { movie: false, dining: false, concierge: false, lounge: false },
    cashbackPct: '',
    movieOffers: { onePlusOne: false, amountBased: 0 },
    loungeAccess: { count: 0, spendLimit: 0, period: 'Monthly' },
    fuelSurchargeWaiver: false,
    forexMarkup: '',
    pointsConversion: '',
    otherBenefits: []
  });

  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];

  const addOtherBenefit = () => {
    setFormData({
      ...formData,
      otherBenefits: [...formData.otherBenefits, { condition: '', benefitName: '', linkedNatures: [] }]
    });
  };

  const removeOtherBenefit = (index: number) => {
    setFormData({
      ...formData,
      otherBenefits: formData.otherBenefits.filter((_: any, i: number) => i !== index)
    });
  };

  const updateOtherBenefit = (index: number, field: string, value: any) => {
    const next = [...formData.otherBenefits];
    next[index] = { ...next[index], [field]: value };
    setFormData({ ...formData, otherBenefits: next });
  };

  const handleInlineNatureAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (tempNature.trim()) {
      addTransactionNature(tempNature.trim());
      setTempNature('');
      setShowNewNatureInput(false);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId, classification: formData.classification };

    if (type === 'bank') {
      const bankData = { ...commonProps, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance), accountType: formData.accountType, customAccountType: formData.accountType === 'Others' ? formData.customAccountType : undefined };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const finalBalance = formData.balanceType === 'receivable' ? -Math.abs(Number(formData.balance)) : Math.abs(Number(formData.balance));
      const cardData = { 
        ...commonProps, 
        lenderName: formData.name, 
        balance: finalBalance, 
        last4: formData.last4, 
        limit: formData.limit ? Number(formData.limit) : undefined, 
        annualLimit: formData.annualLimit ? Number(formData.annualLimit) : undefined, 
        anniversaryDate: formData.anniversaryDate, 
        billingDay: Number(formData.billingDay), 
        offers: formData.offers,
        cashbackPct: formData.cashbackPct ? Number(formData.cashbackPct) : undefined,
        movieOffers: {
          onePlusOne: formData.movieOffers.onePlusOne,
          amountBased: formData.movieOffers.amountBased ? Number(formData.movieOffers.amountBased) : 0
        },
        loungeAccess: {
          count: formData.loungeAccess.count ? Number(formData.loungeAccess.count) : 0,
          spendLimit: formData.loungeAccess.spendLimit ? Number(formData.loungeAccess.spendLimit) : 0,
          period: formData.loungeAccess.period
        },
        fuelSurchargeWaiver: formData.fuelSurchargeWaiver,
        forexMarkup: formData.forexMarkup ? Number(formData.forexMarkup) : undefined,
        pointsConversion: formData.pointsConversion,
        otherBenefits: formData.otherBenefits
      };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    } else if (type === 'asset') {
      const assetData = { ...commonProps, name: formData.name, value: Number(formData.balance), type: formData.accountType };
      account ? updateAsset(assetData) : addAsset(assetData);
    } else if (type === 'liability') {
      const liabilityData = { ...commonProps, name: formData.name, amount: Number(formData.balance), type: formData.accountType };
      account ? updateLiability(liabilityData) : addLiability(liabilityData);
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      {/* Basic Info Section */}
      <div className="space-y-4">
        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest border-b border-slate-100 pb-2">Identification Protocols</h4>
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Entity Owner</label>
              <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}><option value="">Me</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}</select>
          </div>
          <div className="space-y-1">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Classification</label>
              <select required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.classification} onChange={e => setFormData({...formData, classification: e.target.value as AccountClassification})}>
                  {CLASSIFICATIONS.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
          </div>
        </div>
        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1">
            <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">
              {type === 'card' ? 'Lender Name' : (type === 'asset' ? 'Asset Name' : (type === 'liability' ? 'Debt Label' : 'Identifier'))}
            </label>
            <input required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">
              {type === 'asset' ? 'Estimated Value' : (type === 'liability' ? 'Principal Owed' : 'Balance')}
            </label>
            <input required type="number" step="any" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-black text-sm" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} />
          </div>
        </div>

        {(type === 'asset' || type === 'liability') && (
           <div className="space-y-1">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Category</label>
              <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.accountType} onChange={e => setFormData({...formData, accountType: e.target.value})}>
                {type === 'asset' ? (
                  <><option value="Physical">Physical (Property, Gold)</option><option value="Receivable">Receivable (Private Debt to You)</option></>
                ) : (
                  <><option value="Debt">Debt (Mortgage, Private Loan)</option><option value="Payable">Payable (Private Dues)</option></>
                )}
              </select>
           </div>
        )}

        {type === 'card' && (
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1"><label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Last 4 Digits</label><input maxLength={4} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.last4} onChange={e => setFormData({...formData, last4: e.target.value})} /></div>
            <div className="space-y-1">
              <label className="text-[9px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Balance Logic</label>
              <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none font-bold text-xs" value={formData.balanceType} onChange={e => setFormData({...formData, balanceType: e.target.value})}>
                <option value="outstanding">Outstanding (Debt)</option>
                <option value="receivable">Receivable (Credit)</option>
              </select>
            </div>
          </div>
        )}
        {type === 'card' && (
           <div className="grid grid-cols-1 md:grid-cols-3 gap-3 p-4 bg-indigo-50/30 rounded-2xl border border-indigo-100">
              <div className="space-y-1">
                <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-1">Anniversary Date</label>
                <input type="date" className="w-full p-3 bg-white border border-indigo-100 rounded-xl outline-none font-bold text-xs" value={formData.anniversaryDate} onChange={e => setFormData({...formData, anniversaryDate: e.target.value})} />
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-1">Billing Day</label>
                <input type="number" min="1" max="31" className="w-full p-3 bg-white border border-indigo-100 rounded-xl outline-none font-bold text-xs" value={formData.billingDay} onChange={e => setFormData({...formData, billingDay: e.target.value})} />
              </div>
              <div className="space-y-1">
                <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-1">Annual Milestone</label>
                <input type="number" placeholder="Target Spend" className="w-full p-3 bg-white border border-indigo-100 rounded-xl outline-none font-bold text-xs" value={formData.annualLimit} onChange={e => setFormData({...formData, annualLimit: e.target.value})} />
              </div>
           </div>
        )}
      </div>

      {/* Linked Benefits Section (Only for Cards) */}
      {type === 'card' && (
        <div className="space-y-6">
          <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest border-b border-slate-100 pb-2">Integrated Perks</h4>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Cashback & Forex */}
            <div className="space-y-4 p-4 bg-slate-50/50 rounded-2xl border border-slate-100">
               <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">Standard Cashback %</label>
                  <input type="number" step="0.01" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.cashbackPct} onChange={e => setFormData({...formData, cashbackPct: e.target.value})} />
               </div>
               <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">Forex Markup %</label>
                  <input type="number" step="0.01" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.forexMarkup} onChange={e => setFormData({...formData, forexMarkup: e.target.value})} />
               </div>
            </div>

            {/* Movie Offers */}
            <div className="space-y-4 p-4 bg-slate-50/50 rounded-2xl border border-slate-100">
               <div className="flex items-center justify-between mb-2">
                  <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Movie Perks</label>
                  <div className="flex items-center gap-2">
                    <span className="text-[8px] font-bold text-slate-400 uppercase">1+1 Offer</span>
                    <input type="checkbox" className="w-4 h-4 accent-indigo-600" checked={formData.movieOffers.onePlusOne} onChange={e => setFormData({...formData, movieOffers: {...formData.movieOffers, onePlusOne: e.target.checked}})} />
                  </div>
               </div>
               <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">Amount Cap (INR)</label>
                  <input type="number" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.movieOffers.amountBased} onChange={e => setFormData({...formData, movieOffers: {...formData.movieOffers, amountBased: e.target.value}})} />
               </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Lounge Access */}
            <div className="space-y-4 p-4 bg-slate-50/50 rounded-2xl border border-slate-100">
               <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest block mb-1">Lounge Access Protocol</label>
               <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-1">
                    <span className="text-[8px] font-bold text-slate-400 uppercase">Visits Count</span>
                    <input type="number" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.loungeAccess.count} onChange={e => setFormData({...formData, loungeAccess: {...formData.loungeAccess, count: e.target.value}})} />
                  </div>
                  <div className="space-y-1">
                    <span className="text-[8px] font-bold text-slate-400 uppercase">Period</span>
                    <select className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-[10px] font-bold" value={formData.loungeAccess.period} onChange={e => setFormData({...formData, loungeAccess: {...formData.loungeAccess, period: e.target.value}})}>
                      <option>Monthly</option><option>Quarterly</option><option>Yearly</option>
                    </select>
                  </div>
               </div>
               <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">Required Spend (Threshold)</label>
                  <input type="number" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.loungeAccess.spendLimit} onChange={e => setFormData({...formData, loungeAccess: {...formData.loungeAccess, spendLimit: e.target.value}})} />
               </div>
            </div>

            {/* Miscellaneous */}
            <div className="space-y-4 p-4 bg-slate-50/50 rounded-2xl border border-slate-100">
               <div className="flex items-center justify-between mb-4">
                  <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Fuel Surcharge Waiver</label>
                  <input type="checkbox" className="w-4 h-4 accent-indigo-600" checked={formData.fuelSurchargeWaiver} onChange={e => setFormData({...formData, fuelSurchargeWaiver: e.target.checked})} />
               </div>
               <div className="space-y-1">
                  <label className="text-[9px] font-bold text-slate-500 uppercase tracking-widest block">Points Conversion Ratio</label>
                  <input placeholder="e.g. 1 Point = 0.25 INR" className="w-full p-2.5 bg-white border border-slate-200 rounded-lg outline-none text-xs font-bold" value={formData.pointsConversion} onChange={e => setFormData({...formData, pointsConversion: e.target.value})} />
               </div>
            </div>
          </div>

          {/* OTHER BENEFITS BUILDER */}
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h5 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Additional Conditions</h5>
              <button type="button" onClick={addOtherBenefit} className="text-[8px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-lg uppercase tracking-widest hover:bg-indigo-100 transition-colors">+ New Rule</button>
            </div>

            <div className="space-y-3">
              {formData.otherBenefits.map((benefit: CreditCardOtherBenefit, index: number) => (
                <div key={index} className="p-4 bg-white border border-slate-100 rounded-2xl shadow-sm space-y-4 animate-in slide-in-from-top-2">
                   <div className="flex justify-between items-start">
                      <div className="flex-1 grid grid-cols-1 md:grid-cols-2 gap-3">
                        <div className="space-y-1">
                          <label className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Threshold / Condition</label>
                          <input placeholder="e.g. Spend > 50k" className="w-full p-2.5 bg-slate-50 border border-slate-100 rounded-lg text-xs font-bold outline-none" value={benefit.condition} onChange={e => updateOtherBenefit(index, 'condition', e.target.value)} />
                        </div>
                        <div className="space-y-1">
                          <label className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Benefit Outcome</label>
                          <input placeholder="e.g. 2,000 Voucher" className="w-full p-2.5 bg-slate-50 border border-slate-100 rounded-lg text-xs font-bold outline-none" value={benefit.benefitName} onChange={e => updateOtherBenefit(index, 'benefitName', e.target.value)} />
                        </div>
                      </div>
                      <button onClick={() => removeOtherBenefit(index)} className="ml-4 p-2 text-rose-300 hover:text-rose-500 text-lg">✕</button>
                   </div>

                   <div className="space-y-2">
                      <div className="flex justify-between items-center">
                        <label className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Linked Protocol Natures</label>
                        <button type="button" onClick={() => setShowNewNatureInput(true)} className="text-[7px] font-black text-indigo-400 uppercase hover:text-indigo-600">Add New Category</button>
                      </div>

                      {showNewNatureInput && (
                        <div className="flex gap-2 animate-in fade-in slide-in-from-left-2">
                          <input autoFocus placeholder="New nature name..." className="flex-1 p-2 bg-indigo-50/50 border border-indigo-100 rounded-lg text-[10px] font-bold outline-none" value={tempNature} onChange={e => setTempNature(e.target.value)} />
                          <button type="button" onClick={handleInlineNatureAdd} className="px-3 bg-indigo-600 text-white rounded-lg text-[9px] font-bold uppercase">Save</button>
                          <button type="button" onClick={() => setShowNewNatureInput(false)} className="px-2 text-slate-400 text-lg">✕</button>
                        </div>
                      )}

                      <div className="flex flex-wrap gap-2">
                        {natures.map(n => {
                          const isSelected = benefit.linkedNatures.includes(n);
                          return (
                            <button
                              key={n}
                              type="button"
                              onClick={() => {
                                const next = isSelected 
                                  ? benefit.linkedNatures.filter(x => x !== n) 
                                  : [...benefit.linkedNatures, n];
                                updateOtherBenefit(index, 'linkedNatures', next);
                              }}
                              className={`px-3 py-1.5 rounded-full text-[8px] font-black uppercase tracking-tight transition-all border ${
                                isSelected 
                                  ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' 
                                  : 'bg-slate-50 border-slate-200 text-slate-500 hover:bg-slate-100'
                              }`}
                            >
                              {n}
                            </button>
                          );
                        })}
                      </div>
                   </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      <div className="flex gap-3 pt-6 sticky bottom-0 bg-white pb-2">
        <button type="button" onClick={onCancel} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 rounded-2xl font-bold text-[10px] uppercase tracking-widest active:scale-95 transition-all">Cancel</button>
        <button type="submit" className="flex-[2] px-4 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-[0.1em] shadow-xl shadow-indigo-100 active:scale-95 transition-all">Commit Configuration</button>
      </div>
    </form>
  );
};

export default Accounts;

import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, isCloudSyncing, setActiveMemberIds, resetBoarding, simulateSync, markNotificationRead, clearNotifications } = useFinance();
  const [showNotifications, setShowNotifications] = useState(false);
  const [showMemberSelector, setShowMemberSelector] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isShrunk, setIsShrunk] = useState(false);

  const mainRef = useRef<HTMLDivElement>(null);
  const notificationsRef = useRef<HTMLDivElement>(null);
  const selectorRef = useRef<HTMLDivElement>(null);
  const familyMembers = state.profile?.familyMembers || [];
  const unreadCount = state.notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    const handleScroll = () => {
      if (mainRef.current) {
        setIsShrunk(mainRef.current.scrollTop > 30);
      }
    };
    const currentMain = mainRef.current;
    if (currentMain) {
      currentMain.addEventListener('scroll', handleScroll);
    }
    return () => currentMain?.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationsRef.current && !notificationsRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
      if (selectorRef.current && !selectorRef.current.contains(event.target as Node)) {
        setShowMemberSelector(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const isAllSelected = activeMemberIds.includes('all');
  const isMeSelected = activeMemberIds.length === 0;

  const getSelectionLabel = () => {
    if (isAllSelected) return 'Entire Family';
    if (isMeSelected) return 'Mine';
    if (activeMemberIds.length === 1) {
      const member = familyMembers.find(m => m.id === activeMemberIds[0]);
      return member ? member.name : 'Custom View';
    }
    return `Group (${activeMemberIds.length})`;
  };

  const toggleMember = (id: string | 'all') => {
    if (id === 'all') {
      setActiveMemberIds(['all']);
    } else if (id === '') {
      setActiveMemberIds([]);
    } else {
      let nextIds = activeMemberIds.filter(mid => mid !== 'all');
      if (nextIds.includes(id)) {
        nextIds = nextIds.filter(mid => mid !== id);
      } else {
        nextIds.push(id);
      }
      setActiveMemberIds(nextIds);
    }
  };

  const handleSync = async () => {
    setIsSyncing(true);
    await simulateSync();
    setIsSyncing(false);
  };

  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊' },
    { id: 'accounts', label: 'Accounts', icon: '🏦' },
    { id: 'transactions', label: 'Transactions', icon: '💸' },
    { id: 'statements', label: 'Reports', icon: '📜' },
    { id: 'profile', label: 'You', icon: '👤' },
    { id: 'rewards', label: 'Rewards', icon: '🎁' },
  ];

  return (
    <div className="h-[100dvh] flex flex-col md:flex-row bg-slate-50 font-sans selection:bg-indigo-100 overflow-hidden">
      {/* Sidebar (Appears on tablets 768px+ / md breakpoint) */}
      <aside className="hidden md:flex md:w-64 bg-slate-900 border-r border-slate-800 z-30 flex-col text-white sticky top-0 h-full transition-all duration-300">
        <div className="p-6 md:p-8 flex items-center justify-start">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold flex-shrink-0">M</div>
             <h1 className="text-xl font-bold tracking-tight md:block">MyFin</h1>
          </div>
        </div>

        <nav className="flex-1 px-4 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center justify-start gap-4 px-5 py-3 rounded-xl text-sm font-medium transition-all ${
                activeTab === item.id 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
              title={item.label}
            >
              <span className="text-lg">{item.icon}</span>
              <span className="md:block">{item.label}</span>
            </button>
          ))}

          <div className="pt-10 space-y-1">
             <p className="md:block px-5 text-[10px] font-bold text-slate-600 uppercase tracking-widest mb-2">Session</p>
             <button
              onClick={resetBoarding}
              className="w-full flex items-center justify-start gap-4 px-5 py-3 rounded-xl text-xs font-medium text-slate-500 hover:text-rose-400 transition-colors uppercase"
            >
              <span className="text-sm">🚪</span>
              <span className="md:block">Sign Out</span>
            </button>
          </div>
        </nav>
      </aside>

      {/* Main Content Area */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto overflow-x-hidden custom-scrollbar">
        {/* Adaptive Header */}
        <header className={`sticky top-0 bg-white/90 backdrop-blur-md border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all duration-300 morph-header ${isShrunk ? 'h-14' : 'h-16 md:h-20'} pt-[var(--sat)]`}>
          <div className="flex items-center gap-3 md:gap-4">
            <div className="md:hidden flex items-center gap-2">
               <div className={`bg-indigo-600 rounded-lg flex items-center justify-center font-bold text-white transition-all ${isShrunk ? 'w-7 h-7 text-xs' : 'w-9 h-9 text-sm'}`}>M</div>
               {!isShrunk && <span className="font-black text-slate-800 tracking-tighter text-lg">MyFin</span>}
            </div>

            <div className="flex items-center">
              <button 
                onClick={handleSync}
                disabled={isSyncing}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest transition-all ${
                  isSyncing 
                    ? 'bg-slate-100 text-slate-400' 
                    : 'bg-indigo-600 text-white shadow-md active:scale-95'
                }`}
              >
                <span className={isSyncing ? 'animate-spin' : ''}>🔄</span>
                <span className="hidden sm:inline">{isSyncing ? 'Syncing...' : 'Sync'}</span>
              </button>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <div className="relative" ref={selectorRef}>
              <button 
                onClick={() => setShowMemberSelector(!showMemberSelector)}
                className={`flex items-center gap-2 px-3 md:px-4 py-2 bg-slate-100 rounded-full text-[9px] font-black uppercase tracking-widest transition-all hover:bg-slate-200 active:scale-95 border border-transparent ${showMemberSelector ? 'border-indigo-200 bg-white shadow-sm' : ''}`}
              >
                <span className="text-xs">👥</span>
                <span className="max-w-[70px] md:max-w-none truncate">{getSelectionLabel()}</span>
                <span className={`text-[8px] transition-transform duration-200 ${showMemberSelector ? 'rotate-180' : ''}`}>▼</span>
              </button>

              {showMemberSelector && (
                <div className="absolute top-full right-0 mt-2 w-56 md:w-64 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2">
                  <div className="p-3 border-b border-slate-100 bg-slate-50/50">
                    <h4 className="text-[8px] font-black text-slate-400 uppercase tracking-widest">Select Participants</h4>
                  </div>
                  <div className="p-2 space-y-1">
                    <button 
                      onClick={() => { toggleMember(''); setShowMemberSelector(false); }}
                      className={`w-full flex items-center justify-between px-3 py-2.5 rounded-xl text-[10px] font-black uppercase transition-all ${isMeSelected ? 'bg-indigo-600 text-white' : 'hover:bg-slate-50 text-slate-600'}`}
                    >
                      <span>👤 Mine</span>
                      {isMeSelected && <span>✓</span>}
                    </button>
                    <button 
                      onClick={() => { toggleMember('all'); setShowMemberSelector(false); }}
                      className={`w-full flex items-center justify-between px-3 py-2.5 rounded-xl text-[10px] font-black uppercase transition-all ${isAllSelected ? 'bg-indigo-600 text-white' : 'hover:bg-slate-50 text-slate-600'}`}
                    >
                      <span>🌍 Entire Family</span>
                      {isAllSelected && <span>✓</span>}
                    </button>
                    {familyMembers.length > 0 && (
                      <div className="pt-2 border-t border-slate-50 mt-1">
                        <p className="px-3 py-1 text-[7px] font-black text-slate-300 uppercase tracking-widest mb-1">Individual members</p>
                        {familyMembers.map(member => {
                          const isSelected = activeMemberIds.includes(member.id);
                          return (
                            <button 
                              key={member.id}
                              onClick={() => toggleMember(member.id)}
                              className={`w-full flex items-center justify-between px-3 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${isSelected ? 'bg-indigo-50 text-indigo-600' : 'hover:bg-slate-50 text-slate-500'}`}
                            >
                              <span className="flex items-center gap-2">
                                <span className={`w-1.5 h-1.5 rounded-full ${isSelected ? 'bg-indigo-600' : 'bg-slate-200'}`}></span>
                                {member.name}
                              </span>
                              {isSelected && <span>✓</span>}
                            </button>
                          );
                        })}
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>

            <div className="relative" ref={notificationsRef}>
               <button onClick={() => setShowNotifications(!showNotifications)} className="relative p-2 bg-slate-100 rounded-lg text-slate-600 active:scale-95 transition-all">
                 <span className="text-xl">🔔</span>
                 {unreadCount > 0 && <span className="absolute top-1 right-1 bg-rose-500 w-2 h-2 rounded-full border border-white"></span>}
               </button>
               {showNotifications && (
                <div className="absolute top-full right-0 mt-2 w-72 md:w-80 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2">
                  <div className="p-3 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                    <h4 className="text-[9px] font-black text-slate-800 uppercase tracking-widest">Alerts</h4>
                    <button onClick={clearNotifications} className="text-[9px] font-black text-indigo-600 uppercase">Clear All</button>
                  </div>
                  <div className="max-h-[60dvh] overflow-y-auto custom-scrollbar">
                    {state.notifications.length > 0 ? [...state.notifications].reverse().map(n => (
                      <div key={n.id} onClick={() => markNotificationRead(n.id)} className={`p-4 border-b border-slate-50 transition-colors cursor-pointer hover:bg-slate-50 ${n.isRead ? 'opacity-50' : 'bg-white'}`}>
                        <div className="flex justify-between items-start mb-1">
                          <p className="text-[11px] font-black text-slate-800 uppercase leading-tight">{n.title}</p>
                          <span className="text-[8px] font-bold text-slate-400">{n.timestamp}</span>
                        </div>
                        <p className="text-[10px] text-slate-500 font-medium leading-relaxed">{n.message}</p>
                      </div>
                    )) : (
                      <div className="p-10 text-center text-slate-300 italic text-xs">No notifications</div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        <div className="flex-1 p-4 md:p-6 lg:p-10 max-w-7xl mx-auto w-full pb-24 md:pb-10">
          {children}
        </div>

        {/* Mobile Bottom Navigation (Only on screens < 768px) */}
        <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-lg border-t border-slate-200 flex items-center justify-around px-2 pt-2 pb-[calc(env(safe-area-inset-bottom)+0.75rem)] z-50 shadow-[0_-10px_20px_-5px_rgba(0,0,0,0.05)]">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`flex flex-col items-center gap-1 transition-all px-3 py-1 rounded-xl ${
                activeTab === item.id ? 'text-indigo-600' : 'text-slate-400'
              }`}
            >
              <span className={`text-xl transition-transform ${activeTab === item.id ? 'scale-110' : ''}`}>{item.icon}</span>
              <span className={`text-[8px] font-black uppercase tracking-[0.1em] ${activeTab === item.id ? 'opacity-100' : 'opacity-50'}`}>{item.label}</span>
            </button>
          ))}
        </nav>
      </main>
    </div>
  );
};

export default Layout;

export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';
export type AccountClassification = 'Current Asset' | 'Non-Current Asset' | 'Current Liability' | 'Non-Current Liability' | 'Equity';

export interface FamilyMember {
  id: string;
  name: string;
  relation: string;
  mobileNumber: string;
  canAddTransactions?: boolean;
}

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
  familyMembers: FamilyMember[];
  cloudDatabaseName?: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  timestamp: string;
  type: 'transaction' | 'system' | 'sync';
  isRead: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
  ownerId?: string;
  accountType?: 'Savings' | 'Current' | 'Salary' | 'Others';
  customAccountType?: string;
  classification?: AccountClassification;
}

export interface CreditCardOtherBenefit {
  condition: string;
  benefitName: string;
  linkedNatures: string[];
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number;
  last4: string;
  limit?: number;
  annualLimit?: number; 
  anniversaryDate?: string;
  billingDay?: number;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
  ownerId?: string;
  classification?: AccountClassification;
  // NEW BENEFIT FIELDS
  cashbackPct?: number;
  movieOffers?: {
    onePlusOne: boolean;
    amountBased: number;
  };
  loungeAccess?: {
    count: number;
    spendLimit: number;
    period: string;
  };
  fuelSurchargeWaiver?: boolean;
  forexMarkup?: number;
  pointsConversion?: string;
  otherBenefits?: CreditCardOtherBenefit[];
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
  ownerId?: string;
  classification?: AccountClassification;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
  ownerId?: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  periodicity?: Periodicity;
  ownerId?: string;
}

export interface Asset {
  id: string;
  name: string;
  value: number;
  type?: 'Physical' | 'Receivable';
  ownerId?: string;
  classification?: AccountClassification;
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
  type?: 'Debt' | 'Payable';
  ownerId?: string;
  classification?: AccountClassification;
}

export type TransactionType = 'Income' | 'Expense' | 'Asset' | 'Liability';

export interface SharedContact {
  name: string;
  mobile: string;
  amount: number;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  nature: string; 
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet' | 'liability';
  date: string;
  category?: string;
  isShared?: boolean;
  sharedAmount?: number;
  numberOfPeople?: number;
  includeSelf?: boolean;
  sharedContacts?: SharedContact[];
  ownerId?: string; 
  isin?: string;
  stockName?: string;
  units?: number; // New field for tracking quantity of units
  billingPeriod?: string; 
  isSettled?: boolean;
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
  notifications: Notification[];
  transactionNatures: string[]; 
  capital: number; 
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';
import { GoogleGenAI } from "@google/genai";

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  netTotal: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature, addWallet } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isIsinResolving, setIsIsinResolving] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(15);
  const [pdfPassword, setPdfPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [pendingFile, setPendingFile] = useState<File | null>(null);

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    finalSettlementAmount: number; 
    isSettlementPayable: boolean; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  const selectedAccount = useMemo(() => {
    return [...state.banks, ...state.cards, ...state.wallets, ...state.liabilities].find(a => a.id === formData.accountId);
  }, [formData.accountId, state]);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (formData.isin && formData.isin.length === 12 && !formData.stockName) {
        handleIsinLookup(formData.isin);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [formData.isin]);

  const handleIsinLookup = async (isin: string) => {
    setIsIsinResolving(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify the security/stock name for the following ISIN identifier: ${isin}. Return ONLY the official short name of the security. No preamble.`
      });
      const resolvedName = response.text?.trim() || 'Unknown Security';
      setFormData(prev => ({ 
        ...prev, 
        stockName: resolvedName,
        description: prev.description || resolvedName
      }));
    } catch (err) {
      console.error("ISIN Resolution failed:", err);
    } finally {
      setIsIsinResolving(false);
    }
  };

  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
    const zerodhaExists = [...state.banks, ...state.wallets].some(a => a.name.toLowerCase() === 'zerodha');
    if (!zerodhaExists) {
      addWallet({
        id: 'zerodha-account-auto',
        name: 'Zerodha',
        balance: 0,
        ownerId: ''
      });
    }
  }, []);

  useEffect(() => {
    let timer: number;
    if (isScanning && scanTimeLeft > 0) {
      timer = window.setInterval(() => {
        setScanTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isScanning, scanTimeLeft]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setPendingFile(file);
    setShowPasswordInput(true);
  };

  const startAIParsing = async () => {
    if (!pendingFile) return;
    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(18);

    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: pendingFile.type } },
              { text: `Extract data from this Zerodha Contract Note PDF. Return ONLY JSON: { "date": "YYYY-MM-DD", "isSettlementPayable": boolean, "finalSettlementAmount": number, "trades": [{"scrip": "string", "type": "BUY" | "SELL", "netTotal": number}], "otherCharges": number }` }
            ]
          },
          config: { responseMimeType: "application/json" }
        });
        const result = JSON.parse(response.text || '{}');
        if (result.date) setScanResult(result);
        else alert("Failed to parse.");
      } catch (err) {
        console.error(err);
        alert("Verification failed.");
      } finally {
        setIsScanning(false);
        setPdfPassword('');
        setPendingFile(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(pendingFile);
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;
    const zerodhaAccount = [...state.banks, ...state.wallets, ...state.cards].find(a => a.name.toLowerCase() === 'zerodha') || { id: 'zerodha-account-auto', type: 'wallet' };
    scanResult.trades.forEach(t => {
      addTransaction({
        id: Math.random().toString(36).substr(2, 9),
        type: t.type === 'BUY' ? 'Asset' : 'Income', 
        amount: t.netTotal,
        nature: 'Investment in stocks',
        description: `${t.type} ${t.scrip}`,
        accountId: zerodhaAccount.id,
        accountType: (zerodhaAccount as any).type || 'wallet',
        date: scanResult.date,
        ownerId: formData.ownerId
      });
    });
    if (scanResult.otherCharges > 0) {
      addTransaction({
        id: Math.random().toString(36).substr(2, 9),
        type: 'Expense',
        amount: scanResult.otherCharges,
        nature: 'Other Charges',
        description: `Zerodha Charges: ${scanResult.date}`,
        accountId: zerodhaAccount.id,
        accountType: (zerodhaAccount as any).type || 'wallet',
        date: scanResult.date,
        ownerId: formData.ownerId
      });
    }
    setScanResult(null);
  };

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, nature: natures[0] || '' });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const totalValue = t.amount + (t.sharedAmount || 0);
    setFormData({
      ...initialFormState,
      type: t.type,
      amount: String(totalValue),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: t.includeSelf ?? true,
      numberOfPeople: t.numberOfPeople || 2,
      ownerId: t.ownerId || '',
      isin: t.isin || '',
      stockName: t.stockName || '',
      units: t.units ? String(t.units) : '',
      billingPeriod: t.billingPeriod || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: Number(formData.amount),
      nature: formData.nature,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      ownerId: formData.ownerId,
      isin: formData.isin,
      stockName: formData.stockName,
      units: formData.units ? Number(formData.units) : undefined,
      billingPeriod: formData.billingPeriod
    };
    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight uppercase">Audit Ledger</h3>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-2">Verified Transaction History</p>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:flex lg:flex-wrap items-center gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*,.pdf" onChange={handleFileUpload} />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="col-span-2 md:col-span-1 px-4 lg:px-6 py-3 lg:py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-slate-800 transition-all shadow-xl active:scale-95"
          >
            <span>📄</span> Broker Import
          </button>
          <button onClick={() => handleOpenModal('Income')} className="px-4 py-3 lg:py-4 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-4 py-3 lg:py-4 bg-rose-50 text-rose-500 border border-rose-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-4 py-3 lg:py-4 bg-white text-indigo-600 border border-indigo-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-4 py-3 lg:py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Debt</button>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[800px] lg:min-w-full">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Timeline</th>
                <th className="px-8 py-6">Audit Nature</th>
                <th className="px-8 py-6">Entity Claims</th>
                <th className="px-8 py-6 text-right">Settlement</th>
                <th className="px-8 py-6 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/30 transition-colors group">
                  <td className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-tighter">
                    {t.date}
                    {t.billingPeriod && <div className="text-[7px] text-indigo-500 font-black mt-1 uppercase">Cycle: {t.billingPeriod}</div>}
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-3">
                      <p className="text-sm font-black text-slate-800 tracking-tight">{t.description || t.stockName || t.nature}</p>
                      {t.isin && <span className="bg-indigo-50 text-indigo-400 text-[8px] font-black px-2 py-0.5 rounded uppercase tracking-widest">{t.isin}</span>}
                    </div>
                    <div className="flex items-center gap-2 mt-2">
                      <span className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em]">{t.nature}</span>
                      {t.units && <span className="text-[8px] bg-slate-100 text-slate-600 font-black px-2 py-0.5 rounded uppercase">Qty: {t.units}</span>}
                    </div>
                  </td>
                  <td className="px-8 py-6"><span className="text-[10px] font-black text-slate-600 bg-slate-100/50 border border-slate-100 px-3 py-1.5 rounded-xl uppercase tracking-widest">{getOwnerName(t.ownerId)}</span></td>
                  <td className="px-8 py-6 text-right">
                    <div className={`text-base font-black tracking-tight ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : (t.type === 'Expense' ? 'text-rose-500' : 'text-slate-800')}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'} {formatCurrency(t.amount, currency)}
                    </div>
                  </td>
                  <td className="px-8 py-6 text-center">
                    <div className="flex items-center justify-center gap-2 md:opacity-0 md:group-hover:opacity-100 transition-all">
                      <button onClick={() => handleEditClick(t)} className="p-2.5 bg-slate-50 hover:bg-white hover:shadow-md text-slate-400 hover:text-indigo-600 rounded-xl transition-all">✎</button>
                      <button onClick={() => setConfirmDeleteTx(t)} className="p-2.5 bg-slate-50 hover:bg-white hover:shadow-md text-slate-400 hover:text-rose-500 rounded-xl transition-all">✕</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {transactionList.length === 0 && (
            <div className="py-32 text-center">
              <div className="w-16 h-16 bg-slate-50 text-slate-200 flex items-center justify-center rounded-3xl mx-auto mb-6 text-3xl">📂</div>
              <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em]">Vault currently empty</p>
            </div>
          )}
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-center bg-slate-900/60 backdrop-blur-xl p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 relative max-h-[90dvh] overflow-y-auto custom-scrollbar">
            <div className="flex justify-between items-center mb-10 border-b border-slate-100 pb-6">
              <div>
                <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">{formData.type} Record</h3>
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Manual Reconciliation Entry</p>
              </div>
              <button onClick={() => setShowModal(false)} className="text-slate-200 hover:text-slate-800 font-black p-2 text-2xl transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              {formData.type === 'Asset' && (
                <div className="space-y-6 bg-indigo-50/30 p-8 rounded-[2rem] border border-indigo-100 animate-in slide-in-from-top-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">ISIN Protocol Key</label>
                      <input 
                        className="w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs uppercase tracking-widest focus:ring-4 focus:ring-indigo-500/10 transition-all" 
                        placeholder="e.g. INE002A01018"
                        maxLength={12}
                        value={formData.isin} 
                        onChange={e => setFormData({ ...formData, isin: e.target.value.toUpperCase() })} 
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Official Security Name</label>
                      <div className="relative">
                        <input 
                          className={`w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs focus:ring-4 focus:ring-indigo-500/10 transition-all ${isIsinResolving ? 'animate-pulse text-indigo-300' : ''}`} 
                          placeholder={isIsinResolving ? "Querying AI Vault..." : "Identifying..."}
                          value={formData.stockName} 
                          onChange={e => setFormData({ ...formData, stockName: e.target.value })} 
                        />
                        {isIsinResolving && <span className="absolute right-4 top-1/2 -translate-y-1/2 animate-spin text-indigo-500 text-lg">⚙️</span>}
                      </div>
                    </div>
                  </div>

                  {formData.isin && (
                    <div className="space-y-2 animate-in fade-in slide-in-from-left-4 duration-500">
                      <label className="text-[9px] font-black text-indigo-600 uppercase tracking-widest block ml-2">Number of Units / Quantity</label>
                      <input 
                        type="number" 
                        step="any"
                        className="w-full p-4 bg-white border border-indigo-200 rounded-2xl outline-none font-black text-xl text-indigo-600 shadow-sm focus:ring-4 focus:ring-indigo-500/10 transition-all" 
                        placeholder="0.00"
                        value={formData.units} 
                        onChange={e => setFormData({ ...formData, units: e.target.value })} 
                      />
                    </div>
                  )}
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Reporting Entity</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value, accountId: '' })}>
                    <option value="">Me (Primary Vault)</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Nature Protocol</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.nature} onChange={e => setFormData({ ...formData, nature: e.target.value })}>
                    <option value="" disabled>Select Protocol</option>
                    {natures.map(n => <option key={n} value={n}>{n.toUpperCase()}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Settlement Amount ({currency})</label>
                  <input required type="number" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-2xl focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Audit Timeline</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase tracking-widest cursor-pointer" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Brief Description</label>
                  <input className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold text-xs" placeholder="Audit notes..." value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Account Instrument</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">Select Target Account</option>
                    {allAccounts.filter(a => (a.ownerId || '') === (formData.ownerId || '')).map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}
                  </select>
                </div>
              </div>

              {/* Annual Billing Period selection for Credit Cards */}
              {selectedAccount?.type === 'card' && (
                <div className="space-y-2 p-6 bg-slate-50 rounded-[2rem] border border-slate-100 animate-in slide-in-from-bottom-2">
                  <label className="text-[9px] font-black text-indigo-500 uppercase tracking-widest block ml-2">Annual Milestone / Billing Period (Optional)</label>
                  <div className="flex gap-4 items-center">
                    <input 
                      placeholder="e.g. Year 1, 2024-25, etc." 
                      className="flex-1 p-4 bg-white border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase tracking-widest"
                      value={formData.billingPeriod}
                      onChange={e => setFormData({ ...formData, billingPeriod: e.target.value })}
                    />
                    <div className="text-[8px] font-black text-slate-400 w-1/3 leading-tight uppercase">Use this to track spend against annual limits and benefits.</div>
                  </div>
                </div>
              )}

              <div className="flex flex-col md:flex-row gap-4 pt-8 sticky bottom-0 bg-white pb-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase tracking-widest rounded-2xl active:scale-95 transition-all">Discard Changes</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-100 active:scale-95 transition-all">Commit to Ledger</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';
import { GoogleGenAI } from "@google/genai";
import * as XLSX from 'xlsx';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  netTotal: number;
  units?: number;
  date?: string;
  isin?: string;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature, addWallet } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isIsinResolving, setIsIsinResolving] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(15);
  const [pdfPassword, setPdfPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [pendingFile, setPendingFile] = useState<File | null>(null);

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    finalSettlementAmount: number; 
    isSettlementPayable: boolean; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  const selectedAccount = useMemo(() => {
    return [...state.banks, ...state.cards, ...state.wallets, ...state.liabilities].find(a => a.id === formData.accountId);
  }, [formData.accountId, state]);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (formData.isin && formData.isin.length === 12 && !formData.stockName) {
        handleIsinLookup(formData.isin);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [formData.isin]);

  const handleIsinLookup = async (isin: string) => {
    setIsIsinResolving(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify the security/stock name for the following ISIN identifier: ${isin}. Return ONLY the official short name of the security. No preamble.`
      });
      const resolvedName = response.text?.trim() || 'Unknown Security';
      setFormData(prev => ({ 
        ...prev, 
        stockName: resolvedName,
        description: prev.description || resolvedName
      }));
    } catch (err) {
      console.error("ISIN Resolution failed:", err);
    } finally {
      setIsIsinResolving(false);
    }
  };

  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
    const zerodhaExists = [...state.banks, ...state.wallets].some(a => a.name.toLowerCase() === 'zerodha');
    if (!zerodhaExists) {
      addWallet({
        id: 'zerodha-account-auto',
        name: 'Zerodha',
        balance: 0,
        ownerId: ''
      });
    }
  }, []);

  useEffect(() => {
    let timer: number;
    if (isScanning && scanTimeLeft > 0) {
      timer = window.setInterval(() => {
        setScanTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isScanning, scanTimeLeft]);

  const downloadExcelTemplate = () => {
    const headers = [
      ["ISIN", "Date of transaction", "Quantity", "Buy/Sell", "Total Buy/Sell Value", "Total Charges excluding STT", "STT", "Net Payable/ Receivable"],
      ["INE002A01018", "2024-01-20", 10, "BUY", 10000, 20, 10, -10030],
      ["INE002A01018", "2024-01-22", 5, "SELL", -5500, 15, 5, 5480]
    ];

    const ws = XLSX.utils.aoa_to_sheet(headers);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Trades");
    XLSX.writeFile(wb, "MyFin_Broker_Import_Template.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.name.endsWith('.xlsx') || file.name.endsWith('.xls')) {
      handleExcelImport(file);
      return;
    }

    setPendingFile(file);
    setShowPasswordInput(true);
  };

  const handleExcelImport = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const rows: any[] = XLSX.utils.sheet_to_json(worksheet);

        if (rows.length === 0) {
          alert("Excel file is empty.");
          return;
        }

        const trades: ExtractedTrade[] = [];
        let totalOtherCharges = 0;
        let importDate = new Date().toISOString().split('T')[0];

        rows.forEach((row: any) => {
          const isin = row['ISIN'] || '';
          const date = row['Date of transaction'];
          const qty = Number(row['Quantity'] || 0);
          const type = (row['Buy/Sell'] || '').toUpperCase();
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const charges = Number(row['Total Charges excluding STT'] || 0);
          const stt = Number(row['STT'] || 0);

          if (date) importDate = new Date(date).toISOString().split('T')[0];

          trades.push({
            scrip: isin, // Scrip initially ISIN, will resolve name later if needed or just use as is
            type: type === 'BUY' ? 'BUY' : 'SELL',
            netTotal: grossValue,
            units: qty,
            date: importDate,
            isin: isin
          });

          totalOtherCharges += (charges + stt);
        });

        setScanResult({
          date: importDate,
          finalSettlementAmount: 0, // Not strictly used for individual trade creation
          isSettlementPayable: false,
          trades: trades,
          otherCharges: totalOtherCharges
        });

      } catch (err) {
        console.error(err);
        alert("Failed to parse Excel file.");
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const startAIParsing = async () => {
    if (!pendingFile) return;
    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(18);

    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: pendingFile.type } },
              { text: `Extract data from this Zerodha Contract Note PDF. Return ONLY JSON: { "date": "YYYY-MM-DD", "isSettlementPayable": boolean, "finalSettlementAmount": number, "trades": [{"scrip": "string", "type": "BUY" | "SELL", "netTotal": number}], "otherCharges": number }` }
            ]
          },
          config: { responseMimeType: "application/json" }
        });
        const result = JSON.parse(response.text || '{}');
        if (result.date) setScanResult(result);
        else alert("Failed to parse.");
      } catch (err) {
        console.error(err);
        alert("Verification failed.");
      } finally {
        setIsScanning(false);
        setPdfPassword('');
        setPendingFile(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(pendingFile);
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;
    const zerodhaAccount = [...state.banks, ...state.wallets, ...state.cards].find(a => a.name.toLowerCase() === 'zerodha') || { id: 'zerodha-account-auto', type: 'wallet' };

    scanResult.trades.forEach(t => {
      addTransaction({
        id: Math.random().toString(36).substr(2, 9),
        type: t.type === 'BUY' ? 'Asset' : 'Income', 
        amount: t.netTotal,
        nature: 'Investment in stocks',
        description: `${t.type} ${t.scrip}`,
        accountId: zerodhaAccount.id,
        accountType: (zerodhaAccount as any).type || 'wallet',
        date: t.date || scanResult.date,
        ownerId: formData.ownerId,
        isin: t.isin,
        units: t.units
      });
    });

    if (scanResult.otherCharges > 0) {
      addTransaction({
        id: Math.random().toString(36).substr(2, 9),
        type: 'Expense',
        amount: scanResult.otherCharges,
        nature: 'Other Charges',
        description: `Broker Charges: ${scanResult.date}`,
        accountId: zerodhaAccount.id,
        accountType: (zerodhaAccount as any).type || 'wallet',
        date: scanResult.date,
        ownerId: formData.ownerId
      });
    }
    setScanResult(null);
  };

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, nature: natures[0] || '' });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      ...initialFormState,
      type: t.type,
      amount: String(t.amount),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      ownerId: t.ownerId || '',
      isin: t.isin || '',
      stockName: t.stockName || '',
      units: t.units ? String(t.units) : '',
      billingPeriod: t.billingPeriod || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: Number(formData.amount),
      nature: formData.nature,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      ownerId: formData.ownerId,
      isin: formData.isin,
      stockName: formData.stockName,
      units: formData.units ? Number(formData.units) : undefined,
      billingPeriod: formData.billingPeriod
    };
    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight uppercase">Audit Ledger</h3>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-2">Verified Transaction History</p>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:flex lg:flex-wrap items-center gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*,.pdf,.xlsx,.xls" onChange={handleFileUpload} />
          <div className="flex flex-col gap-1 items-center col-span-2 md:col-span-1">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="w-full px-4 lg:px-6 py-3 lg:py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-slate-800 transition-all shadow-xl active:scale-95"
            >
              <span>📄</span> Broker Import
            </button>
            <button 
              onClick={downloadExcelTemplate}
              className="text-[8px] font-black text-indigo-500 uppercase tracking-widest hover:underline px-2"
            >
              Download Excel Template
            </button>
          </div>
          <button onClick={() => handleOpenModal('Income')} className="px-4 py-3 lg:py-4 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-4 py-3 lg:py-4 bg-rose-50 text-rose-500 border border-rose-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-4 py-3 lg:py-4 bg-white text-indigo-600 border border-indigo-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-4 py-3 lg:py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Debt</button>
        </div>
      </div>

      {scanResult && (
        <div className="bg-indigo-900 text-white p-6 md:p-10 rounded-[2.5rem] shadow-2xl animate-in slide-in-from-top-10 duration-500 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 text-8xl opacity-10 font-black">IMPORT</div>
          <div className="relative z-10">
            <h4 className="text-sm font-black uppercase tracking-widest mb-6 border-b border-white/10 pb-4 flex items-center gap-3">
              <span className="text-2xl">📋</span> Verify Extracted Ledger
            </h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="space-y-6">
                <div>
                  <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-1">Audit Timeline</p>
                  <p className="text-2xl font-black">{scanResult.date}</p>
                </div>
                <div className="bg-white/5 p-6 rounded-3xl border border-white/10">
                   <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-4">Trade Summary</p>
                   <div className="space-y-4">
                     {scanResult.trades.map((t, i) => (
                       <div key={i} className="flex justify-between items-center border-b border-white/5 pb-2 last:border-0 last:pb-0">
                         <div>
                           <p className="text-xs font-black uppercase tracking-tight">{t.scrip}</p>
                           <p className="text-[8px] font-black text-indigo-400 uppercase">{t.type} {t.units ? `• ${t.units} Units` : ''}</p>
                         </div>
                         <p className="text-sm font-black">{formatCurrency(t.netTotal, currency)}</p>
                       </div>
                     ))}
                   </div>
                </div>
              </div>
              <div className="flex flex-col justify-between">
                <div className="space-y-4">
                  <div className="flex justify-between items-center p-4 bg-white/5 rounded-2xl">
                    <span className="text-[10px] font-black uppercase">Other Charges</span>
                    <span className="text-sm font-black">{formatCurrency(scanResult.otherCharges, currency)}</span>
                  </div>
                  <div className="flex justify-between items-center p-6 bg-indigo-800 rounded-3xl border border-white/10 shadow-xl">
                    <span className="text-[10px] font-black uppercase">Net Settlement</span>
                    <p className={`text-2xl font-black ${scanResult.isSettlementPayable ? 'text-rose-400' : 'text-emerald-400'}`}>
                      {scanResult.isSettlementPayable ? '-' : '+'} {formatCurrency(scanResult.finalSettlementAmount || scanResult.trades.reduce((acc, t) => acc + t.netTotal, 0) + scanResult.otherCharges, currency)}
                    </p>
                  </div>
                </div>
                <div className="flex gap-4 mt-10">
                  <button onClick={() => setScanResult(null)} className="flex-1 py-5 bg-white/10 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-white/20 transition-all">Reject</button>
                  <button onClick={commitScannedTrade} className="flex-[2] py-5 bg-emerald-500 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-emerald-900/40 hover:bg-emerald-600 transition-all active:scale-95">Commit to Vault</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[800px] lg:min-w-full">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Timeline</th>
                <th className="px-8 py-6">Audit Nature</th>
                <th className="px-8 py-6">Entity Claims</th>
                <th className="px-8 py-6 text-right">Settlement</th>
                <th className="px-8 py-6 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/30 transition-colors group">
                  <td className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-tighter">
                    {t.date}
                    {t.billingPeriod && <div className="text-[7px] text-indigo-500 font-black mt-1 uppercase">Cycle: {t.billingPeriod}</div>}
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-3">
                      <p className="text-sm font-black text-slate-800 tracking-tight">{t.description || t.stockName || t.nature}</p>
                      {t.isin && <span className="bg-indigo-50 text-indigo-400 text-[8px] font-black px-2 py-0.5 rounded uppercase tracking-widest">{t.isin}</span>}
                    </div>
                    <div className="flex items-center gap-2 mt-2">
                      <span className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em]">{t.nature}</span>
                      {t.units && <span className="text-[8px] bg-slate-100 text-slate-600 font-black px-2 py-0.5 rounded uppercase">Qty: {t.units}</span>}
                    </div>
                  </td>
                  <td className="px-8 py-6"><span className="text-[10px] font-black text-slate-600 bg-slate-100/50 border border-slate-100 px-3 py-1.5 rounded-xl uppercase tracking-widest">{getOwnerName(t.ownerId)}</span></td>
                  <td className="px-8 py-6 text-right">
                    <div className={`text-base font-black tracking-tight ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : (t.type === 'Expense' ? 'text-rose-500' : 'text-slate-800')}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'} {formatCurrency(t.amount, currency)}
                    </div>
                  </td>
                  <td className="px-8 py-6 text-center">
                    <div className="flex items-center justify-center gap-2 md:opacity-0 md:group-hover:opacity-100 transition-all">
                      <button onClick={() => handleEditClick(t)} className="p-2.5 bg-slate-50 hover:bg-white hover:shadow-md text-slate-400 hover:text-indigo-600 rounded-xl transition-all">✎</button>
                      <button onClick={() => setConfirmDeleteTx(t)} className="p-2.5 bg-slate-50 hover:bg-white hover:shadow-md text-slate-400 hover:text-rose-500 rounded-xl transition-all">✕</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {transactionList.length === 0 && (
            <div className="py-32 text-center">
              <div className="w-16 h-16 bg-slate-50 text-slate-200 flex items-center justify-center rounded-3xl mx-auto mb-6 text-3xl">📂</div>
              <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em]">Vault currently empty</p>
            </div>
          )}
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-center bg-slate-900/60 backdrop-blur-xl p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 relative max-h-[90dvh] overflow-y-auto custom-scrollbar">
            <div className="flex justify-between items-center mb-10 border-b border-slate-100 pb-6">
              <div>
                <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">{formData.type} Record</h3>
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Manual Reconciliation Entry</p>
              </div>
              <button onClick={() => setShowModal(false)} className="text-slate-200 hover:text-slate-800 font-black p-2 text-2xl transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              {formData.type === 'Asset' && (
                <div className="space-y-6 bg-indigo-50/30 p-8 rounded-[2rem] border border-indigo-100 animate-in slide-in-from-top-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">ISIN Protocol Key</label>
                      <input 
                        className="w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs uppercase tracking-widest focus:ring-4 focus:ring-indigo-500/10 transition-all" 
                        placeholder="e.g. INE002A01018"
                        maxLength={12}
                        value={formData.isin} 
                        onChange={e => setFormData({ ...formData, isin: e.target.value.toUpperCase() })} 
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Official Security Name</label>
                      <div className="relative">
                        <input 
                          className={`w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs focus:ring-4 focus:ring-indigo-500/10 transition-all ${isIsinResolving ? 'animate-pulse text-indigo-300' : ''}`} 
                          placeholder={isIsinResolving ? "Querying AI Vault..." : "Identifying..."}
                          value={formData.stockName} 
                          onChange={e => setFormData({ ...formData, stockName: e.target.value })} 
                        />
                        {isIsinResolving && <span className="absolute right-4 top-1/2 -translate-y-1/2 animate-spin text-indigo-500 text-lg">⚙️</span>}
