              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Brief Description</label>
                  <input className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold text-xs" placeholder="Audit notes..." value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Account Instrument</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">Select Target Account</option>
                    {allAccounts.filter(a => (a.ownerId || '') === (formData.ownerId || '')).map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}
                  </select>
                </div>
              </div>

              {/* Annual Billing Period selection for Credit Cards */}
              {selectedAccount?.type === 'card' && (
                <div className="space-y-2 p-6 bg-slate-50 rounded-[2rem] border border-slate-100 animate-in slide-in-from-bottom-2">
                  <label className="text-[9px] font-black text-indigo-500 uppercase tracking-widest block ml-2">Annual Milestone / Billing Period (Optional)</label>
                  <div className="flex gap-4 items-center">
                    <input 
                      placeholder="e.g. Year 1, 2024-25, etc." 
                      className="flex-1 p-4 bg-white border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase tracking-widest"
                      value={formData.billingPeriod}
                      onChange={e => setFormData({ ...formData, billingPeriod: e.target.value })}
                    />
                    <div className="text-[8px] font-black text-slate-400 w-1/3 leading-tight uppercase">Use this to track spend against annual limits and benefits.</div>
                  </div>
                </div>
              )}

              <div className="flex flex-col md:flex-row gap-4 pt-8 sticky bottom-0 bg-white pb-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase tracking-widest rounded-2xl active:scale-95 transition-all">Discard Changes</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-100 active:scale-95 transition-all">Commit to Ledger</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showPasswordInput && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
           <div className="bg-white w-full max-w-sm p-8 rounded-3xl border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
              <h4 className="text-sm font-black text-slate-800 uppercase tracking-tighter mb-4">Secure Document Entry</h4>
              <p className="text-[10px] font-medium text-slate-400 uppercase tracking-widest mb-6">Enter PDF Password to proceed with decryption</p>
              <input type="password" autoFocus className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-black text-lg mb-6" value={pdfPassword} onChange={e => setPdfPassword(e.target.value)} onKeyPress={e => e.key === 'Enter' && startAIParsing()} />
              <div className="flex gap-3">
                 <button onClick={() => setShowPasswordInput(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-xl">Cancel</button>
                 <button onClick={startAIParsing} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg">Decrypt & Verify</button>
              </div>
           </div>
        </div>
      )}

      {isScanning && (
        <div className="fixed inset-0 z-[70] flex flex-col items-center justify-center bg-indigo-900/95 backdrop-blur-3xl text-white">
           <div className="w-24 h-24 border-4 border-indigo-400/30 border-t-indigo-400 rounded-full animate-spin mb-10"></div>
           <h2 className="text-2xl font-black tracking-tighter uppercase mb-2">Analyzing Document Integrity</h2>
           <p className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.3em]">AI Audit in Progress: {scanTimeLeft}s remaining</p>
           <div className="mt-12 max-w-xs text-center">
              <p className="text-xs font-medium text-indigo-200 italic opacity-60 line-clamp-2">Decrypting secure containers and identifying stock units for reconciliation...</p>
           </div>
        </div>
      )}

      {confirmDeleteTx && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
           <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
             <div className="text-center mb-8">
               <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">⚠️</div>
               <h4 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Purge Record?</h4>
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">This action is irreversible and affects capital calculation</p>
             </div>
             <div className="flex gap-3">
               <button onClick={() => setConfirmDeleteTx(null)} className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold text-[10px] uppercase rounded-2xl">Cancel</button>
               <button onClick={() => { deleteTransaction(confirmDeleteTx.id); setConfirmDeleteTx(null); }} className="flex-[2] py-4 bg-rose-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-rose-100">Delete Permanently</button>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction, FamilyMember, Notification } from '../types';
import { supabase } from '../lib/supabase';

interface FinanceContextType {
  state: FinancialState;
  filteredState: FinancialState;
  isAuthenticated: boolean;
  activeMemberIds: string[];
  isCloudSyncing: boolean;
  setActiveMemberIds: (ids: string[]) => void;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addFamilyMember: (member: FamilyMember) => Promise<{ success: boolean; syncedCount: number; error?: string }>;
  removeFamilyMember: (id: string) => void;
  toggleFamilyMemberTxPermission: (id: string) => void;
  addBank: (bank: BankAccount) => void;
  updateBank: (bank: BankAccount) => void;
  deleteBank: (id: string) => void;
  addCard: (card: CreditCard) => void;
  updateCard: (card: CreditCard) => void;
  deleteCard: (id: string) => void;
  addWallet: (wallet: Wallet) => void;
  updateWallet: (wallet: Wallet) => void;
  deleteWallet: (id: string) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  updateAsset: (asset: Asset) => void;
  deleteAsset: (id: string) => void;
  addLiability: (liability: Liability) => void;
  updateLiability: (liability: Liability) => void;
  deleteLiability: (id: string) => void;
  addTransaction: (transaction: Transaction) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addTransactionNature: (nature: string) => void;
  deleteTransactionNature: (nature: string) => void;
  clearNotifications: () => void;
  markNotificationRead: (id: string) => void;
  simulateSync: () => Promise<void>;
  resetBoarding: () => Promise<void>;
  loadStateFromCloud: (mobile: string) => Promise<boolean>;
  importState: (newState: FinancialState) => void;
}

const GLOBAL_SESSION_KEY = 'myfin_active_session';
const STATE_PREFIX = 'myfin_state_';

const initialState: FinancialState = {
  profile: { 
    name: '', 
    designation: '', 
    age: 0, 
    city: '', 
    country: 'India', 
    currency: 'INR', 
    mobileNumber: '',
    isBoarded: false, 
    familyMembers: [],
    cloudDatabaseName: 'Default_Vault'
  },
  banks: [],
  cards: [],
  wallets: [], 
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: [],
  transactions: [],
  notifications: [],
  transactionNatures: ['Salary', 'Grocery', 'Rent', 'Investment', 'Loan Repayment', 'Medical', 'Dining', 'Travel', 'Utilities', 'Investment in stocks', 'Other Charges'],
  capital: 0
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]);
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [activeMobile, setActiveMobile] = useState<string | null>(() => localStorage.getItem(GLOBAL_SESSION_KEY));

  const [state, setState] = useState<FinancialState>(() => {
    const mobile = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (mobile) {
      const saved = localStorage.getItem(`${STATE_PREFIX}${mobile}`);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          return { ...initialState, ...parsed };
        } catch (e) {
          return initialState;
        }
      }
    }
    return initialState;
  });

  useEffect(() => {
    if (state.profile.mobileNumber && state.profile.isBoarded) {
      localStorage.setItem(GLOBAL_SESSION_KEY, state.profile.mobileNumber);
      localStorage.setItem(`${STATE_PREFIX}${state.profile.mobileNumber}`, JSON.stringify(state));
    }
  }, [state]);

  useEffect(() => {
    const persistToSupabase = async () => {
      if (!state.profile.mobileNumber || !state.profile.isBoarded) return;

      setIsCloudSyncing(true);
      try {
        const { error } = await supabase
          .from('user_states')
          .upsert({ 
            mobile_number: state.profile.mobileNumber, 
            state: state,
            updated_at: new Date().toISOString()
          }, { onConflict: 'mobile_number' });

        if (error) console.error('Supabase Persist Error:', error);
      } catch (err) {
        console.error('Cloud sync failed:', err);
      } finally {
        setTimeout(() => setIsCloudSyncing(false), 500);
      }
    };

    const timeoutId = setTimeout(persistToSupabase, 2000);
    return () => clearTimeout(timeoutId);
  }, [state]);

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    const factor = isReversing ? -1 : 1;
    const totalAmount = (transaction.amount || 0) + (transaction.sharedAmount || 0);
    const balanceDelta = (transaction.type === 'Income' || transaction.type === 'Liability') ? totalAmount : -totalAmount;
    const finalBalanceDelta = balanceDelta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = (newState.banks || []).map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalBalanceDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.cards = (newState.cards || []).map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = (newState.wallets || []).map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalBalanceDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.liabilities = (newState.liabilities || []).map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }

    if (isReversing) {
      newState.incomes = (newState.incomes || []).filter(i => i.id !== transaction.id);
      newState.expenses = (newState.expenses || []).filter(e => e.id !== transaction.id);
      newState.assets = (newState.assets || []).filter(a => a.id !== transaction.id && !a.id.startsWith(transaction.id + '_shared'));
      newState.liabilities = (newState.liabilities || []).filter(l => l.id !== transaction.id && !l.id.startsWith(transaction.id + '_shared'));
    } else {
      const selfShare = transaction.amount;
      const sharedPortion = transaction.sharedAmount || 0;

      switch (transaction.type) {
        case 'Income':
          if (selfShare > 0) {
            newState.incomes.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, amount: selfShare, periodicity: 'Monthly', dateOfReceipt: transaction.date, ownerId: transaction.ownerId });
          }
          if (sharedPortion > 0) {
            newState.liabilities.push({ id: transaction.id + '_shared_payable', name: `Payable (Shared ${transaction.nature}): ${transaction.description}`, amount: sharedPortion, type: 'Payable', ownerId: transaction.ownerId });
          }
          break;
        case 'Expense':
          if (selfShare > 0) {
            newState.expenses.push({ id: transaction.id, category: transaction.nature, amount: selfShare, date: transaction.date, ownerId: transaction.ownerId });
          }
          if (sharedPortion > 0) {
            newState.assets.push({ id: transaction.id + '_shared_receivable', name: `Receivable (Shared ${transaction.nature}): ${transaction.description}`, value: sharedPortion, type: 'Receivable', ownerId: transaction.ownerId });
          }
          break;
        case 'Asset':
          // Automatic classification logic based on age (implemented in rendering/reporting level for dynamic behavior)
          newState.assets.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, value: transaction.amount, type: 'Physical', ownerId: transaction.ownerId });
          break;
        case 'Liability':
          newState.liabilities.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, amount: transaction.amount, type: 'Debt', ownerId: transaction.ownerId });
          break;
      }
    }
  };

  const addTransactionNature = (nature: string) => {
    setState(prev => {
      if (prev.transactionNatures.includes(nature)) return prev;
      return { ...prev, transactionNatures: [...prev.transactionNatures, nature] };
    });
  };

  const deleteTransactionNature = (nature: string) => {
    setState(prev => ({
      ...prev,
      transactionNatures: prev.transactionNatures.filter(n => n !== nature)
    }));
  };

  const loadStateFromCloud = async (mobile: string): Promise<boolean> => {
    try {
      const { data, error } = await supabase.from('user_states').select('state').eq('mobile_number', mobile).single();
      if (data && data.state) {
        setState({ ...initialState, ...data.state });
        setActiveMobile(mobile);
        localStorage.setItem(GLOBAL_SESSION_KEY, mobile);
        setAuthenticated(true);
        return true;
      }
      return false;
    } catch (err) {
      return false;
    }
  };

  const importState = (newState: FinancialState) => {
    if (newState && newState.profile && newState.profile.mobileNumber) {
      setState({ ...initialState, ...newState });
      setActiveMobile(newState.profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, newState.profile.mobileNumber);
      setAuthenticated(true);
    }
  };

  const updateProfile = (profile: UserProfile) => {
    setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));
    if (profile.mobileNumber) {
      setActiveMobile(profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, profile.mobileNumber);
    }
  };

  const addFamilyMember = async (member: FamilyMember): Promise<{ success: boolean; syncedCount: number; error?: string }> => {
    if (member.mobileNumber === state.profile.mobileNumber) return { success: false, syncedCount: 0, error: "Cannot link your own account." };
    if (state.profile.familyMembers.some(m => m.mobileNumber === member.mobileNumber)) return { success: false, syncedCount: 0, error: 'Member already linked.' };
    let syncedCount = 0;
    let memberData: any = null;
    try {
      const { data } = await supabase.from('user_states').select('state').eq('mobile_number', member.mobileNumber).single();
      if (data && data.state) memberData = data.state;
    } catch (err) {}
    setState(prev => {
      const newFamilyMembers = [...(prev.profile.familyMembers || []), { ...member, canAddTransactions: member.canAddTransactions ?? true }];
      if (!memberData) return { ...prev, profile: { ...prev.profile, familyMembers: newFamilyMembers } };
      const syncTag = (item: any) => ({ ...item, id: `${member.id}_${item.id}`, ownerId: member.id });
      const newBanks = (memberData.banks || []).map(syncTag);
      const newCards = (memberData.cards || []).map(syncTag);
      const newWallets = (memberData.wallets || []).map(syncTag);
      const newTransactions = (memberData.transactions || []).map(syncTag);
      const newIncomes = (memberData.incomes || []).map(syncTag);
      const newExpenses = (memberData.expenses || []).map(syncTag);
      const newAssets = (memberData.assets || []).map(syncTag);
      const newLiabilities = (memberData.liabilities || []).map(syncTag);
      syncedCount = newBanks.length + newCards.length + newWallets.length + newTransactions.length;
      return {
        ...prev,
        profile: { ...prev.profile, familyMembers: newFamilyMembers },
        banks: [...(prev.banks || []), ...newBanks],
        cards: [...(prev.cards || []), ...newCards],
        wallets: [...(prev.wallets || []), ...newWallets],
        transactions: [...(prev.transactions || []), ...newTransactions],
        incomes: [...(prev.incomes || []), ...newIncomes],
        expenses: [...(prev.expenses || []), ...newExpenses],
        assets: [...(prev.assets || []), ...newAssets],
        liabilities: [...(prev.liabilities || []), ...newLiabilities],
        capital: prev.capital + (memberData.capital || 0),
        notifications: [...(prev.notifications || []), {
          id: Math.random().toString(36).substr(2, 9),
          title: 'Family Sync Complete',
          message: `Linked ${member.name} and synced ${syncedCount} records.`,
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          type: 'sync',
          isRead: false
        }]
      };
    });
    return { success: true, syncedCount };
  };

  const removeFamilyMember = (id: string) => setState(prev => ({
    ...prev,
    profile: { ...prev.profile, familyMembers: (prev.profile.familyMembers || []).filter(m => m.id !== id) }
  }));

  const toggleFamilyMemberTxPermission = (id: string) => setState(prev => ({
    ...prev,
    profile: {
      ...prev.profile,
      familyMembers: prev.profile.familyMembers.map(m => m.id === id ? { ...m, canAddTransactions: !m.canAddTransactions } : m)
    }
  }));

  const addBank = (bank: BankAccount) => setState(prev => ({ 
    ...prev, 
    banks: [...(prev.banks || []), bank],
    capital: prev.capital + bank.balance 
  }));
  const updateBank = (bank: BankAccount) => setState(prev => {
    const old = prev.banks.find(b => b.id === bank.id);
    const diff = bank.balance - (old?.balance || 0);
    return { 
      ...prev, 
      banks: prev.banks.map(b => b.id === bank.id ? bank : b),
      capital: prev.capital + diff
    };
  });
  const deleteBank = (id: string) => setState(prev => {
    const old = prev.banks.find(b => b.id === id);
    return { 
      ...prev, 
      banks: prev.banks.filter(b => b.id !== id),
      capital: prev.capital - (old?.balance || 0)
    };
  });

  const addCard = (card: CreditCard) => setState(prev => ({ 
    ...prev, 
    cards: [...(prev.cards || []), card],
    capital: prev.capital - card.balance
  }));
  const updateCard = (card: CreditCard) => setState(prev => {
    const old = prev.cards.find(c => c.id === card.id);
    const diff = card.balance - (old?.balance || 0);
    return { 
      ...prev, 
      cards: prev.cards.map(c => c.id === card.id ? card : c),
      capital: prev.capital - diff
    };
  });
  const deleteCard = (id: string) => setState(prev => {
    const old = prev.cards.find(c => c.id === id);
    return { 
      ...prev, 
      cards: prev.cards.filter(c => c.id !== id),
      capital: prev.capital + (old?.balance || 0)
    };
  });

  const addWallet = (wallet: Wallet) => setState(prev => ({ 
    ...prev, 
    wallets: [...(prev.wallets || []), wallet],
    capital: prev.capital + wallet.balance
  }));
  const updateWallet = (wallet: Wallet) => setState(prev => {
    const old = prev.wallets.find(w => w.id === wallet.id);
    const diff = wallet.balance - (old?.balance || 0);
    return { 
      ...prev, 
      wallets: prev.wallets.map(w => w.id === wallet.id ? wallet : w),
      capital: prev.capital + diff
    };
  });
  const deleteWallet = (id: string) => setState(prev => {
    const old = prev.wallets.find(w => w.id === id);
    return { 
      ...prev, 
      wallets: prev.wallets.filter(w => w.id !== id),
      capital: prev.capital - (old?.balance || 0)
    };
  });

  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...prev.incomes, income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...prev.expenses, expense] }));

  const addAsset = (asset: Asset) => setState(prev => ({ 
    ...prev, 
    assets: [...prev.assets, asset],
    capital: prev.capital + asset.value
  }));
  const updateAsset = (asset: Asset) => setState(prev => {
    const old = prev.assets.find(a => a.id === asset.id);
    const diff = asset.value - (old?.value || 0);
    return { 
      ...prev, 
      assets: prev.assets.map(a => a.id === asset.id ? asset : a),
      capital: prev.capital + diff
    };
  });
  const deleteAsset = (id: string) => setState(prev => {
    const old = prev.assets.find(a => a.id === id);
    return { 
      ...prev, 
      assets: prev.assets.filter(a => a.id !== id),
      capital: prev.capital - (old?.value || 0)
    };
  });

  const addLiability = (liability: Liability) => setState(prev => ({ 
    ...prev, 
    liabilities: [...prev.liabilities, liability],
    capital: prev.capital - liability.amount
  }));
  const updateLiability = (liability: Liability) => setState(prev => {
    const old = prev.liabilities.find(l => l.id === liability.id);
    const diff = liability.amount - (old?.amount || 0);
    return { 
      ...prev, 
      liabilities: prev.liabilities.map(l => l.id === liability.id ? liability : l),
      capital: prev.capital - diff
    };
  });
  const deleteLiability = (id: string) => setState(prev => {
    const old = prev.liabilities.find(l => l.id === id);
    return { 
      ...prev, 
      liabilities: prev.liabilities.filter(l => l.id !== id),
      capital: prev.capital + (old?.amount || 0)
    };
  });

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...(prev.transactions || [])] };
      applyTransactionEffect(transaction, newState, false);
      return newState;
    });
  };

  const updateTransaction = (updatedTransaction: Transaction) => {
    setState(prev => {
      const oldTransaction = (prev.transactions || []).find(t => t.id === updatedTransaction.id);
      if (!oldTransaction) return prev;
      let newState = { ...prev };
      applyTransactionEffect(oldTransaction, newState, true);
      newState.transactions = (newState.transactions || []).map(t => t.id === updatedTransaction.id ? updatedTransaction : t);
      applyTransactionEffect(updatedTransaction, newState, false);
      return newState;
    });
  };

  const deleteTransaction = (id: string) => {
    setState(prev => {
      const transaction = (prev.transactions || []).find(t => t.id === id);
      if (!transaction) return prev;
      const newState = { ...prev, transactions: (prev.transactions || []).filter(t => t.id !== id) };
      applyTransactionEffect(transaction, newState, true);
      return newState;
    });
  };

  const clearNotifications = () => setState(prev => ({ ...prev, notifications: [] }));
  const markNotificationRead = (id: string) => setState(prev => ({
    ...prev,
    notifications: (prev.notifications || []).map(n => n.id === id ? { ...n, isRead: true } : n)
  }));

  const simulateSync = async () => {
    setState(prev => ({
      ...prev,
      notifications: [...(prev.notifications || []), {
        id: Math.random().toString(36).substr(2, 9),
        title: 'Cloud Sync Complete',
        message: 'Your ledger has been successfully synchronized with the cloud vault.',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        type: 'sync',
        isRead: false
      }]
    }));
  };

  const filteredState = useMemo(() => {
    if (activeMemberIds.includes('all')) return state;
    const isFiltered = activeMemberIds.length > 0;
    const filterIds = isFiltered ? activeMemberIds : [undefined, ''];
    const filterFn = (item: any) => filterIds.includes(item.ownerId || '');
    return {
      ...state,
      banks: (state.banks || []).filter(filterFn),
      cards: (state.cards || []).filter(filterFn),
      wallets: (state.wallets || []).filter(filterFn),
      incomes: (state.incomes || []).filter(filterFn),
      expenses: (state.expenses || []).filter(filterFn),
      assets: (state.assets || []).filter(filterFn),
      liabilities: (state.liabilities || []).filter(filterFn),
      transactions: (state.transactions || []).filter(filterFn),
    };
  }, [state, activeMemberIds]);

  const resetBoarding = async () => { 
    const mobile = state.profile.mobileNumber;
    if (mobile) {
      try {
        await supabase.from('user_states').delete().eq('mobile_number', mobile);
        localStorage.removeItem(`${STATE_PREFIX}${mobile}`);
      } catch (err) {
        console.error('Failed to purge cloud record during reset:', err);
      }
    }

    localStorage.removeItem(GLOBAL_SESSION_KEY);
    setState(initialState); 
    setAuthenticated(false); 
    setActiveMobile(null);
  };

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, isCloudSyncing, setActiveMemberIds, setAuthenticated, updateProfile, 
      addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission,
      addBank, updateBank, deleteBank, addCard, updateCard, deleteCard, addWallet, updateWallet, deleteWallet, 
      addIncome, addExpense, addAsset, updateAsset, deleteAsset, addLiability, updateLiability, deleteLiability,
      addTransaction, updateTransaction, deleteTransaction, addTransactionNature, deleteTransactionNature,
      clearNotifications, markNotificationRead, simulateSync, resetBoarding, loadStateFromCloud, importState
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';
import { GoogleGenAI } from "@google/genai";
import * as XLSX from 'xlsx';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  netTotal: number;
  units?: number;
  date?: string;
  isin?: string;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature, addWallet } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isIsinResolving, setIsIsinResolving] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(15);
  const [pdfPassword, setPdfPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [pendingFile, setPendingFile] = useState<File | null>(null);

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    finalSettlementAmount: number; 
    isSettlementPayable: boolean; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  const selectedAccount = useMemo(() => {
    return [...state.banks, ...state.cards, ...state.wallets, ...state.liabilities].find(a => a.id === formData.accountId);
  }, [formData.accountId, state]);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (formData.isin && formData.isin.length === 12 && !formData.stockName) {
        handleIsinLookup(formData.isin);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [formData.isin]);

  const handleIsinLookup = async (isin: string) => {
    setIsIsinResolving(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify the security/stock name for the following ISIN identifier: ${isin}. Return ONLY the official short name of the security. No preamble.`
      });
      const resolvedName = response.text?.trim() || 'Unknown Security';
      setFormData(prev => ({ 
        ...prev, 
        stockName: resolvedName,
        description: prev.description || resolvedName
      }));
    } catch (err) {
      console.error("ISIN Resolution failed:", err);
    } finally {
      setIsIsinResolving(false);
    }
  };

  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
    const zerodhaExists = [...state.banks, ...state.wallets].some(a => a.name.toLowerCase() === 'zerodha');
    if (!zerodhaExists) {
      addWallet({
        id: 'zerodha-account-auto',
        name: 'Zerodha',
        balance: 0,
        ownerId: ''
      });
    }
  }, []);

  useEffect(() => {
    let timer: number;
    if (isScanning && scanTimeLeft > 0) {
      timer = window.setInterval(() => {
        setScanTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isScanning, scanTimeLeft]);

  const downloadExcelTemplate = () => {
    const headers = [
      ["ISIN", "Date of transaction", "Quantity", "Buy/Sell", "Total Buy/Sell Value", "Total Charges excluding STT", "STT", "Net Payable/ Receivable"],
      ["INE002A01018", "2024-01-20", 10, "BUY", 10000, 20, 10, -10030],
      ["INE002A01018", "2024-01-22", 5, "SELL", -5500, 15, 5, 5480]
    ];

    const ws = XLSX.utils.aoa_to_sheet(headers);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Trades");
    XLSX.writeFile(wb, "MyFin_Broker_Import_Template.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.name.endsWith('.xlsx') || file.name.endsWith('.xls')) {
      handleExcelImport(file);
      return;
    }

    setPendingFile(file);
    setShowPasswordInput(true);
  };

  const handleExcelImport = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const rows: any[] = XLSX.utils.sheet_to_json(worksheet);

        if (rows.length === 0) {
          alert("Excel file is empty.");
          return;
        }

        const trades: ExtractedTrade[] = [];
        let totalOtherCharges = 0;
        let lastDate = new Date().toISOString().split('T')[0];

        rows.forEach((row: any) => {
          const isin = row['ISIN'] || '';
          let txDateRaw = row['Date of transaction'];

          // Handle SheetJS date objects or strings
          let formattedDate = lastDate;
          if (txDateRaw) {
            const d = new Date(txDateRaw);
            if (!isNaN(d.getTime())) {
              formattedDate = d.toISOString().split('T')[0];
            }
          }
          lastDate = formattedDate;

          const qty = Number(row['Quantity'] || 0);
          const type = (row['Buy/Sell'] || '').toUpperCase();
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const chargesExclSTT = Number(row['Total Charges excluding STT'] || 0);
          const stt = Number(row['STT'] || 0);

          trades.push({
            scrip: isin, 
            type: type === 'BUY' ? 'BUY' : 'SELL',
            netTotal: grossValue,
            units: qty,
            date: formattedDate,
            isin: isin
          });

          totalOtherCharges += (chargesExclSTT + stt);
        });

        setScanResult({
          date: lastDate,
          finalSettlementAmount: 0,
          isSettlementPayable: false,
          trades: trades,
          otherCharges: totalOtherCharges
        });

      } catch (err) {
        console.error(err);
        alert("Failed to parse Excel file. Ensure it follows the template format.");
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const startAIParsing = async () => {
    if (!pendingFile) return;
    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(18);

    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: pendingFile.type } },
              { text: `Extract data from this Zerodha Contract Note PDF. Return ONLY JSON: { "date": "YYYY-MM-DD", "isSettlementPayable": boolean, "finalSettlementAmount": number, "trades": [{"scrip": "string", "type": "BUY" | "SELL", "netTotal": number}], "otherCharges": number }` }
            ]
          },
          config: { responseMimeType: "application/json" }
        });
        const result = JSON.parse(response.text || '{}');
        if (result.date) setScanResult(result);
        else alert("Failed to parse document content.");
      } catch (err) {
        console.error(err);
        alert("Verification failed.");
      } finally {
        setIsScanning(false);
        setPdfPassword('');
        setPendingFile(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(pendingFile);
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;
    const zerodhaAccount = [...state.banks, ...state.wallets, ...state.cards].find(a => a.name.toLowerCase() === 'zerodha') || { id: 'zerodha-account-auto', type: 'wallet' };

    scanResult.trades.forEach(t => {
      addTransaction({
        id: Math.random().toString(36).substr(2, 9),
        type: t.type === 'BUY' ? 'Asset' : 'Income', 
        amount: t.netTotal,
        nature: 'Investment in stocks',
        description: `${t.type} ${t.scrip}`,
        accountId: zerodhaAccount.id,
        accountType: (zerodhaAccount as any).type || 'wallet',
        date: t.date || scanResult.date,
        ownerId: formData.ownerId,
        isin: t.isin,
        units: t.units
      });
    });

    if (scanResult.otherCharges > 0) {
      addTransaction({
        id: Math.random().toString(36).substr(2, 9),
        type: 'Expense',
        amount: scanResult.otherCharges,
        nature: 'Other Charges',
        description: `Broker Charges: ${scanResult.date}`,
        accountId: zerodhaAccount.id,
        accountType: (zerodhaAccount as any).type || 'wallet',
        date: scanResult.date,
        ownerId: formData.ownerId
      });
    }
    setScanResult(null);
  };

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, nature: natures[0] || '' });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      ...initialFormState,
      type: t.type,
      amount: String(t.amount),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      ownerId: t.ownerId || '',
      isin: t.isin || '',
      stockName: t.stockName || '',
      units: t.units ? String(t.units) : '',
      billingPeriod: t.billingPeriod || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: Number(formData.amount),
      nature: formData.nature,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      ownerId: formData.ownerId,
      isin: formData.isin,
      stockName: formData.stockName,
      units: formData.units ? Number(formData.units) : undefined,
      billingPeriod: formData.billingPeriod
    };
    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight uppercase">Audit Ledger</h3>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-2">Verified Transaction History</p>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:flex lg:flex-wrap items-center gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*,.pdf,.xlsx,.xls" onChange={handleFileUpload} />
          <div className="flex flex-col gap-1 items-center col-span-2 md:col-span-1">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="w-full px-4 lg:px-6 py-3 lg:py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-slate-800 transition-all shadow-xl active:scale-95"
            >
              <span>📄</span> Broker Import
            </button>
            <button 
              onClick={downloadExcelTemplate}
              className="text-[8px] font-black text-indigo-500 uppercase tracking-widest hover:underline px-2"
            >
              Download Excel Template
            </button>
          </div>
          <button onClick={() => handleOpenModal('Income')} className="px-4 py-3 lg:py-4 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-4 py-3 lg:py-4 bg-rose-50 text-rose-500 border border-rose-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-4 py-3 lg:py-4 bg-white text-indigo-600 border border-indigo-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-4 py-3 lg:py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Debt</button>
        </div>
      </div>

      {scanResult && (
        <div className="bg-indigo-900 text-white p-6 md:p-10 rounded-[2.5rem] shadow-2xl animate-in slide-in-from-top-10 duration-500 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 text-8xl opacity-10 font-black">IMPORT</div>
          <div className="relative z-10">
            <h4 className="text-sm font-black uppercase tracking-widest mb-6 border-b border-white/10 pb-4 flex items-center gap-3">
              <span className="text-2xl">📋</span> Verify Extracted Ledger
            </h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="space-y-6">
                <div>
                  <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-1">Audit Timeline</p>
                  <p className="text-2xl font-black">{scanResult.date}</p>
                </div>
                <div className="bg-white/5 p-6 rounded-3xl border border-white/10">
                   <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-4">Trade Summary</p>
                   <div className="space-y-4">
                     {scanResult.trades.map((t, i) => (
                       <div key={i} className="flex justify-between items-center border-b border-white/5 pb-2 last:border-0 last:pb-0">
                         <div>
                           <p className="text-xs font-black uppercase tracking-tight">{t.scrip}</p>
                           <p className="text-[8px] font-black text-indigo-400 uppercase">{t.type} {t.units ? `• ${t.units} Units` : ''} • {t.date || scanResult.date}</p>
                         </div>
                         <p className="text-sm font-black">{formatCurrency(t.netTotal, currency)}</p>
                       </div>
                     ))}
                   </div>
                </div>
              </div>
              <div className="flex flex-col justify-between">
                <div className="space-y-4">
                  <div className="flex justify-between items-center p-4 bg-white/5 rounded-2xl">
                    <span className="text-[10px] font-black uppercase">Other Charges</span>
                    <span className="text-sm font-black">{formatCurrency(scanResult.otherCharges, currency)}</span>
                  </div>
                  <div className="flex justify-between items-center p-6 bg-indigo-800 rounded-3xl border border-white/10 shadow-xl">
                    <span className="text-[10px] font-black uppercase">Net Settlement</span>
                    <p className={`text-2xl font-black ${scanResult.isSettlementPayable ? 'text-rose-400' : 'text-emerald-400'}`}>
                      {scanResult.isSettlementPayable ? '-' : '+'} {formatCurrency(scanResult.finalSettlementAmount || scanResult.trades.reduce((acc, t) => acc + t.netTotal, 0) + scanResult.otherCharges, currency)}
                    </p>
                  </div>
                </div>
                <div className="flex gap-4 mt-10">
                  <button onClick={() => setScanResult(null)} className="flex-1 py-5 bg-white/10 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-white/20 transition-all">Reject</button>
                  <button onClick={commitScannedTrade} className="flex-[2] py-5 bg-emerald-500 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-emerald-900/40 hover:bg-emerald-600 transition-all active:scale-95">Commit to Vault</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[800px] lg:min-w-full">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Timeline</th>
                <th className="px-8 py-6">Audit Nature</th>
                <th className="px-8 py-6">Entity Claims</th>
                <th className="px-8 py-6 text-right">Settlement</th>
