};

export default Statements;

export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';
export type AccountClassification = 'Current Asset' | 'Non-Current Asset' | 'Current Liability' | 'Non-Current Liability' | 'Equity';

export interface FamilyMember {
  id: string;
  name: string;
  relation: string;
  mobileNumber: string;
  canAddTransactions?: boolean;
}

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
  familyMembers: FamilyMember[];
  cloudDatabaseName?: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  timestamp: string;
  type: 'transaction' | 'system' | 'sync';
  isRead: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
  ownerId?: string;
  accountType?: 'Savings' | 'Current' | 'Salary' | 'Others';
  customAccountType?: string;
  classification?: AccountClassification;
}

export interface CreditCardOtherBenefit {
  condition: string;
  benefitName: string;
  linkedNatures: string[];
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number;
  last4: string;
  limit?: number;
  annualLimit?: number; 
  anniversaryDate?: string;
  billingDay?: number;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
  ownerId?: string;
  classification?: AccountClassification;
  // NEW BENEFIT FIELDS
  cashbackPct?: number;
  movieOffers?: {
    onePlusOne: boolean;
    amountBased: number;
  };
  loungeAccess?: {
    count: number;
    spendLimit: number;
    period: string;
  };
  fuelSurchargeWaiver?: boolean;
  forexMarkup?: number;
  pointsConversion?: string;
  otherBenefits?: CreditCardOtherBenefit[];
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
  ownerId?: string;
  classification?: AccountClassification;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
  ownerId?: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  periodicity?: Periodicity;
  ownerId?: string;
}

export interface Asset {
  id: string;
  name: string;
  value: number;
  type?: 'Physical' | 'Receivable';
  ownerId?: string;
  classification?: AccountClassification;
  isin?: string;
  units?: number;
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
  type?: 'Debt' | 'Payable';
  ownerId?: string;
  classification?: AccountClassification;
}

export type TransactionType = 'Income' | 'Expense' | 'Asset' | 'Liability';

export interface SharedContact {
  name: string;
  mobile: string;
  amount: number;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  nature: string; 
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet' | 'liability';
  date: string;
  category?: string;
  isShared?: boolean;
  sharedAmount?: number;
  numberOfPeople?: number;
  includeSelf?: boolean;
  sharedContacts?: SharedContact[];
  ownerId?: string; 
  isin?: string;
  stockName?: string;
  units?: number; // New field for tracking quantity of units
  billingPeriod?: string; 
  isSettled?: boolean;
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
  notifications: Notification[];
  transactionNatures: string[]; 
  capital: number; 
}

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction, FamilyMember, Notification } from '../types';
import { supabase } from '../lib/supabase';

interface FinanceContextType {
  state: FinancialState;
  filteredState: FinancialState;
  isAuthenticated: boolean;
  activeMemberIds: string[];
  isCloudSyncing: boolean;
  setActiveMemberIds: (ids: string[]) => void;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addFamilyMember: (member: FamilyMember) => Promise<{ success: boolean; syncedCount: number; error?: string }>;
  removeFamilyMember: (id: string) => void;
  toggleFamilyMemberTxPermission: (id: string) => void;
  addBank: (bank: BankAccount) => void;
  updateBank: (bank: BankAccount) => void;
  deleteBank: (id: string) => void;
  addCard: (card: CreditCard) => void;
  updateCard: (card: CreditCard) => void;
  deleteCard: (id: string) => void;
  addWallet: (wallet: Wallet) => void;
  updateWallet: (wallet: Wallet) => void;
  deleteWallet: (id: string) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  updateAsset: (asset: Asset) => void;
  deleteAsset: (id: string) => void;
  addLiability: (liability: Liability) => void;
  updateLiability: (liability: Liability) => void;
  deleteLiability: (id: string) => void;
  addTransaction: (transaction: Transaction) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addTransactionNature: (nature: string) => void;
  deleteTransactionNature: (nature: string) => void;
  clearNotifications: () => void;
  markNotificationRead: (id: string) => void;
  simulateSync: () => Promise<void>;
  resetBoarding: () => Promise<void>;
  loadStateFromCloud: (mobile: string) => Promise<boolean>;
  importState: (newState: FinancialState) => void;
}

const GLOBAL_SESSION_KEY = 'myfin_active_session';
const STATE_PREFIX = 'myfin_state_';

const initialState: FinancialState = {
  profile: { 
    name: '', 
    designation: '', 
    age: 0, 
    city: '', 
    country: 'India', 
    currency: 'INR', 
    mobileNumber: '',
    isBoarded: false, 
    familyMembers: [],
    cloudDatabaseName: 'Default_Vault'
  },
  banks: [],
  cards: [],
  wallets: [], 
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: [],
  transactions: [],
  notifications: [],
  transactionNatures: ['Salary', 'Grocery', 'Rent', 'Investment', 'Loan Repayment', 'Medical', 'Dining', 'Travel', 'Utilities', 'Investment in stocks', 'Other Charges'],
  capital: 0
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]);
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [activeMobile, setActiveMobile] = useState<string | null>(() => localStorage.getItem(GLOBAL_SESSION_KEY));

  const [state, setState] = useState<FinancialState>(() => {
    const mobile = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (mobile) {
      const saved = localStorage.getItem(`${STATE_PREFIX}${mobile}`);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          return { ...initialState, ...parsed };
        } catch (e) {
          return initialState;
        }
      }
    }
    return initialState;
  });

  useEffect(() => {
    if (state.profile.mobileNumber && state.profile.isBoarded) {
      localStorage.setItem(GLOBAL_SESSION_KEY, state.profile.mobileNumber);
      localStorage.setItem(`${STATE_PREFIX}${state.profile.mobileNumber}`, JSON.stringify(state));
    }
  }, [state]);

  useEffect(() => {
    const persistToSupabase = async () => {
      if (!state.profile.mobileNumber || !state.profile.isBoarded) return;

      setIsCloudSyncing(true);
      try {
        const { error } = await supabase
          .from('user_states')
          .upsert({ 
            mobile_number: state.profile.mobileNumber, 
            state: state,
            updated_at: new Date().toISOString()
          }, { onConflict: 'mobile_number' });

        if (error) console.error('Supabase Persist Error:', error);
      } catch (err) {
        console.error('Cloud sync failed:', err);
      } finally {
        setTimeout(() => setIsCloudSyncing(false), 500);
      }
    };

    const timeoutId = setTimeout(persistToSupabase, 2000);
    return () => clearTimeout(timeoutId);
  }, [state]);

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    const factor = isReversing ? -1 : 1;
    const totalAmount = (transaction.amount || 0) + (transaction.sharedAmount || 0);
    const balanceDelta = (transaction.type === 'Income' || transaction.type === 'Liability') ? totalAmount : -totalAmount;
    const finalBalanceDelta = balanceDelta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = (newState.banks || []).map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalBalanceDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.cards = (newState.cards || []).map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = (newState.wallets || []).map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalBalanceDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.liabilities = (newState.liabilities || []).map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }

    if (isReversing) {
      newState.incomes = (newState.incomes || []).filter(i => i.id !== transaction.id);
      newState.expenses = (newState.expenses || []).filter(e => e.id !== transaction.id);
      newState.assets = (newState.assets || []).filter(a => a.id !== transaction.id && !a.id.startsWith(transaction.id + '_shared'));
      newState.liabilities = (newState.liabilities || []).filter(l => l.id !== transaction.id && !l.id.startsWith(transaction.id + '_shared'));
    } else {
      const selfShare = transaction.amount;
      const sharedPortion = transaction.sharedAmount || 0;

      switch (transaction.type) {
        case 'Income':
          if (selfShare > 0) {
            newState.incomes.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, amount: selfShare, periodicity: 'Monthly', dateOfReceipt: transaction.date, ownerId: transaction.ownerId });
          }
          if (sharedPortion > 0) {
            newState.liabilities.push({ id: transaction.id + '_shared_payable', name: `Payable (Shared ${transaction.nature}): ${transaction.description}`, amount: sharedPortion, type: 'Payable', ownerId: transaction.ownerId });
          }
          break;
        case 'Expense':
          if (selfShare > 0) {
            newState.expenses.push({ id: transaction.id, category: transaction.nature, amount: selfShare, date: transaction.date, ownerId: transaction.ownerId });
          }
          if (sharedPortion > 0) {
            newState.assets.push({ id: transaction.id + '_shared_receivable', name: `Receivable (Shared ${transaction.nature}): ${transaction.description}`, value: sharedPortion, type: 'Receivable', ownerId: transaction.ownerId });
          }
          break;
        case 'Asset':
          newState.assets.push({ 
            id: transaction.id, 
            name: `${transaction.nature}: ${transaction.description}`, 
            value: transaction.amount, 
            type: 'Physical', 
            ownerId: transaction.ownerId,
            isin: transaction.isin,
            units: transaction.units
          });
          break;
        case 'Liability':
          newState.liabilities.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, amount: transaction.amount, type: 'Debt', ownerId: transaction.ownerId });
          break;
      }
    }
  };

  const addTransactionNature = (nature: string) => {
    setState(prev => {
      if (prev.transactionNatures.includes(nature)) return prev;
      return { ...prev, transactionNatures: [...prev.transactionNatures, nature] };
    });
  };

  const deleteTransactionNature = (nature: string) => {
    setState(prev => ({
      ...prev,
      transactionNatures: prev.transactionNatures.filter(n => n !== nature)
    }));
  };

  const loadStateFromCloud = async (mobile: string): Promise<boolean> => {
    try {
      const { data, error } = await supabase.from('user_states').select('state').eq('mobile_number', mobile).single();
      if (data && data.state) {
        setState({ ...initialState, ...data.state });
        setActiveMobile(mobile);
        localStorage.setItem(GLOBAL_SESSION_KEY, mobile);
        setAuthenticated(true);
        return true;
      }
      return false;
    } catch (err) {
      return false;
    }
  };

  const importState = (newState: FinancialState) => {
    if (newState && newState.profile && newState.profile.mobileNumber) {
      setState({ ...initialState, ...newState });
      setActiveMobile(newState.profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, newState.profile.mobileNumber);
      setAuthenticated(true);
    }
  };

  const updateProfile = (profile: UserProfile) => {
    setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));
    if (profile.mobileNumber) {
      setActiveMobile(profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, profile.mobileNumber);
    }
  };

  const addFamilyMember = async (member: FamilyMember): Promise<{ success: boolean; syncedCount: number; error?: string }> => {
    if (member.mobileNumber === state.profile.mobileNumber) return { success: false, syncedCount: 0, error: "Cannot link your own account." };
    if (state.profile.familyMembers.some(m => m.mobileNumber === member.mobileNumber)) return { success: false, syncedCount: 0, error: 'Member already linked.' };
    let syncedCount = 0;
    let memberData: any = null;
    try {
      const { data } = await supabase.from('user_states').select('state').eq('mobile_number', member.mobileNumber).single();
      if (data && data.state) memberData = data.state;
    } catch (err) {}
    setState(prev => {
      const newFamilyMembers = [...(prev.profile.familyMembers || []), { ...member, canAddTransactions: member.canAddTransactions ?? true }];
      if (!memberData) return { ...prev, profile: { ...prev.profile, familyMembers: newFamilyMembers } };
      const syncTag = (item: any) => ({ ...item, id: `${member.id}_${item.id}`, ownerId: member.id });
      const newBanks = (memberData.banks || []).map(syncTag);
      const newCards = (memberData.cards || []).map(syncTag);
      const newWallets = (memberData.wallets || []).map(syncTag);
      const newTransactions = (memberData.transactions || []).map(syncTag);
      const newIncomes = (memberData.incomes || []).map(syncTag);
      const newExpenses = (memberData.expenses || []).map(syncTag);
      const newAssets = (memberData.assets || []).map(syncTag);
      const newLiabilities = (memberData.liabilities || []).map(syncTag);
      syncedCount = newBanks.length + newCards.length + newWallets.length + newTransactions.length;
      return {
        ...prev,
        profile: { ...prev.profile, familyMembers: newFamilyMembers },
        banks: [...(prev.banks || []), ...newBanks],
        cards: [...(prev.cards || []), ...newCards],
        wallets: [...(prev.wallets || []), ...newWallets],
        transactions: [...(prev.transactions || []), ...newTransactions],
        incomes: [...(prev.incomes || []), ...newIncomes],
        expenses: [...(prev.expenses || []), ...newExpenses],
        assets: [...(prev.assets || []), ...newAssets],
        liabilities: [...(prev.liabilities || []), ...newLiabilities],
        capital: prev.capital + (memberData.capital || 0),
        notifications: [...(prev.notifications || []), {
          id: Math.random().toString(36).substr(2, 9),
          title: 'Family Sync Complete',
          message: `Linked ${member.name} and synced ${syncedCount} records.`,
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          type: 'sync',
          isRead: false
        }]
      };
    });
    return { success: true, syncedCount };
  };

  const removeFamilyMember = (id: string) => setState(prev => ({
    ...prev,
    profile: { ...prev.profile, familyMembers: (prev.profile.familyMembers || []).filter(m => m.id !== id) }
  }));

  const toggleFamilyMemberTxPermission = (id: string) => setState(prev => ({
    ...prev,
    profile: {
      ...prev.profile,
      familyMembers: prev.profile.familyMembers.map(m => m.id === id ? { ...m, canAddTransactions: !m.canAddTransactions } : m)
    }
  }));

  const addBank = (bank: BankAccount) => setState(prev => ({ 
    ...prev, 
    banks: [...(prev.banks || []), bank],
    capital: prev.capital + bank.balance 
  }));
  const updateBank = (bank: BankAccount) => setState(prev => {
    const old = prev.banks.find(b => b.id === bank.id);
    const diff = bank.balance - (old?.balance || 0);
    return { 
      ...prev, 
      banks: prev.banks.map(b => b.id === bank.id ? bank : b),
      capital: prev.capital + diff
    };
  });
  const deleteBank = (id: string) => setState(prev => {
    const old = prev.banks.find(b => b.id === id);
    return { 
      ...prev, 
      banks: prev.banks.filter(b => b.id !== id),
      capital: prev.capital - (old?.balance || 0)
    };
  });

  const addCard = (card: CreditCard) => setState(prev => ({ 
    ...prev, 
    cards: [...(prev.cards || []), card],
    capital: prev.capital - card.balance
  }));
  const updateCard = (card: CreditCard) => setState(prev => {
    const old = prev.cards.find(c => c.id === card.id);
    const diff = card.balance - (old?.balance || 0);
    return { 
      ...prev, 
      cards: prev.cards.map(c => c.id === card.id ? card : c),
      capital: prev.capital - diff
    };
  });
  const deleteCard = (id: string) => setState(prev => {
    const old = prev.cards.find(c => c.id === id);
    return { 
      ...prev, 
      cards: prev.cards.filter(c => c.id !== id),
      capital: prev.capital + (old?.balance || 0)
    };
  });

  const addWallet = (wallet: Wallet) => setState(prev => ({ 
    ...prev, 
    wallets: [...(prev.wallets || []), wallet],
    capital: prev.capital + wallet.balance
  }));
  const updateWallet = (wallet: Wallet) => setState(prev => {
    const old = prev.wallets.find(w => w.id === wallet.id);
    const diff = wallet.balance - (old?.balance || 0);
    return { 
      ...prev, 
      wallets: prev.wallets.map(w => w.id === wallet.id ? wallet : w),
      capital: prev.capital + diff
    };
  });
  const deleteWallet = (id: string) => setState(prev => {
    const old = prev.wallets.find(w => w.id === id);
    return { 
      ...prev, 
      wallets: prev.wallets.filter(w => w.id !== id),
      capital: prev.capital - (old?.balance || 0)
    };
  });

  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...prev.incomes, income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...prev.expenses, expense] }));

  const addAsset = (asset: Asset) => setState(prev => ({ 
    ...prev, 
    assets: [...prev.assets, asset],
    capital: prev.capital + asset.value
  }));
  const updateAsset = (asset: Asset) => setState(prev => {
    const old = prev.assets.find(a => a.id === asset.id);
    const diff = asset.value - (old?.value || 0);
    return { 
      ...prev, 
      assets: prev.assets.map(a => a.id === asset.id ? asset : a),
      capital: prev.capital + diff
    };
  });
  const deleteAsset = (id: string) => setState(prev => {
    const old = prev.assets.find(a => a.id === id);
    return { 
      ...prev, 
      assets: prev.assets.filter(a => a.id !== id),
      capital: prev.capital - (old?.value || 0)
    };
  });

  const addLiability = (liability: Liability) => setState(prev => ({ 
    ...prev, 
    liabilities: [...prev.liabilities, liability],
    capital: prev.capital - liability.amount
  }));
  const updateLiability = (liability: Liability) => setState(prev => {
    const old = prev.liabilities.find(l => l.id === liability.id);
    const diff = liability.amount - (old?.amount || 0);
    return { 
      ...prev, 
      liabilities: prev.liabilities.map(l => l.id === liability.id ? liability : l),
      capital: prev.capital - diff
    };
  });
  const deleteLiability = (id: string) => setState(prev => {
    const old = prev.liabilities.find(l => l.id === id);
    return { 
      ...prev, 
      liabilities: prev.liabilities.filter(l => l.id !== id),
      capital: prev.capital + (old?.amount || 0)
    };
  });

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...(prev.transactions || [])] };
      applyTransactionEffect(transaction, newState, false);
      return newState;
    });
  };

  const updateTransaction = (updatedTransaction: Transaction) => {
    setState(prev => {
      const oldTransaction = (prev.transactions || []).find(t => t.id === updatedTransaction.id);
      if (!oldTransaction) return prev;
      let newState = { ...prev };
      applyTransactionEffect(oldTransaction, newState, true);
      newState.transactions = (newState.transactions || []).map(t => t.id === updatedTransaction.id ? updatedTransaction : t);
      applyTransactionEffect(updatedTransaction, newState, false);
      return newState;
    });
  };

  const deleteTransaction = (id: string) => {
    setState(prev => {
      const transaction = (prev.transactions || []).find(t => t.id === id);
      if (!transaction) return prev;
      const newState = { ...prev, transactions: (prev.transactions || []).filter(t => t.id !== id) };
      applyTransactionEffect(transaction, newState, true);
      return newState;
    });
  };

  const clearNotifications = () => setState(prev => ({ ...prev, notifications: [] }));
  const markNotificationRead = (id: string) => setState(prev => ({
    ...prev,
    notifications: (prev.notifications || []).map(n => n.id === id ? { ...n, isRead: true } : n)
  }));

  const simulateSync = async () => {
    setState(prev => ({
      ...prev,
      notifications: [...(prev.notifications || []), {
        id: Math.random().toString(36).substr(2, 9),
        title: 'Cloud Sync Complete',
        message: 'Your ledger has been successfully synchronized with the cloud vault.',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        type: 'sync',
        isRead: false
      }]
    }));
  };

  const filteredState = useMemo(() => {
    if (activeMemberIds.includes('all')) return state;
    const isFiltered = activeMemberIds.length > 0;
    const filterIds = isFiltered ? activeMemberIds : [undefined, ''];
    const filterFn = (item: any) => filterIds.includes(item.ownerId || '');
    return {
      ...state,
      banks: (state.banks || []).filter(filterFn),
      cards: (state.cards || []).filter(filterFn),
      wallets: (state.wallets || []).filter(filterFn),
      incomes: (state.incomes || []).filter(filterFn),
      expenses: (state.expenses || []).filter(filterFn),
      assets: (state.assets || []).filter(filterFn),
      liabilities: (state.liabilities || []).filter(filterFn),
      transactions: (state.transactions || []).filter(filterFn),
    };
  }, [state, activeMemberIds]);

  const resetBoarding = async () => { 
    const mobile = state.profile.mobileNumber;
    if (mobile) {
      try {
        await supabase.from('user_states').delete().eq('mobile_number', mobile);
        localStorage.removeItem(`${STATE_PREFIX}${mobile}`);
      } catch (err) {
        console.error('Failed to purge cloud record during reset:', err);
      }
    }

    localStorage.removeItem(GLOBAL_SESSION_KEY);
    setState(initialState); 
    setAuthenticated(false); 
    setActiveMobile(null);
  };

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, isCloudSyncing, setActiveMemberIds, setAuthenticated, updateProfile, 
      addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission,
      addBank, updateBank, deleteBank, addCard, updateCard, deleteCard, addWallet, updateWallet, deleteWallet, 
      addIncome, addExpense, addAsset, updateAsset, deleteAsset, addLiability, updateLiability, deleteLiability,
      addTransaction, updateTransaction, deleteTransaction, addTransactionNature, deleteTransactionNature,
      clearNotifications, markNotificationRead, simulateSync, resetBoarding, loadStateFromCloud, importState
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { calculateNetWorth } from '../utils/calculations';
import { formatCurrency } from '../utils/formatters';
import { AccountClassification } from '../types';
import { TransactionHistoryModal } from './Accounts';

type Period = 'current_month' | 'last_90_days' | 'ytd' | 'all_time' | 'custom';

const Statements: React.FC = () => {
  const { state, filteredState, activeMemberIds } = useFinance();
  const [activePeriod, setActivePeriod] = useState<Period>('all_time');

  // Custom Date States for Calendar Selection
  const [customStart, setCustomStart] = useState(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [customEnd, setCustomEnd] = useState(new Date().toISOString().split('T')[0]);

  const [expandedHeads, setExpandedHeads] = useState<string[]>(['Current Asset', 'Equity']);
  const [selectedAccountForHistory, setSelectedAccountForHistory] = useState<any>(null);
  const currency = filteredState.profile.currency;

  const filteredTransactions = useMemo(() => {
    const txs = filteredState.transactions || [];
    const now = new Date();

    if (activePeriod === 'current_month') {
      const start = new Date(now.getFullYear(), now.getMonth(), 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'last_90_days') {
      const start = new Date();
      start.setDate(now.getDate() - 90);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'ytd') {
      const start = new Date(now.getFullYear(), 0, 1);
      return txs.filter(t => new Date(t.date) >= start);
    }
    if (activePeriod === 'custom') {
      const start = new Date(customStart);
      const end = new Date(customEnd);
      end.setHours(23, 59, 59, 999);
      return txs.filter(t => {
        const d = new Date(t.date);
        return d >= start && d <= end;
      });
    }
    return txs;
  }, [filteredState.transactions, activePeriod, customStart, customEnd]);

  const periodIncome = filteredTransactions.filter(t => t.type === 'Income').reduce((acc, t) => acc + t.amount, 0);
  const periodExpense = filteredTransactions.filter(t => t.type === 'Expense').reduce((acc, t) => acc + t.amount, 0);
  const netSurplus = periodIncome - periodExpense;

  const { netWorth } = calculateNetWorth(filteredState);

  const isAllView = activeMemberIds.includes('all');
  const isMeView = activeMemberIds.length === 0;
  const isConsolidatedView = isAllView || activeMemberIds.length > 1;

  const capitalDisplay = isAllView ? state.capital : (isMeView ? state.capital : 0);
  const retainedEarnings = netWorth - capitalDisplay;

  // Balance Sheet Data Structuring with Auto-Reclassification and Stock Clubbing
  const heads = useMemo(() => {
    const data: Record<AccountClassification, { total: number, items: { id: string, name: string, value: number, source: string, originalAccount?: any, details?: string }[] }> = {
      'Current Asset': { total: 0, items: [] },
      'Non-Current Asset': { total: 0, items: [] },
      'Current Liability': { total: 0, items: [] },
      'Non-Current Liability': { total: 0, items: [] },
      'Equity': { total: 0, items: [] }
    };

    const now = new Date();

    // Intermediate storage for stocks to club them
    const stocksByClassification: Record<string, { value: number, units: number, count: number }> = {
      'Current Asset': { value: 0, units: 0, count: 0 },
      'Non-Current Asset': { value: 0, units: 0, count: 0 }
    };

    const processAccount = (id: string, name: string, balance: number, classification: AccountClassification, source: string, originalAccount: any) => {
      let cls = classification;
      let val = balance;
      const isAssetType = cls === 'Current Asset' || cls === 'Non-Current Asset';
      const isLiabilityType = cls === 'Current Liability' || cls === 'Non-Current Liability';

      // Find purchase date for assets to classify Current vs Non-Current
      let entryDate = now;
      const tx = state.transactions.find(t => t.id === id);
      if (tx) {
        entryDate = new Date(tx.date);
      }

      if (isAssetType && source !== 'Bank' && source !== 'Wallet') {
        const diffTime = Math.abs(now.getTime() - entryDate.getTime());
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        cls = diffDays > 365 ? 'Non-Current Asset' : 'Current Asset';
      }

      if (val < 0 && isAssetType) {
        cls = 'Current Liability';
        val = Math.abs(val);
      } else if (val < 0 && isLiabilityType) {
        cls = 'Current Asset';
        val = Math.abs(val);
      }

      // Logic to club stock investments
      const isStock = tx && tx.nature === 'Investment in stocks';
      if (isStock && (cls === 'Current Asset' || cls === 'Non-Current Asset')) {
        stocksByClassification[cls].value += val;
        stocksByClassification[cls].units += (tx.units || 0);
        stocksByClassification[cls].count += 1;
        // We don't push to data[cls].items yet, we wait to add the clubbed line
      } else {
        data[cls].total += val;
        data[cls].items.push({ id, name, value: val, source, originalAccount });
      }
    };

    filteredState.banks.forEach(b => processAccount(b.id, b.name, b.balance, b.classification || 'Current Asset', 'Bank', b));
    filteredState.wallets.forEach(w => processAccount(w.id, w.name, w.balance, w.classification || 'Current Asset', 'Wallet', w));
    filteredState.cards.forEach(c => processAccount(c.id, c.lenderName, c.balance, c.classification || 'Current Liability', 'Credit', c));
    filteredState.assets.forEach(a => processAccount(a.id, a.name, a.value, a.classification || (a.type === 'Receivable' ? 'Current Asset' : 'Non-Current Asset'), 'Manual Asset', a));
    filteredState.liabilities.forEach(l => processAccount(l.id, l.name, l.amount, l.classification || (l.type === 'Payable' ? 'Current Liability' : 'Non-Current Liability'), 'Manual Debt', l));

    // Add clubbed stocks to the final data
    (['Current Asset', 'Non-Current Asset'] as const).forEach(cls => {
      const stockData = stocksByClassification[cls];
      if (stockData.count > 0) {
        data[cls].total += stockData.value;
        data[cls].items.push({ 
          id: `clubbed_stocks_${cls}`, 
          name: 'Equity Investments', 
          value: stockData.value, 
          source: 'Brokerage',
          details: `${stockData.units.toLocaleString()} Shares across ${stockData.count} trades`
        });
      }
    });

    data['Equity'].total = capitalDisplay + retainedEarnings;
    data['Equity'].items.push({ id: 'owner_cap', name: 'Owner Capital', value: capitalDisplay, source: 'Equity' });
    data['Equity'].items.push({ id: 'retained_earning', name: 'Retained Earnings', value: retainedEarnings, source: 'Equity' });

    return data;
  }, [filteredState, state.transactions, capitalDisplay, retainedEarnings]);

  const toggleHead = (head: string) => {
    setExpandedHeads(prev => prev.includes(head) ? prev.filter(h => h !== head) : [...prev, head]);
  };

  const totalAssetsValue = heads['Current Asset'].total + heads['Non-Current Asset'].total;
  const totalLiabilitiesAndEquityValue = heads['Current Liability'].total + heads['Non-Current Liability'].total + heads['Equity'].total;
  const liquidityRatio = heads['Current Liability'].total > 0 ? (heads['Current Asset'].total / heads['Current Liability'].total).toFixed(2) : '∞';

  const assetHeader = isMeView ? "Total Assets" : (isConsolidatedView ? "Consolidated Assets" : "Assigned Assets");
  const liabilityHeader = isMeView ? "Total Equity and Liabilities" : (isConsolidatedView ? "Consolidated Equity and Liabilities" : "Total Claims & Equity");

  return (
    <div className="space-y-8 md:space-y-12 animate-in fade-in duration-700 pb-20 -mx-3 md:mx-0">
      {/* Header & Period Selection */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-6 px-4 md:px-0">
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h2 className="text-xl md:text-3xl font-black text-slate-800 tracking-tight uppercase">Audit Statements</h2>
            <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[8px] md:text-[10px] font-black rounded uppercase tracking-widest border border-indigo-100">Live Reports</span>
          </div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
            {isMeView ? 'Personal Position (Mine)' : isConsolidatedView ? 'Consolidated Family View' : 'Partial Selection'}
          </p>
        </div>

        <div className="flex flex-col md:flex-row items-stretch md:items-center gap-4 w-full md:w-auto">
          {activePeriod === 'custom' && (
            <div className="flex items-center gap-2 bg-white p-2 border border-slate-200 rounded-2xl shadow-sm animate-in slide-in-from-right-4">
              <input type="date" value={customStart} onChange={e => setCustomStart(e.target.value)} className="bg-transparent border-0 text-[10px] font-black uppercase outline-none" />
              <span className="text-[10px] font-black text-slate-300 px-1">➜</span>
              <input type="date" value={customEnd} onChange={e => setCustomEnd(e.target.value)} className="bg-transparent border-0 text-[10px] font-black uppercase outline-none" />
            </div>
          )}
          <div className="flex flex-wrap items-center gap-1 bg-white p-1 border border-slate-200 rounded-full shadow-sm">
            {[
              { id: 'current_month', label: 'Month' },
              { id: 'last_90_days', label: 'Quarter' },
              { id: 'ytd', label: 'YTD' },
              { id: 'all_time', label: 'All' },
              { id: 'custom', label: '📅' }
            ].map(p => (
              <button
                key={p.id}
                onClick={() => setActivePeriod(p.id as Period)}
                className={`px-4 py-1.5 rounded-full text-[9px] md:text-xs font-black uppercase transition-all ${
                  activePeriod === p.id ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:text-slate-800'
                }`}
              >
                {p.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* P&L Account */}
      <section className="bg-white border-y md:border md:rounded-[2.5rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-900 px-6 md:px-10 py-10 md:py-12 text-white">
          <div className="flex flex-col md:flex-row justify-between items-center gap-8">
            <div className="text-center md:text-left">
              <h3 className="text-sm md:text-lg font-black tracking-widest uppercase mb-1">Profit & Loss Account</h3>
              <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest italic">Performance Summary for Period</p>
            </div>
            <div className="text-center md:text-right">
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Net Flow Balance</p>
              <p className={`text-4xl md:text-6xl font-black tracking-tighter ${netSurplus >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                {formatCurrency(netSurplus, currency)}
              </p>
            </div>
          </div>

          <div className="grid grid-cols-2 gap-8 mt-12 pt-10 border-t border-white/10">
            <div className="text-center md:text-left">
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-2">Total Income (Inflow)</p>
              <p className="text-2xl font-black text-emerald-400">{formatCurrency(periodIncome, currency)}</p>
            </div>
            <div className="text-center md:text-right">
              <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-2">Total Expense (Outflow)</p>
              <p className="text-2xl font-black text-rose-400">{formatCurrency(periodExpense, currency)}</p>
            </div>
          </div>
        </div>
      </section>

      {/* Balance Sheet */}
      <section className="bg-white border-y md:border md:rounded-[2.5rem] border-slate-200 overflow-hidden shadow-sm">
        <div className="bg-slate-50 px-6 md:px-10 py-10 text-slate-800 border-b border-slate-200">
          <div className="flex flex-col md:flex-row justify-between items-center gap-6">
            <div className="text-center md:text-left">
              <h3 className="text-sm md:text-lg font-black tracking-widest uppercase mb-1">Balance Sheet</h3>
              <p className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Financial Health Snapshot</p>
            </div>
            <div className="text-center md:text-right">
              <div className="flex items-center justify-center md:justify-end gap-3 mb-2">
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Current Ratio</span>
                  <span className={`px-2 py-1 rounded text-[10px] font-black ${Number(liquidityRatio) > 1.2 ? 'bg-emerald-100 text-emerald-600' : 'bg-rose-100 text-rose-600'}`}>{liquidityRatio}</span>
              </div>
              <p className="text-4xl md:text-6xl font-black tracking-tighter text-indigo-600">{formatCurrency(netWorth, currency)}</p>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-2">{isMeView ? 'Personal Net Worth' : 'Consolidated Net Worth'}</p>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
          {/* ASSETS */}
          <div className="p-6 md:p-12 space-y-8">
            <div className="flex justify-between items-center mb-4">
              <h4 className="text-xs font-black text-slate-800 uppercase tracking-widest">{assetHeader}</h4>
              <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full">TOTAL: {formatCurrency(totalAssetsValue, currency)}</span>
            </div>

            <div className="space-y-4">
              {(['Current Asset', 'Non-Current Asset'] as const).map(head => (
                <div key={head} className="border border-slate-100 rounded-3xl overflow-hidden bg-white shadow-sm transition-all duration-300">
                  <button onClick={() => toggleHead(head)} className="w-full flex justify-between items-center p-6 hover:bg-slate-50 transition-colors">
                    <div className="flex items-center gap-3">
                      <div className={`w-2 h-2 rounded-full ${head === 'Current Asset' ? 'bg-indigo-600' : 'bg-slate-400'}`}></div>
                      <span className="text-[11px] font-black text-slate-800 uppercase tracking-widest">{head}</span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="text-xs font-black text-slate-800">{formatCurrency(heads[head].total, currency)}</span>
                      <span className={`text-[10px] transition-transform duration-300 ${expandedHeads.includes(head) ? 'rotate-180' : ''}`}>▼</span>
                    </div>
                  </button>
                  {expandedHeads.includes(head) && (
                    <div className="px-6 pb-6 pt-2 space-y-1 bg-slate-50/40">
                      {heads[head].items.map((item) => (
                        <button key={item.id} onClick={() => item.originalAccount && setSelectedAccountForHistory(item.originalAccount)} className={`w-full flex justify-between items-center p-3.5 rounded-xl transition-all border border-transparent ${item.originalAccount ? 'hover:bg-white hover:border-slate-200 hover:shadow-sm cursor-pointer' : 'cursor-default'}`}>
                          <div className="text-left">
                            <p className="text-[11px] font-bold text-slate-800 uppercase">{item.name}</p>
                            <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest">
                                {item.details ? item.details : item.source}
                            </p>
                          </div>
                          <span className="text-[11px] font-black text-slate-600">{formatCurrency(item.value, currency)}</span>
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="p-8 bg-slate-50 rounded-[2rem] border border-dashed border-slate-200 flex justify-between items-center mt-12">
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Aggregate Assets</p>
               <p className="text-2xl font-black text-slate-800 tracking-tighter">{formatCurrency(totalAssetsValue, currency)}</p>
            </div>
          </div>

          {/* LIABILITIES & EQUITY */}
          <div className="p-6 md:p-12 space-y-8 bg-slate-50/10">
            <div className="flex justify-between items-center mb-4">
              <h4 className="text-xs font-black text-slate-800 uppercase tracking-widest">{liabilityHeader}</h4>
              <span className="text-[10px] font-black text-rose-600 bg-rose-50 px-3 py-1 rounded-full">TOTAL: {formatCurrency(totalLiabilitiesAndEquityValue, currency)}</span>
            </div>

            <div className="space-y-4">
              {(['Current Liability', 'Non-Current Liability', 'Equity'] as const).map(head => (
                <div key={head} className="border border-slate-100 rounded-3xl overflow-hidden bg-white shadow-sm transition-all duration-300">
                  <button onClick={() => toggleHead(head)} className="w-full flex justify-between items-center p-6 hover:bg-slate-50 transition-colors">
                    <div className="flex items-center gap-3">
                      <div className={`w-2 h-2 rounded-full ${head === 'Equity' ? 'bg-emerald-500' : 'bg-rose-400'}`}></div>
                      <span className="text-[11px] font-black text-slate-800 uppercase tracking-widest">{head}</span>
                    </div>
                    <div className="flex items-center gap-4">
                      <span className="text-xs font-black text-slate-800">{formatCurrency(heads[head].total, currency)}</span>
                      <span className={`text-[10px] transition-transform duration-300 ${expandedHeads.includes(head) ? 'rotate-180' : ''}`}>▼</span>
                    </div>
                  </button>
                  {expandedHeads.includes(head) && (
                    <div className="px-6 pb-6 pt-2 space-y-1 bg-slate-50/40">
                      {heads[head].items.map((item) => (
                        <button key={item.id} onClick={() => item.originalAccount && setSelectedAccountForHistory(item.originalAccount)} className={`w-full flex justify-between items-center p-3.5 rounded-xl transition-all border border-transparent ${item.originalAccount ? 'hover:bg-white hover:border-slate-200 hover:shadow-sm cursor-pointer' : 'cursor-default'}`}>
                          <div className="text-left">
                            <p className="text-[11px] font-bold text-slate-800 uppercase">{item.name}</p>
                            <p className="text-[8px] font-black text-slate-300 uppercase tracking-widest">{item.source}</p>
                          </div>
                          <span className="text-[11px] font-black text-slate-600">{formatCurrency(item.value, currency)}</span>
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              ))}
            </div>

            <div className="p-8 bg-slate-900 rounded-[2rem] shadow-xl flex justify-between items-center mt-12 text-white">
               <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Aggregate Liabilities & Equity</p>
               <p className="text-2xl font-black text-white tracking-tighter">{formatCurrency(totalLiabilitiesAndEquityValue, currency)}</p>
            </div>
          </div>
        </div>
      </section>

      {/* Audit Modal */}
      {selectedAccountForHistory && (
        <TransactionHistoryModal 
          account={selectedAccountForHistory} 
          currency={currency} 
          onClose={() => setSelectedAccountForHistory(null)} 
        />
      )}
    </div>
  );
};

export default Statements;

export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';
export type AccountClassification = 'Current Asset' | 'Non-Current Asset' | 'Current Liability' | 'Non-Current Liability' | 'Equity';

export interface FamilyMember {
  id: string;
  name: string;
  relation: string;
  mobileNumber: string;
  canAddTransactions?: boolean;
}

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
  familyMembers: FamilyMember[];
  cloudDatabaseName?: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  timestamp: string;
  type: 'transaction' | 'system' | 'sync';
  isRead: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
  ownerId?: string;
  accountType?: 'Savings' | 'Current' | 'Salary' | 'Others';
