}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number;
  last4: string;
  limit?: number;
  annualLimit?: number; 
  anniversaryDate?: string;
  billingDay?: number;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
  ownerId?: string;
  classification?: AccountClassification;
  // NEW BENEFIT FIELDS
