              <h4 className="text-sm font-black text-slate-800 uppercase tracking-tighter mb-4">Secure Document Entry</h4>
              <p className="text-[10px] font-medium text-slate-400 uppercase tracking-widest mb-6">Enter PDF Password to proceed with decryption</p>
              <input type="password" autoFocus className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-black text-lg mb-6" value={pdfPassword} onChange={e => setPdfPassword(e.target.value)} onKeyPress={e => e.key === 'Enter' && startAIParsing()} />
              <div className="flex gap-3">
                 <button onClick={() => setShowPasswordInput(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-xl">Cancel</button>
                 <button onClick={startAIParsing} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg">Decrypt & Verify</button>
              </div>
           </div>
        </div>
      )}

      {isScanning && (
        <div className="fixed inset-0 z-[70] flex flex-col items-center justify-center bg-indigo-900/95 backdrop-blur-3xl text-white">
           <div className="w-24 h-24 border-4 border-indigo-400/30 border-t-indigo-400 rounded-full animate-spin mb-10"></div>
           <h2 className="text-2xl font-black tracking-tighter uppercase mb-2">Analyzing Document Integrity</h2>
           <p className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.3em]">AI Audit in Progress: {scanTimeLeft}s remaining</p>
           <div className="mt-12 max-w-xs text-center">
              <p className="text-xs font-medium text-indigo-200 italic opacity-60 line-clamp-2">Decrypting secure containers and identifying stock units for reconciliation...</p>
           </div>
        </div>
      )}

      {confirmDeleteTx && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
           <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
             <div className="text-center mb-8">
               <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">⚠️</div>
               <h4 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Purge Record?</h4>
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">This action is irreversible and affects capital calculation</p>
             </div>
             <div className="flex gap-3">
               <button onClick={() => setConfirmDeleteTx(null)} className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold text-[10px] uppercase rounded-2xl">Cancel</button>
               <button onClick={() => { deleteTransaction(confirmDeleteTx.id); setConfirmDeleteTx(null); }} className="flex-[2] py-4 bg-rose-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-rose-100">Delete Permanently</button>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';
import { GoogleGenAI } from "@google/genai";
import * as XLSX from 'xlsx';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  grossValue: number;
  netTotal: number; // Final amount after STT and allocated charges
  units?: number;
  date?: string;
  isin?: string;
  stt?: number;
  allocatedCharges?: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature, addWallet } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isIsinResolving, setIsIsinResolving] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(15);
  const [pdfPassword, setPdfPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [pendingFile, setPendingFile] = useState<File | null>(null);
  const [importOwnerId, setImportOwnerId] = useState<string>('');

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const selectedAccount = useMemo(() => {
    return allAccounts.find(a => a.id === formData.accountId);
  }, [formData.accountId, allAccounts]);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (formData.isin && formData.isin.length === 12 && !formData.stockName) {
        handleIsinLookup(formData.isin);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [formData.isin]);

  const handleIsinLookup = async (isin: string) => {
    setIsIsinResolving(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify the security/stock name for the following ISIN identifier: ${isin}. Return ONLY the official short name of the security. No preamble.`
      });
      const resolvedName = response.text?.trim() || 'Unknown Security';
      setFormData(prev => ({ 
        ...prev, 
        stockName: resolvedName,
        description: prev.description || resolvedName
      }));
    } catch (err) {
      console.error("ISIN Resolution failed:", err);
    } finally {
      setIsIsinResolving(false);
    }
  };

  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
    const zerodhaExists = allAccounts.some(a => a.name.toLowerCase() === 'zerodha');
    if (!zerodhaExists) {
      addWallet({
        id: 'zerodha-account-auto',
        name: 'Zerodha',
        balance: 0,
        ownerId: ''
      });
    }
  }, [allAccounts]);

  useEffect(() => {
    let timer: number;
    if (isScanning && scanTimeLeft > 0) {
      timer = window.setInterval(() => {
        setScanTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isScanning, scanTimeLeft]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.name.endsWith('.xlsx') || file.name.endsWith('.xls')) {
      handleExcelImport(file);
      if (fileInputRef.current) fileInputRef.current.value = '';
      return;
    }

    setPendingFile(file);
    setShowPasswordInput(true);
  };

  const handleExcelImport = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array', cellDates: true });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const rows: any[] = XLSX.utils.sheet_to_json(worksheet);

        if (rows.length === 0) {
          alert("Excel file is empty.");
          return;
        }

        let totalOtherCharges = 0;
        let totalGrossValueAbs = 0;
        let lastDate = new Date().toISOString().split('T')[0];

        // Clean headers by trimming keys
        const cleanedRows = rows.map(r => {
          const newRow: any = {};
          Object.keys(r).forEach(k => newRow[k.trim()] = r[k]);
          return newRow;
        });

        // First pass: Calculate totals for proportional allocation of "Other Charges"
        cleanedRows.forEach((row: any) => {
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const chargesExclSTT = Math.abs(Number(row['Total Charges excluding STT'] || 0));
          totalOtherCharges += chargesExclSTT;
          totalGrossValueAbs += grossValue;
        });

        const trades: ExtractedTrade[] = [];

        // Second pass: Create trade objects with proportional charge allocation
        cleanedRows.forEach((row: any) => {
          const isin = row['ISIN'] || 'UNKNOWN_ISIN';
          let txDateRaw = row['Date of transaction'];

          let formattedDate = lastDate;
          if (txDateRaw) {
            const d = new Date(txDateRaw);
            if (!isNaN(d.getTime())) {
              formattedDate = d.toISOString().split('T')[0];
            }
          }
          lastDate = formattedDate;

          const qty = Number(row['Quantity'] || 0);
          const type = String(row['Buy/Sell'] || 'BUY').toUpperCase();
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const stt = Math.abs(Number(row['STT'] || 0));

          // PROPORTIONAL ALLOCATION of "Total Charges excluding STT"
          const proportion = totalGrossValueAbs > 0 ? (grossValue / totalGrossValueAbs) : 0;
          const allocatedOtherCharges = proportion * totalOtherCharges;

          // Final logic: Net Cost for the ledger entry
          // BUY: Cost = Gross + STT + Allocated Charges
          // SELL: Revenue = Gross - STT - Allocated Charges (we store as grossValue in transaction, but keep net for accounting)
          const finalCostBasis = grossValue + stt + allocatedOtherCharges;

          trades.push({
            scrip: isin, 
            type: type === 'BUY' ? 'BUY' : 'SELL',
            grossValue: grossValue,
            netTotal: finalCostBasis,
            units: qty,
            date: formattedDate,
            isin: isin,
            stt: stt,
            allocatedCharges: allocatedOtherCharges
          });
        });

        setScanResult({
          date: lastDate,
          trades: trades,
          otherCharges: totalOtherCharges
        });

      } catch (err) {
        console.error(err);
        alert("Failed to parse Excel file. Ensure it follows the required headers template.");
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const startAIParsing = async () => {
    if (!pendingFile) return;
    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(18);

    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: pendingFile.type } },
              { text: `Extract data from this Zerodha Contract Note PDF. Return ONLY JSON: { "date": "YYYY-MM-DD", "trades": [{"scrip": "string", "type": "BUY" | "SELL", "grossValue": number, "stt": number, "units": number}], "otherCharges": number }` }
            ]
          },
          config: { responseMimeType: "application/json" }
        });
        const result = JSON.parse(response.text || '{}');
        if (result.date && result.trades) {
          // AI results might need proportional allocation for otherCharges too
          const totalGross = result.trades.reduce((acc: number, t: any) => acc + (t.grossValue || 0), 0);
          const mappedTrades = result.trades.map((t: any) => {
             const prop = totalGross > 0 ? (t.grossValue / totalGross) : 0;
             const alloc = prop * (result.otherCharges || 0);
             return {
               ...t,
               netTotal: (t.grossValue || 0) + (t.stt || 0) + alloc,
               allocatedCharges: alloc
             };
          });
          setScanResult({ ...result, trades: mappedTrades });
        }
        else alert("AI could not identify valid trade patterns in this document.");
      } catch (err) {
        console.error(err);
        alert("Verification failed or AI Service timeout.");
      } finally {
        setIsScanning(false);
        setPdfPassword('');
        setPendingFile(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(pendingFile);
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;
    try {
      // Find Zerodha account in the unified allAccounts list
      const zerodhaAccount = allAccounts.find(a => a.name.toLowerCase() === 'zerodha') || 
                            allAccounts.find(a => a.name.toLowerCase().includes('zerodha')) || 
                            { id: 'zerodha-account-auto', type: 'wallet' };

      scanResult.trades.forEach(t => {
        addTransaction({
          id: Math.random().toString(36).substr(2, 9),
          type: t.type === 'BUY' ? 'Asset' : 'Income', 
          amount: t.netTotal,
          nature: 'Investment in stocks',
          description: `${t.type} ${t.scrip}`,
          accountId: (zerodhaAccount as any).id,
          accountType: (zerodhaAccount as any).type || 'wallet',
          date: t.date || scanResult.date,
          ownerId: importOwnerId, // Use owner selected in import review
          isin: t.isin,
          units: t.units,
          stt: t.stt,
          brokerage: t.allocatedCharges
        });
      });

      setScanResult(null);
    } catch (err) {
      console.error("Commit failed:", err);
      alert("Failed to commit transactions to ledger. Check logs.");
    }
  };

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, nature: natures[0] || '' });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      ...initialFormState,
      type: t.type,
      amount: String(t.amount),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      ownerId: t.ownerId || '',
      isin: t.isin || '',
      stockName: t.stockName || '',
      units: t.units ? String(t.units) : '',
      billingPeriod: t.billingPeriod || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) {
      alert("Please select a target account for settlement.");
      return;
    }

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: Number(formData.amount),
      nature: formData.nature,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type as any,
      date: formData.date,
      ownerId: formData.ownerId,
      isin: formData.isin,
      stockName: formData.stockName,
      units: formData.units ? Number(formData.units) : undefined,
      billingPeriod: formData.billingPeriod
    };
    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight uppercase">Audit Ledger</h3>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-2">Verified Transaction History</p>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:flex lg:flex-wrap items-center gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*,.pdf,.xlsx,.xls" onChange={handleFileUpload} />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="col-span-2 md:col-span-1 px-4 lg:px-6 py-3 lg:py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-slate-800 transition-all shadow-xl active:scale-95"
          >
            <span>📄</span> Broker Import
          </button>
          <button onClick={() => handleOpenModal('Income')} className="px-4 py-3 lg:py-4 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-4 py-3 lg:py-4 bg-rose-50 text-rose-500 border border-rose-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-4 py-3 lg:py-4 bg-white text-indigo-600 border border-indigo-100 rounded-2xl text-[10px] font-black uppercase tracking-widest active:scale-95 transition-all">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-4 py-3 lg:py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Debt</button>
        </div>
      </div>

      {scanResult && (
        <div className="bg-indigo-900 text-white p-6 md:p-10 rounded-[2.5rem] shadow-2xl animate-in slide-in-from-top-10 duration-500 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 text-8xl opacity-10 font-black">IMPORT</div>
          <div className="relative z-10">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 border-b border-white/10 pb-4 gap-4">
               <h4 className="text-sm font-black uppercase tracking-widest flex items-center gap-3">
                 <span className="text-2xl">📋</span> Verify Extracted Ledger
               </h4>
               <div className="flex items-center gap-3 bg-white/10 p-2 rounded-xl border border-white/10">
                  <span className="text-[9px] font-black text-indigo-200 uppercase tracking-widest">Target Owner:</span>
                  <select 
                    className="bg-transparent text-[10px] font-black text-white outline-none appearance-none cursor-pointer"
                    value={importOwnerId}
                    onChange={(e) => setImportOwnerId(e.target.value)}
                  >
                    <option value="" className="text-slate-800">Me (Primary)</option>
                    {familyMembers.map(m => <option key={m.id} value={m.id} className="text-slate-800">{m.name}</option>)}
                  </select>
                  <span className="text-[8px]">▼</span>
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="space-y-6">
                <div>
                  <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-1">Audit Timeline</p>
                  <p className="text-2xl font-black">{scanResult.date}</p>
                </div>
                <div className="bg-white/5 p-6 rounded-3xl border border-white/10">
                   <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-4">Trade Summary (Allocation applied)</p>
                   <div className="space-y-4 max-h-[300px] overflow-y-auto custom-scrollbar pr-2">
                     {scanResult.trades.map((t, i) => (
                       <div key={i} className="flex justify-between items-center border-b border-white/5 pb-2 last:border-0 last:pb-0">
                         <div>
                           <p className="text-xs font-black uppercase tracking-tight truncate max-w-[150px]">{t.scrip}</p>
                           <p className="text-[8px] font-black text-indigo-400 uppercase">
                             {t.type} {t.units ? `• ${t.units} Units` : ''} • STT: {formatCurrency(t.stt || 0, currency)}
                           </p>
                           <p className="text-[7px] font-black text-indigo-500/60 uppercase">Other Allocated: {formatCurrency(t.allocatedCharges || 0, currency)}</p>
                         </div>
                         <div className="text-right">
                           <p className="text-sm font-black">{formatCurrency(t.netTotal, currency)}</p>
                           <p className="text-[8px] text-indigo-300">Net Cost</p>
                         </div>
                       </div>
                     ))}
                   </div>
                </div>
              </div>
              <div className="flex flex-col justify-between">
                <div className="space-y-4">
                  <div className="flex justify-between items-center p-4 bg-white/5 rounded-2xl">
                    <span className="text-[10px] font-black uppercase">Aggregate Other Charges</span>
                    <span className="text-sm font-black">{formatCurrency(scanResult.otherCharges, currency)}</span>
                  </div>
                  <div className="flex justify-between items-center p-6 bg-indigo-800 rounded-3xl border border-white/10 shadow-xl">
                    <span className="text-[10px] font-black uppercase">Net Total Settlement</span>
                    <p className="text-2xl font-black text-emerald-400">
                      {formatCurrency(scanResult.trades.reduce((acc, t) => acc + t.netTotal, 0), currency)}
                    </p>
                  </div>
                </div>
                <div className="flex gap-4 mt-10">
                  <button onClick={() => setScanResult(null)} className="flex-1 py-5 bg-white/10 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-white/20 transition-all">Reject</button>
                  <button onClick={commitScannedTrade} className="flex-[2] py-5 bg-emerald-500 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-emerald-900/40 hover:bg-emerald-600 transition-all active:scale-95">Commit to Vault</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[800px] lg:min-w-full">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Timeline</th>
                <th className="px-8 py-6">Audit Nature</th>
                <th className="px-8 py-6">Entity Claims</th>
                <th className="px-8 py-6 text-right">Settlement</th>
                <th className="px-8 py-6 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/30 transition-colors group">
                  <td className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-tighter">
                    {t.date}
