      )}

      {isScanning && (
        <div className="fixed inset-0 z-[70] flex flex-col items-center justify-center bg-indigo-900/95 backdrop-blur-3xl text-white">
           <div className="w-24 h-24 border-4 border-indigo-400/30 border-t-indigo-400 rounded-full animate-spin mb-10"></div>
           <h2 className="text-2xl font-black tracking-tighter uppercase mb-2">Analyzing Document Integrity</h2>
           <p className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.3em]">AI Audit in Progress: {scanTimeLeft}s remaining</p>
           <div className="mt-12 max-w-xs text-center">
              <p className="text-xs font-medium text-indigo-200 italic opacity-60 line-clamp-2">Decrypting secure containers and identifying stock units for reconciliation...</p>
           </div>
        </div>
      )}

      {confirmDeleteTx && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
           <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
             <div className="text-center mb-8">
               <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">⚠️</div>
               <h4 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Purge Record?</h4>
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">This action is irreversible and affects capital calculation</p>
             </div>
             <div className="flex gap-3">
               <button onClick={() => setConfirmDeleteTx(null)} className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold text-[10px] uppercase rounded-2xl">Cancel</button>
               <button onClick={() => { deleteTransaction(confirmDeleteTx.id); setConfirmDeleteTx(null); }} className="flex-[2] py-4 bg-rose-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-rose-100">Delete Permanently</button>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';
import { GoogleGenAI } from "@google/genai";
import * as XLSX from 'xlsx';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  grossValue: number;
  netTotal: number; // Final amount after STT and allocated charges
  units?: number;
  date?: string;
  isin?: string;
  stt?: number;
  allocatedCharges?: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature, addWallet } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [isIsinResolving, setIsIsinResolving] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(15);
  const [pdfPassword, setPdfPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [pendingFile, setPendingFile] = useState<File | null>(null);
  const [importOwnerId, setImportOwnerId] = useState<string>('');

  const [scanResult, setScanResult] = useState<{ 
    date: string; 
    trades: ExtractedTrade[];
    otherCharges: number;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const selectedAccount = useMemo(() => {
    return allAccounts.find(a => a.id === formData.accountId);
  }, [formData.accountId, allAccounts]);

  useEffect(() => {
    const timer = setTimeout(() => {
      if (formData.isin && formData.isin.length === 12 && !formData.stockName) {
        handleIsinLookup(formData.isin);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [formData.isin]);

  const handleIsinLookup = async (isin: string) => {
    setIsIsinResolving(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify the security/stock name for the following ISIN identifier: ${isin}. Return ONLY the official short name of the security. No preamble.`
      });
      const resolvedName = response.text?.trim() || 'Unknown Security';
      setFormData(prev => ({ 
        ...prev, 
        stockName: resolvedName,
        description: prev.description || resolvedName
      }));
    } catch (err) {
      console.error("ISIN Resolution failed:", err);
    } finally {
      setIsIsinResolving(false);
    }
  };

  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
    const zerodhaExists = allAccounts.some(a => a.name.toLowerCase() === 'zerodha');
    if (!zerodhaExists) {
      addWallet({
        id: 'zerodha-account-auto',
        name: 'Zerodha',
        balance: 0,
        ownerId: ''
      });
    }
  }, [allAccounts]);

  useEffect(() => {
    let timer: number;
    if (isScanning && scanTimeLeft > 0) {
      timer = window.setInterval(() => {
        setScanTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isScanning, scanTimeLeft]);

  const downloadExcelTemplate = () => {
    const headers = [
      "ISIN",
      "Date of transaction",
      "Quantity",
      "Buy/Sell",
      "Total Buy/Sell Value",
      "Total Charges excluding STT",
      "STT",
      "Net Payable/ Receivable"
    ];

    // Create an empty data row with hints
    const data = [
      headers,
      ["INE002A01018", new Date().toISOString().split('T')[0], 10, "BUY", 10000, 20, 10.5, -10030.5],
      ["INE002A01018", new Date().toISOString().split('T')[0], 5, "SELL", -5500, 15, 5.25, 5479.75]
    ];

    const ws = XLSX.utils.aoa_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Import_Template");

    // Note: Standard XLSX files don't carry "dropdowns" easily via AOA_TO_SHEET 
    // without more complex XML injection, but the instruction is clear for users.

    XLSX.writeFile(wb, "MyFin_Broker_Import_Template.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.name.endsWith('.xlsx') || file.name.endsWith('.xls')) {
      handleExcelImport(file);
      if (fileInputRef.current) fileInputRef.current.value = '';
      return;
    }

    setPendingFile(file);
    setShowPasswordInput(true);
  };

  const handleExcelImport = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array', cellDates: true });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const rows: any[] = XLSX.utils.sheet_to_json(worksheet);

        if (rows.length === 0) {
          alert("Excel file is empty.");
          return;
        }

        let totalOtherCharges = 0;
        let totalGrossValueAbs = 0;
        let lastDate = new Date().toISOString().split('T')[0];

        // Clean headers by trimming keys
        const cleanedRows = rows.map(r => {
          const newRow: any = {};
          Object.keys(r).forEach(k => newRow[k.trim()] = r[k]);
          return newRow;
        });

        // First pass: Calculate totals for proportional allocation of "Other Charges"
        cleanedRows.forEach((row: any) => {
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const chargesExclSTT = Math.abs(Number(row['Total Charges excluding STT'] || 0));
          totalOtherCharges += chargesExclSTT;
          totalGrossValueAbs += grossValue;
        });

        const trades: ExtractedTrade[] = [];

        // Second pass: Create trade objects with proportional charge allocation
        cleanedRows.forEach((row: any) => {
          const isin = row['ISIN'] || 'UNKNOWN_ISIN';
          let txDateRaw = row['Date of transaction'];

          let formattedDate = lastDate;
          if (txDateRaw) {
            const d = new Date(txDateRaw);
            if (!isNaN(d.getTime())) {
              formattedDate = d.toISOString().split('T')[0];
            }
          }
          lastDate = formattedDate;

          const qty = Number(row['Quantity'] || 0);
          const type = String(row['Buy/Sell'] || 'BUY').toUpperCase();
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const stt = Math.abs(Number(row['STT'] || 0));

          // PROPORTIONAL ALLOCATION of "Total Charges excluding STT"
          const proportion = totalGrossValueAbs > 0 ? (grossValue / totalGrossValueAbs) : 0;
          const allocatedOtherCharges = proportion * totalOtherCharges;

          const finalCostBasis = grossValue + stt + allocatedOtherCharges;

          trades.push({
            scrip: isin, 
            type: type === 'BUY' ? 'BUY' : 'SELL',
            grossValue: grossValue,
            netTotal: finalCostBasis,
            units: qty,
            date: formattedDate,
            isin: isin,
            stt: stt,
            allocatedCharges: allocatedOtherCharges
          });
        });

        setScanResult({
          date: lastDate,
          trades: trades,
          otherCharges: totalOtherCharges
        });

      } catch (err) {
        console.error(err);
        alert("Failed to parse Excel file. Ensure it follows the required headers template.");
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const startAIParsing = async () => {
    if (!pendingFile) return;
    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(18);

    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: pendingFile.type } },
              { text: `Extract data from this Zerodha Contract Note PDF. Return ONLY JSON: { "date": "YYYY-MM-DD", "trades": [{"scrip": "string", "type": "BUY" | "SELL", "grossValue": number, "stt": number, "units": number}], "otherCharges": number }` }
            ]
          },
          config: { responseMimeType: "application/json" }
        });
        const result = JSON.parse(response.text || '{}');
        if (result.date && result.trades) {
          const totalGross = result.trades.reduce((acc: number, t: any) => acc + (t.grossValue || 0), 0);
          const mappedTrades = result.trades.map((t: any) => {
             const prop = totalGross > 0 ? (t.grossValue / totalGross) : 0;
             const alloc = prop * (result.otherCharges || 0);
             return {
               ...t,
               netTotal: (t.grossValue || 0) + (t.stt || 0) + alloc,
               allocatedCharges: alloc
             };
          });
          setScanResult({ ...result, trades: mappedTrades });
        }
        else alert("AI could not identify valid trade patterns in this document.");
      } catch (err) {
        console.error(err);
        alert("Verification failed or AI Service timeout.");
      } finally {
        setIsScanning(false);
        setPdfPassword('');
        setPendingFile(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(pendingFile);
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;
    try {
      const zerodhaAccount = allAccounts.find(a => a.name.toLowerCase() === 'zerodha') || 
                            allAccounts.find(a => a.name.toLowerCase().includes('zerodha')) || 
