    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: '',
    isin: '',
    stockName: '',
    units: '',
    billingPeriod: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = (state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId }));
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
    const zerodhaExists = allAccounts.some(a => a.name.toLowerCase().includes('zerodha'));
    if (!zerodhaExists) {
      addWallet({
        id: 'zerodha-account-auto',
        name: 'Zerodha',
        balance: 0,
        ownerId: ''
      });
    }
  }, [allAccounts]);

  const handleIsinLookup = async (isin: string) => {
    setIsIsinResolving(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Identify the security/stock name for the following ISIN identifier: ${isin}. Return ONLY the official short name of the security. No preamble.`
      });
      const resolvedName = response.text?.trim() || 'Unknown Security';
      setFormData(prev => ({ 
        ...prev, 
        stockName: resolvedName,
        description: prev.description || resolvedName
      }));
    } catch (err) {
      console.error("ISIN Resolution failed:", err);
    } finally {
      setIsIsinResolving(false);
    }
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      if (formData.isin && formData.isin.length === 12 && !formData.stockName) {
        handleIsinLookup(formData.isin);
      }
    }, 500);
    return () => clearTimeout(timer);
  }, [formData.isin]);

  const downloadExcelTemplate = () => {
    const headers = [
      "ISIN", "Date of transaction", "Quantity", "Buy/Sell", "Total Buy/Sell Value", "Total Charges excluding STT", "STT", "Net Payable/ Receivable"
    ];
    const data = [
      headers,
      ["INE002A01018", new Date().toISOString().split('T')[0], 10, "BUY", 10000, 20, 10.5, -10030.5],
      ["INE002A01018", new Date().toISOString().split('T')[0], 5, "SELL", -5500, 15, 5.25, 5479.75]
    ];
    const ws = XLSX.utils.aoa_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Import_Template");
    XLSX.writeFile(wb, "MyFin_Broker_Import_Template.xlsx");
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.name.endsWith('.xlsx') || file.name.endsWith('.xls')) {
      handleExcelImport(file);
      if (fileInputRef.current) fileInputRef.current.value = '';
      return;
    }

    setPendingFile(file);
    setShowPasswordInput(true);
  };

  const handleExcelImport = (file: File) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array', cellDates: true });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const rows: any[] = XLSX.utils.sheet_to_json(worksheet);

        if (rows.length === 0) {
          alert("Excel file is empty.");
          return;
        }

        let totalOtherCharges = 0;
        let totalGrossValueAbs = 0;
        let lastDate = new Date().toISOString().split('T')[0];

        const cleanedRows = rows.map(r => {
          const newRow: any = {};
          Object.keys(r).forEach(k => newRow[k.trim()] = r[k]);
          return newRow;
        });

        cleanedRows.forEach((row: any) => {
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const chargesExclSTT = Math.abs(Number(row['Total Charges excluding STT'] || 0));
          totalOtherCharges += chargesExclSTT;
          totalGrossValueAbs += grossValue;
        });

        const trades: ExtractedTrade[] = [];
        cleanedRows.forEach((row: any) => {
          const isin = row['ISIN'] || 'UNKNOWN_ISIN';
          let txDateRaw = row['Date of transaction'];
          let formattedDate = lastDate;
          if (txDateRaw) {
            const d = new Date(txDateRaw);
            if (!isNaN(d.getTime())) formattedDate = d.toISOString().split('T')[0];
          }
          lastDate = formattedDate;

          const qty = Number(row['Quantity'] || 0);
          const type = String(row['Buy/Sell'] || 'BUY').toUpperCase();
          const grossValue = Math.abs(Number(row['Total Buy/Sell Value'] || 0));
          const stt = Math.abs(Number(row['STT'] || 0));
          const netSettlement = Number(row['Net Payable/ Receivable'] || 0);

          const proportion = totalGrossValueAbs > 0 ? (grossValue / totalGrossValueAbs) : 0;
          const allocatedOtherCharges = proportion * totalOtherCharges;
          const finalCostBasis = Math.abs(netSettlement) || (grossValue + stt + allocatedOtherCharges);

          trades.push({
            scrip: isin, 
            type: type === 'BUY' ? 'BUY' : 'SELL',
            grossValue: grossValue,
            netTotal: finalCostBasis,
            units: qty,
            date: formattedDate,
            isin: isin,
            stt: stt,
            allocatedCharges: allocatedOtherCharges
          });
        });

        setScanResult({ date: lastDate, trades, otherCharges: totalOtherCharges });
      } catch (err) {
        console.error(err);
        alert("Failed to parse Excel file.");
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const startAIParsing = async () => {
    if (!pendingFile) return;
    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(20);

    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // Define Response Schema for consistency using Type enum from @google/genai
        const responseSchema = {
          type: Type.OBJECT,
          properties: {
            date: { type: Type.STRING, description: "The settlement date or document date in YYYY-MM-DD format." },
            otherCharges: { type: Type.NUMBER, description: "Total of all non-STT charges like brokerage, exchange fees, etc." },
            trades: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  isin: { type: Type.STRING, description: "International Securities Identification Number (12 characters)." },
                  scrip: { type: Type.STRING, description: "Name of the security or stock." },
                  type: { type: Type.STRING, description: "Direction of trade: BUY or SELL" },
                  units: { type: Type.NUMBER, description: "Number of shares or quantity." },
                  grossValue: { type: Type.NUMBER, description: "The gross amount before charges." },
                  stt: { type: Type.NUMBER, description: "Securities Transaction Tax amount." },
                  netSettlement: { type: Type.NUMBER, description: "The final net payable or receivable amount for this specific trade line." }
                },
                required: ["isin", "type", "units", "grossValue", "netSettlement"]
              }
            }
          },
          required: ["date", "trades", "otherCharges"]
        };

        const response = await ai.models.generateContent({
          model: 'gemini-3-pro-preview',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: pendingFile.type } },
              { text: `Analyze this Broker Contract Note document (PDF/Image) and extract all stock market trade entries.
              Identify these attributes for every single trade line found:
              - ISIN
              - Date of transaction
              - Quantity/Units
              - Buy/Sell direction
              - Total Buy/Sell Value / Gross Value
              - STT
              - Net Payable/Receivable

              Also identify 'otherCharges' which represents total brokerage and exchange fees excluding STT.
              Ensure every numeric value is extracted as a positive float.
              Use the provided JSON schema.` }
            ]
          },
          config: { 
            responseMimeType: "application/json",
            responseSchema: responseSchema,
            thinkingConfig: { thinkingBudget: 15000 }
          }
        });

        const resultText = response.text;
        if (!resultText) throw new Error("Empty AI response");

        const result = JSON.parse(resultText.trim());
        if (result && result.trades && Array.isArray(result.trades) && result.trades.length > 0) {
          const totalGross = result.trades.reduce((acc: number, t: any) => acc + (Math.abs(t.grossValue) || 0), 0);
          const mappedTrades = result.trades.map((t: any) => {
             const prop = totalGross > 0 ? (Math.abs(t.grossValue) / totalGross) : 0;
             const alloc = prop * (Math.abs(result.otherCharges) || 0);
             return {
               scrip: t.scrip || t.isin || 'Unknown',
               type: (String(t.type).toUpperCase().includes('SELL')) ? 'SELL' : 'BUY',
               isin: t.isin || '',
               units: Math.abs(t.units) || 0,
               grossValue: Math.abs(t.grossValue) || 0,
               stt: Math.abs(t.stt) || 0,
               date: t.date || result.date || new Date().toISOString().split('T')[0],
               netTotal: Math.abs(t.netSettlement) || ((Math.abs(t.grossValue) || 0) + (Math.abs(t.stt) || 0) + alloc),
               allocatedCharges: alloc
             };
          });
          setScanResult({ 
            date: result.date || new Date().toISOString().split('T')[0], 
            trades: mappedTrades, 
            otherCharges: Math.abs(result.otherCharges) || 0 
          });
        }
        else {
          alert("The Document Analyser could not identify any trade patterns. Please ensure the document is a clear Broker Contract Note or Ledger Statement.");
        }
      } catch (err) {
        console.error("AI Analysis Error:", err);
        alert("The AI service encountered an error processing this document. Please check your internet connection or try a clearer file.");
      } finally {
        setIsScanning(false);
        setPdfPassword('');
        setPendingFile(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(pendingFile);
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;
    try {
      const zerodhaAccount = allAccounts.find(a => a.name.toLowerCase().includes('zerodha')) || { id: 'zerodha-account-auto', type: 'wallet' };
      scanResult.trades.forEach(t => {
        addTransaction({
          id: Math.random().toString(36).substr(2, 9),
          type: t.type === 'BUY' ? 'Asset' : 'Income', 
          amount: t.netTotal,
          nature: 'Investment in stocks',
          description: `${t.type} ${t.scrip}`,
          accountId: (zerodhaAccount as any).id,
          accountType: (zerodhaAccount as any).type || 'wallet',
          date: t.date || scanResult.date,
          ownerId: importOwnerId, 
          isin: t.isin,
          units: t.units,
          stt: t.stt,
          brokerage: t.allocatedCharges
        });
      });
      setScanResult(null);
    } catch (err) {
      console.error(err);
      alert("Failed to commit transactions to the vault. Please try again.");
    }
  };

  const tradeSummaryPerScrip = useMemo(() => {
    if (!scanResult) return [];
    const summary: Record<string, { isin: string, scrip: string, bought: number, sold: number }> = {};
    scanResult.trades.forEach(t => {
      const key = t.isin || t.scrip;
      if (!summary[key]) summary[key] = { isin: t.isin, scrip: t.scrip, bought: 0, sold: 0 };
      if (t.type === 'BUY') summary[key].bought += t.units;
      else summary[key].sold += t.units;
    });
    return Object.values(summary);
  }, [scanResult]);

  const getHoldingDelta = (isin: string) => {
    const existing = state.transactions.filter(t => t.isin === isin && t.nature === 'Investment in stocks');
    const existingHolding = existing.reduce((acc, t) => {
      return t.type === 'Asset' ? acc + (t.units || 0) : acc - (t.units || 0);
    }, 0);
    return existingHolding;
  };

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, nature: natures[0] || '' });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      ...initialFormState,
      type: t.type, amount: String(t.amount), nature: t.nature, description: t.description,
      accountId: t.accountId, date: t.date, ownerId: t.ownerId || '', isin: t.isin || '',
      stockName: t.stockName || '', units: t.units ? String(t.units) : '', billingPeriod: t.billingPeriod || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) return;
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) return alert("Select target account.");

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type, amount: Number(formData.amount), nature: formData.nature,
      description: formData.description, accountId: formData.accountId, accountType: account.type as any,
      date: formData.date, ownerId: formData.ownerId, isin: formData.isin, stockName: formData.stockName,
      units: formData.units ? Number(formData.units) : undefined, billingPeriod: formData.billingPeriod
    };
    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-xl md:text-2xl font-black text-slate-800 tracking-tight uppercase">Audit Ledger</h3>
          <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mt-2">Verified Transaction History</p>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-3 lg:flex lg:flex-wrap items-center gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*,.pdf,.xlsx,.xls" onChange={handleFileUpload} />

          <div className="flex flex-col gap-1 items-stretch col-span-2 md:col-span-1">
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="px-4 lg:px-6 py-3 lg:py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-slate-800 transition-all shadow-xl active:scale-95"
            >
              <span>📄</span> Broker Analyser
            </button>
            <button onClick={downloadExcelTemplate} className="text-[8px] font-black text-indigo-500 uppercase tracking-widest hover:underline px-2 text-center">Download Template</button>
          </div>

          <button onClick={() => handleOpenModal('Income')} className="px-4 py-3 lg:py-4 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-4 py-3 lg:py-4 bg-rose-50 text-rose-500 border border-rose-100 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-4 py-3 lg:py-4 bg-white text-indigo-600 border border-indigo-100 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-4 py-3 lg:py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg transition-all">Debt</button>
        </div>
      </div>

      {scanResult && (
        <div className="bg-indigo-900 text-white p-6 md:p-10 rounded-[2.5rem] shadow-2xl animate-in slide-in-from-top-10 duration-500 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-8 text-8xl opacity-10 font-black">IMPORT</div>
          <div className="relative z-10">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 border-b border-white/10 pb-4 gap-4">
               <h4 className="text-sm font-black uppercase tracking-widest flex items-center gap-3">
                 <span className="text-2xl">📋</span> Analysed Holding Impact
               </h4>
               <div className="flex items-center gap-3 bg-white/10 p-2 rounded-xl border border-white/10">
                  <span className="text-[9px] font-black text-indigo-200 uppercase tracking-widest">Target Owner:</span>
                  <select 
                    className="bg-transparent text-[10px] font-black text-white outline-none appearance-none cursor-pointer"
                    value={importOwnerId}
                    onChange={(e) => setImportOwnerId(e.target.value)}
                  >
                    <option value="" className="text-slate-800">Me (Primary)</option>
                    {familyMembers.map(m => <option key={m.id} value={m.id} className="text-slate-800">{m.name}</option>)}
                  </select>
               </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              <div className="space-y-6">
                <div className="bg-white/5 p-6 rounded-3xl border border-white/10">
                   <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-4">Stock Holding Matrix</p>
                   <div className="space-y-4">
                      {tradeSummaryPerScrip.map((s, i) => {
                        const prevHolding = getHoldingDelta(s.isin);
                        const netDelta = s.bought - s.sold;
                        const finalHolding = prevHolding + netDelta;
                        return (
                          <div key={i} className="flex flex-col p-4 bg-indigo-800/40 rounded-2xl border border-white/5">
                             <div className="flex justify-between items-center mb-2">
                                <span className="text-xs font-black uppercase tracking-tight truncate max-w-[150px]">{s.isin || s.scrip}</span>
                                <span className="text-[10px] font-black text-indigo-200">Final Holding: {finalHolding.toLocaleString()}</span>
                             </div>
                             <div className="grid grid-cols-3 gap-2">
                                <div className="text-center p-2 bg-emerald-500/10 rounded-xl">
                                   <p className="text-[7px] font-black text-emerald-400 uppercase">Bought</p>
                                   <p className="text-xs font-black">{s.bought}</p>
                                </div>
                                <div className="text-center p-2 bg-rose-500/10 rounded-xl">
                                   <p className="text-[7px] font-black text-rose-400 uppercase">Sold</p>
                                   <p className="text-xs font-black">{s.sold}</p>
                                </div>
                                <div className="text-center p-2 bg-indigo-500/10 rounded-xl">
                                   <p className="text-[7px] font-black text-indigo-400 uppercase">Net Units</p>
                                   <p className={`text-xs font-black ${netDelta >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>{netDelta}</p>
                                </div>
                             </div>
                          </div>
                        );
                      })}
                   </div>
                </div>
              </div>

              <div className="flex flex-col justify-between">
                <div className="bg-white/5 p-6 rounded-3xl border border-white/10">
                   <p className="text-[10px] font-black text-indigo-300 uppercase tracking-widest mb-4">Detailed Reconciliation</p>
                   <div className="space-y-4 max-h-[250px] overflow-y-auto custom-scrollbar pr-2">
                     {scanResult.trades.map((t, i) => (
                       <div key={i} className="flex justify-between items-center border-b border-white/5 pb-2 last:border-0 last:pb-0">
                         <div>
                           <p className="text-xs font-black uppercase tracking-tight">{t.scrip}</p>
                           <p className="text-[8px] font-black text-indigo-400 uppercase">{t.type} • {t.units} Units • STT: {formatCurrency(t.stt, currency)}</p>
                         </div>
                         <div className="text-right">
                           <p className="text-sm font-black">{formatCurrency(t.netTotal, currency)}</p>
                         </div>
                       </div>
                     ))}
                   </div>
                </div>
                <div className="flex gap-4 mt-8">
                  <button onClick={() => setScanResult(null)} className="flex-1 py-5 bg-white/10 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-white/20 transition-all">Reject</button>
                  <button onClick={commitScannedTrade} className="flex-[2] py-5 bg-emerald-500 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl hover:bg-emerald-600 transition-all active:scale-95">Commit to Ledger</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col">
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse min-w-[800px] lg:min-w-full">
            <thead className="bg-slate-50/50 text-slate-400 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-100">
              <tr>
                <th className="px-8 py-6">Timeline</th>
                <th className="px-8 py-6">Audit Nature</th>
                <th className="px-8 py-6">Entity Claims</th>
                <th className="px-8 py-6 text-right">Settlement</th>
                <th className="px-8 py-6 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/30 transition-colors group">
                  <td className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-tighter">{t.date}</td>
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-3">
                      <p className="text-sm font-black text-slate-800 tracking-tight">{t.description || t.stockName || t.nature}</p>
                      {t.isin && <span className="bg-indigo-50 text-indigo-400 text-[8px] font-black px-2 py-0.5 rounded uppercase tracking-widest">{t.isin}</span>}
                    </div>
                    <div className="flex items-center gap-2 mt-2">
                      <span className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em]">{t.nature}</span>
                      {t.units && <span className="text-[8px] bg-slate-100 text-slate-600 font-black px-2 py-0.5 rounded uppercase">Qty: {t.units}</span>}
                      {t.stt ? <span className="text-[8px] text-slate-300 font-black uppercase">STT: {formatCurrency(t.stt, currency)}</span> : null}
                    </div>
                  </td>
                  <td className="px-8 py-6"><span className="text-[10px] font-black text-slate-600 bg-slate-100/50 border border-slate-100 px-3 py-1.5 rounded-xl uppercase tracking-widest">{getOwnerName(t.ownerId)}</span></td>
                  <td className="px-8 py-6 text-right font-black tracking-tight">
                    <span className={t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : (t.type === 'Expense' ? 'text-rose-500' : 'text-slate-800')}>
                      {t.type === 'Income' || t.type === 'Liability' ? '+' : '-'} {formatCurrency(t.amount, currency)}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-center flex items-center justify-center gap-2 md:opacity-0 md:group-hover:opacity-100 transition-all">
                    <button onClick={() => handleEditClick(t)} className="p-2.5 bg-slate-50 hover:bg-white hover:shadow-md text-slate-400 hover:text-indigo-600 rounded-xl">✎</button>
                    <button onClick={() => setConfirmDeleteTx(t)} className="p-2.5 bg-slate-50 hover:bg-white hover:shadow-md text-slate-400 hover:text-rose-500 rounded-xl">✕</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {transactionList.length === 0 && (
            <div className="py-32 text-center">
              <div className="w-16 h-16 bg-slate-50 text-slate-200 flex items-center justify-center rounded-3xl mx-auto mb-6 text-3xl">📂</div>
              <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em]">Vault currently empty</p>
            </div>
          )}
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-center bg-slate-900/60 backdrop-blur-xl p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-2xl rounded-[3rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 relative max-h-[90dvh] overflow-y-auto custom-scrollbar">
            <div className="flex justify-between items-center mb-10 border-b border-slate-100 pb-6">
              <div>
                <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">{formData.type} Record</h3>
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">Manual Reconciliation Entry</p>
              </div>
              <button onClick={() => setShowModal(false)} className="text-slate-200 hover:text-slate-800 font-black p-2 text-2xl transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              {formData.type === 'Asset' && (
                <div className="space-y-6 bg-indigo-50/30 p-8 rounded-[2rem] border border-indigo-100 animate-in slide-in-from-top-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">ISIN Protocol Key</label>
                      <input className="w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs uppercase tracking-widest focus:ring-4 focus:ring-indigo-500/10 transition-all" placeholder="e.g. INE002A01018" maxLength={12} value={formData.isin} onChange={e => setFormData({ ...formData, isin: e.target.value.toUpperCase() })} />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-indigo-400 uppercase tracking-widest block ml-2">Official Security Name</label>
                      <div className="relative">
                        <input className={`w-full p-4 bg-white border border-indigo-100 rounded-2xl outline-none font-black text-xs focus:ring-4 focus:ring-indigo-500/10 transition-all ${isIsinResolving ? 'animate-pulse text-indigo-300' : ''}`} placeholder={isIsinResolving ? "Querying AI Vault..." : "Identifying..."} value={formData.stockName} onChange={e => setFormData({ ...formData, stockName: e.target.value })} />
                        {isIsinResolving && <span className="absolute right-4 top-1/2 -translate-y-1/2 animate-spin text-indigo-500 text-lg">⚙️</span>}
                      </div>
                    </div>
                  </div>
                  {formData.isin && (
                    <div className="space-y-2 animate-in fade-in slide-in-from-left-4 duration-500">
                      <label className="text-[9px] font-black text-indigo-600 uppercase tracking-widest block ml-2">Number of Units / Quantity</label>
                      <input type="number" step="any" className="w-full p-4 bg-white border border-indigo-200 rounded-2xl outline-none font-black text-xl text-indigo-600 shadow-sm focus:ring-4 focus:ring-indigo-500/10 transition-all" placeholder="0.00" value={formData.units} onChange={e => setFormData({ ...formData, units: e.target.value })} />
                    </div>
                  )}
                </div>
              )}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Reporting Entity</label>
                  <select className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value, accountId: '' })}><option value="">Me (Primary Vault)</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}</select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Nature Protocol</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.nature} onChange={e => setFormData({ ...formData, nature: e.target.value })}><option value="" disabled>Select Protocol</option>{natures.map(n => <option key={n} value={n}>{n.toUpperCase()}</option>)}</select>
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Settlement Amount ({currency})</label>
                  <input required type="number" step="any" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-2xl focus:ring-4 focus:ring-indigo-500/10 transition-all" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Audit Timeline</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs uppercase tracking-widest cursor-pointer" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Brief Description</label>
                  <input className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-bold text-xs" placeholder="Audit notes..." value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest block ml-2">Account Instrument</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none font-black text-xs appearance-none cursor-pointer" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}><option value="">Select Target Account</option>{allAccounts.filter(a => (a.ownerId || '') === (formData.ownerId || '')).map(acc => (<option key={acc.id} value={acc.id}>{acc.name}</option>))}</select>
                </div>
              </div>
              <div className="flex flex-col md:flex-row gap-4 pt-8 sticky bottom-0 bg-white pb-2">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 font-black text-[10px] uppercase tracking-widest rounded-2xl transition-all">Discard Changes</button>
                <button type="submit" className="flex-[2] py-5 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-100 transition-all">Commit to Ledger</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showPasswordInput && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
           <div className="bg-white w-full max-w-sm p-8 rounded-3xl border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
              <h4 className="text-sm font-black text-slate-800 uppercase tracking-tighter mb-4">Secure Document Entry</h4>
              <p className="text-[10px] font-medium text-slate-400 uppercase tracking-widest mb-6">Enter PDF Password to proceed with decryption</p>
              <input type="password" autoFocus className="w-full p-4 bg-slate-50 border border-slate-200 rounded-xl outline-none font-black text-lg mb-6" value={pdfPassword} onChange={e => setPdfPassword(e.target.value)} onKeyPress={e => e.key === 'Enter' && startAIParsing()} />
              <div className="flex gap-3">
                 <button onClick={() => setShowPasswordInput(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 font-black text-[10px] uppercase rounded-xl">Cancel</button>
                 <button onClick={startAIParsing} className="flex-[2] py-4 bg-indigo-600 text-white font-black text-[10px] uppercase rounded-xl shadow-lg">Decrypt & Verify</button>
              </div>
           </div>
        </div>
      )}

      {isScanning && (
        <div className="fixed inset-0 z-[70] flex flex-col items-center justify-center bg-indigo-900/95 backdrop-blur-3xl text-white">
           <div className="w-24 h-24 border-4 border-indigo-400/30 border-t-indigo-400 rounded-full animate-spin mb-10"></div>
           <h2 className="text-2xl font-black tracking-tighter uppercase mb-2">Analysing Document Context</h2>
           <p className="text-[10px] font-black text-indigo-300 uppercase tracking-[0.3em]">AI Document Analyser in Progress: {scanTimeLeft}s remaining</p>
        </div>
      )}

      {confirmDeleteTx && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
           <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 border border-slate-200 shadow-2xl animate-in zoom-in duration-200">
             <div className="text-center mb-8">
               <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">⚠️</div>
               <h4 className="text-lg font-black text-slate-800 uppercase tracking-tighter">Purge Record?</h4>
               <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-2">This action is irreversible and affects capital calculation</p>
             </div>
             <div className="flex gap-3">
               <button onClick={() => setConfirmDeleteTx(null)} className="flex-1 py-4 bg-slate-100 text-slate-600 font-bold text-[10px] uppercase rounded-2xl">Cancel</button>
               <button onClick={() => { deleteTransaction(confirmDeleteTx.id); setConfirmDeleteTx(null); }} className="flex-[2] py-4 bg-rose-600 text-white font-black text-[10px] uppercase rounded-2xl shadow-xl shadow-rose-100">Delete Permanently</button>
             </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Transactions;
